INSERT INTO `icerik` (`id`, `kategori`, `tarih`, `tutar`, `tr_baslik`, `tr_icerik`, `tr_detay`, `en_baslik`, `en_icerik`, `en_detay`, `ru_baslik`, `ru_icerik`, `ru_detay`, `ar_baslik`, `ar_icerik`, `ar_detay`, `fr_baslik`, `fr_icerik`, `fr_detay`, `de_baslik`, `de_icerik`, `de_detay`, `cin_baslik`, `cin_icerik`, `cin_detay`, `eskayit`, `kayit_yapan_kullanici`, `kayit_tarihi`, `guncelleme_yapan_kullanici`, `guncelleme_tarihi`, `guncelleme_notu`, `durum`) VALUES
('15', '2', '2022-03-20', NULL, 'Gökçe Özel kimdir ?', '<p>İstanbul &Uuml;niversitesi Cerrahpaşa İngilizce Tıp Fak&uuml;ltesi Mezunuyum. Dışkapı Yıldırım Beyazıt Eğitim ve Araştırma Hastanesi Kulak Burun Boğaz Kliniğinde Uzmanlık Eğitimimi Tamamladım.</p>\n\n<p>2013-2021 yılları arasında Kırıkkale &Uuml;niversitesi Tıp Fak&uuml;ltesi Kulak Burun Boğaz Anabilim Dalında &Ouml;ğretim &Uuml;yesi olarak &ccedil;alıştım. 2015 Yılında Do&ccedil;ent, 2021 yılında Profes&ouml;r oldum oldum.</p>\n\n<p>T&uuml;rkiye Y&uuml;z Plastik Cerrahi Derneği Y&ouml;netim Kurulu ve Avrupa Fasiyal Plastik Cerrahi Derneği &uuml;yesiyim. Complications in Medical Aesthetic Collaborative (CMAC) derneği uluslararası danışma kurulundayım. Ulusal ve uluslararası dergilerde yayınlanmış 100&rsquo;&uuml;n &uuml;zerinde makalem mevcut olup H indeksim 12&rsquo;dir.</p>\n\n<p>Mesleki pratiğinde kulak burun boğaz branşının her alanında hastalarına hizmet vermektedir.</p>\n', '', 'Who is Gokce Ozel?', '<p>I graduated from Istanbul University Cerrahpaşa Faculty of Medicine in English. I completed my specialization training in Dışkapı Yıldırım Beyazıt Research Hospital, Otolaryngology Clinic.</p>\r\n\r\n<p>Between 2013-2021, I worked as a faculty member in Kırıkkale University Faculty of Medicine, Department of Otolaryngology. I became Associate Professor in 2015 and Professor in 2021.</p>\r\n\r\n<p>I am a member of the European Facial Plastic Surgery Association and the Turkish Facial Plastic Surgery Association. I am on the advisory board of the Complications in Medical Aesthetic Collaborative (CMAC). I have over 100 articles published in national and international journals and my H index is 12.</p>\r\n\r\n<p>My professional interest is facial plastic surgery. Minimally invasive and invasive procedures that I actively perform for facial rejuvenation in my clinical practice : face and neck lift, jowl liposuction , rhinoplasty , blepharoplasty , eyebrow lift and forehead lift, prominent ear aesthetics, chin aesthetics, bichectomy , dimple aesthetics, botulinum toxin and filler applications, mesotherapy , lipolysis mesotherapy, thread aesthetics, microneedling and radiofrequency assisted devices, chemical peeling.</p>\r\n\r\n<p>&nbsp;</p>\r\n', '', '', '', '', '', '', '', '', '', '', 'Wer ist Gökçe Özel?', '<p>Ich habe meinen Abschluss Medizinische Fakult&auml;t der Cerrahpasa-Universit&auml;t Istanbul in englischer Sprache gemacht. Ich habe meine Spezialisierungsausbildung in Dışkapı Yıldırım Beyazıt Ausbildungs- und Forschungskrankenhaus, Hals-Nasen-Ohren-Klinik abgeschlossen.</p>\r\n\r\n<p>Zwischen 2013 und 2021 arbeitete ich als Fakult&auml;tsmitglied an der Medizinischen Fakult&auml;t der Universit&auml;t Kırıkkale, Abteilung f&uuml;r Hals-Nasen-Ohrenheilkunde. 2015 wurde ich Associate Professor und 2021 Professor.</p>\r\n\r\n<p>Ich bin Vorstandsmitglied der Turkish Facial Plastic Surgery Association und Mitglied der European Facial Plastic Surgery Association. Ich bin im internationalen Beirat der Complications in Medical Aesthetic Collaborative (CMAC). Ich habe &uuml;ber 100 Artikel in nationalen und internationalen Zeitschriften ver&ouml;ffentlicht und mein H-Index ist 12.</p>\r\n\r\n<p>Mein berufliches Interesse gilt der plastischen Gesichtschirurgie. Minimal-invasive und invasive Eingriffe, die ich aktiv zur Gesichtsverj&uuml;ngung in meiner klinischen Praxis durchf&uuml;hre sind Gesichts- und Halsstraffung, Wangenfettabsaugung, Nasenkorrektur, Lidstraffung, Augenbrauen- und Stirnstraffung, prominente Ohr&auml;sthetik, Kinn&auml;sthetik, Bichektomie, Gr&uuml;bchen&auml;sthetik, Botulinumtoxin und Filler-Anwendungen, Mesotherapie, Lipolyse-Mesotherapie, Faden&auml;sthetik, Mikro-Nadeln und radiofrequenzunterst&uuml;tzte Ger&auml;te, chemisches Peeling.</p>\r\n', '', NULL, NULL, NULL, '560f90dee99bf2a65f1420220320eyalcinfb244a80aa5cd543d597', '1', '2022-03-20 14:22:06', NULL, NULL, NULL, '1'),
('16', '40', '2022-03-20', NULL, 'Neler Yapıyoruz', '<p>&nbsp;</p>\r\n\r\n<ul>\r\n	<li>Burun Estetiği</li>\r\n	<li>Kulak Estetiği</li>\r\n	<li>Y&uuml;z Germe Estetiği</li>\r\n	<li>Boyun Germe Estetiği</li>\r\n	<li>G&ouml;z Estetiği</li>\r\n	<li>&Ccedil;ene Estetiği</li>\r\n	<li>Endoskopik Sin&uuml;s Cerrahisi</li>\r\n	<li>Sin&uuml;s Tedavisi</li>\r\n	<li>Migren Tedavisi</li>\r\n	<li>Dolgu&nbsp;Uygulamaları</li>\r\n	<li>Ozon Uygulamaları</li>\r\n</ul>\r\n', '', 'What We Do', '<p>Nose Aesthetics<br />\r\nEar Aesthetics<br />\r\nFace Lift Aesthetics<br />\r\nNeck Lift Aesthetics<br />\r\nEye Aesthetics<br />\r\nChin Aesthetics<br />\r\nEndoscopic Sinus Surgery<br />\r\nSinus Treatment<br />\r\nMigraine Treatment<br />\r\nFilling&nbsp;<br />\r\n<br />\r\n&nbsp;</p>\r\n', '', '', '', '', 'ماذا نفعل', '<p dir=\"rtl\">&nbsp;</p>\r\n\r\n<p dir=\"rtl\">تجميل الأنف&nbsp;&nbsp;</p>\r\n\r\n<p dir=\"rtl\">جراحة الجيوب الأنفية بالمنظار&nbsp;</p>\r\n\r\n<p dir=\"rtl\">شد الوجه (فايسليفت)&nbsp;</p>\r\n\r\n<p dir=\"rtl\">سكوب تجميل الأذن (اوتوبلاستي)&nbsp;</p>\r\n\r\n<p dir=\"rtl\">تجميل الوجه والرقبة&nbsp;</p>\r\n\r\n<p dir=\"rtl\">جماليات عين اللوز&nbsp;</p>\r\n\r\n<p dir=\"rtl\">جماليات الجفن&nbsp;</p>\r\n\r\n<p dir=\"rtl\">حشو&nbsp;</p>\r\n\r\n<p dir=\"rtl\">شد الوجه بحبل (حزام فرنسي )&nbsp;</p>\r\n\r\n<p dir=\"rtl\">علاج الصداع النصفي&nbsp;</p>\r\n\r\n<p dir=\"rtl\">شفط دهون الذقن&nbsp;</p>\r\n\r\n<p dir=\"rtl\">تجميل الفك (مينتوبلاستي)&nbsp;</p>\r\n\r\n<p dir=\"rtl\">إجراءات تقشير الجلد (التقشير الكيميائي)&nbsp;</p>\r\n\r\n<p dir=\"rtl\">تصحيح الندبات (مراجعة الندبة)</p>\r\n', '', '', '', '', 'Was machen wir?', '<ul>\r\n	<li>\r\n	<p><strong>Rhinoplastik</strong></p>\r\n	</li>\r\n	<li>\r\n	<p><strong>Ohrenschmalz (Otoplastik)</strong></p>\r\n	</li>\r\n	<li>\r\n	<p><strong>Gesichts-Hals-&Auml;sthetik</strong></p>\r\n	</li>\r\n	<li>\r\n	<p><strong>Augenlid&auml;sthetik</strong></p>\r\n	</li>\r\n	<li>\r\n	<p><strong>Augenbrauen Heben</strong></p>\r\n	</li>\r\n	<li>\r\n	<p><strong>Lippen&auml;sthetik</strong></p>\r\n	</li>\r\n	<li>\r\n	<p><strong>Facelift</strong></p>\r\n	</li>\r\n	<li>\r\n	<p><strong>Kinn&auml;sthetik</strong></p>\r\n	</li>\r\n	<li>\r\n	<p><strong>Füllung</strong></p>\r\n	</li>\r\n</ul>\r\n', '', NULL, NULL, NULL, '44a1b353e234c3d9e1d520220320eyalcin889b27d8733957315ee7', '1', '2022-03-20 14:57:06', NULL, NULL, NULL, '1'),
('17', '41', '2022-03-20', NULL, 'Prof. Dr. Gökçe Özel Kliniği', '<p>Y&uuml;z Estetiği hakkında detaylı bilgi almak i&ccedil;in l&uuml;tfen iletişim kanalları &uuml;zerinden bize ulaşın.</p>\r\n', '', 'Prof. Dr. Gokce Private Clinic', '<p>For detailed information about Facial Aesthetics, please contact us via communication channels.</p>\r\n', '', '', '', '', 'عيادة البروفيسور دكتور جوكشه اوزيل ', '<p dir=\"rtl\">للحصول على معلومات مفصلة حول جماليات الوجه ، يرجى الاتصال بنا عبر قنوات الاتصال.</p>\r\n', '', '', '', '', '', '', '', NULL, NULL, NULL, '960f9d3fa7e6325f814220220320eyalcin7d7b14d9461ddae47bec', '1', '2022-03-20 15:08:09', NULL, NULL, NULL, '1'),
('18', '45', '2022-03-20', NULL, 'Yüz Estetiği mi düşünüyorsunuz ?', '<p style=\"text-align:center\">Rinoloji, otoloji, baş ve boyun cerrahisi alanlarında &ccedil;ok sayıda klinik ve akademik &ccedil;alışması bulunan Prof. Dr. G&ouml;k&ccedil;e &Ouml;zel&rsquo;in asıl ilgi alanı y&uuml;z estetik cerrahisidir.&nbsp;Klinik pratiğinde &ouml;zellikle y&uuml;z gen&ccedil;leştirmeye y&ouml;nelik, y&uuml;ze uyumlu ve doğal bir g&ouml;r&uuml;n&uuml;m elde etmeyi ama&ccedil;layan m&uuml;dahaleler ger&ccedil;ekleştirmeyi seven G&ouml;k&ccedil;e &Ouml;zel bu anlamda sayısız y&uuml;z ve boyun germe, gıdı liposuction, rinoplasti, blefaroplasti, kaş kaldırma ve alın germe, kep&ccedil;e kulak estetiği, &ccedil;ene estetiği, botulinum toksin ve dolgu uygulamaları, mezoterapi, lipoliz mezoterapisi ve ip estetiği işlemleri ger&ccedil;ekleştirmiştir.&nbsp;</p>\r\n', '', '', '', '', '', '', '', 'هل تفكر في جماليات الوجه؟', '<p dir=\"rtl\">البروفيسور دكتور جوكشه اوزيل ، التي لديها الكثير من الدراسات السريرية والأكاديمية في مجالات طب الأنف والأذن والحنجرة وجراحة الرأس والرقبة ، هي الاهتمام الرئيسي لجراحة تجميل الوجه. جوكشه اوزيل ، التي تحب إجراء التدخلات التي تهدف إلى تحقيق مظهر متناغم وطبيعي ، خاصة لتجديد شباب الوجه في ممارستها السريرية ، لديها العديد من عمليات شد الوجه والرقبة ، وشفط دهون الذقن ، وجراحة الأنف ، وجراحة الجفن ، ورفع الحاجب وشد الجبهة ، وجماليات الأذن البارزة ، تجميل الذقن ،&nbsp; تم إجراء تطبيقات توكسين البوتولينوم والحشو ، الميزوثيرابي ، الميزوثيرابي تحلل الدهن ، تجميل الخيوط.</p>\r\n', '', '', '', '', 'Denken Sie über Gesichtsästhetik nach?', '<p>Nach vielen klinischen und akademischen Studien in den Bereichen Rhinologie, Otologie, Kopf- und Halschirurgie liegt das Hauptinteresse von Prof. Dr. G&ouml;k&ccedil;e &Ouml;zel in der &auml;sthetischen Gesichtschirurgie.</p>\r\n\r\n<p>G&ouml;k&ccedil;e &Ouml;zel, die in ihrer klinischen Praxis gerne Eingriffe vor allem zur Gesichtsverj&uuml;ngung vornimmt und ein harmonisches und nat&uuml;rliches Erscheinungsbild anstrebt, hat in diesem Sinne zahlreiche &auml;sthetische Gesichts- und Halslifting-Operationen, Wangenfettabsaugung, Rhinoplastik, Blepharoplastik, Augenbrauenlifting und Stirnlifting, Abstehende Ohr&auml;sthetik, Kinn&auml;sthetik, Botulinumtoxin- und F&uuml;llungsanwendungen, Mesotherapie, Lipolyse, Mesotherapie und Faden&auml;sthetik durchgef&uuml;hrt.</p>\r\n', '', NULL, NULL, NULL, 'b0503f383a6a7bd328be20220320eyalcinca37b61b0cc20b946534', '1', '2022-03-20 17:43:08', NULL, NULL, NULL, '1'),
('19', '43', '2022-03-20', NULL, 'Revizyon Rinoplasti', '<p>Revizyon Rinoplasti, daha &ouml;nce ameliyat olmuş fakat burundaki şekil bozuklukları ile nefes alma problemleri devam eden ve bu sorunlarla birlikte ortaya &ccedil;ıkan psikolojik etkileri de d&uuml;zeltmeyi ama&ccedil;layan bir operasyondur.&nbsp; Bu operasyon Rinoplasti ameliyatlarına oranla daha zordur. Hasta beklentisinin y&uuml;ksek olduğu ancak buna karşın başarı oranının ilk ameliyata g&ouml;re daha d&uuml;ş&uuml;k olabileceği bir cerrahidir. Ayrıca hassas bir cerrahi birikim gerektiren ve titizlikle yapılması gereken bir ameliyattır.<br />\r\n<br />\r\nOperasyon, daha &ouml;nce ger&ccedil;ekleşmiş ameliyat sonrası ortaya &ccedil;ıkan sorunların tedavisi amacıyla uygulanır.&nbsp; Burnun yeniden şekillendirilmesi ve y&uuml;zle uyumlu estetik bir g&ouml;r&uuml;n&uuml;m&uuml;n sağlaması hedeflenir.&nbsp;Burun sırtındaki &ccedil;&ouml;kme (semer burun deformitesi), burun sırtındaki kemer g&ouml;r&uuml;n&uuml;m&uuml;, septum deviasyonu (kemik eğikliğinin), burun i&ccedil;indeki veya dışındaki doku kaybındaki artış, burun etlerinde şişlik ve bunlara bağlı nefes alma şikayetlerinin ortadan kaldırılmasını ama&ccedil;lar.<br />\r\n<br />\r\nOperasyon yaklaşık 2,5-3 saat s&uuml;rmektedir. Hastalar ameliyattan sonra 1 gece hastanede misafir edilir. Bu s&uuml;re&ccedil;te iyileşmeyi hızlandırıcı tedaviler ve soğuk uygulamaları yapılır. Kıkırdak ve kemikler gibi hassas b&ouml;lgeleri korumak adına al&ccedil;ı ve ortası delik olan bir silikon tampon konulur. Silikon tamponlar 2 g&uuml;n sonra, burun ucu dikişleri 7 g&uuml;n sonra alınır ve hasta g&uuml;nl&uuml;k yaşamına d&ouml;ner.</p>\r\n', '', 'Revision Rhinoplasty', '<p>Revision Rhinoplasty is an operation that has been operated before, but still has nasal deformities and breathing problems, and aims to correct the psychological effects that occur with these problems. This operation is more difficult than Rhinoplasty operations. It is a surgery in which patient expectation is high, but the success rate may be lower than the first surgery. In addition, it is an operation that requires a sensitive surgical experience and must be performed meticulously.</p>\r\n\r\n<p>The operation is applied for the treatment of problems that occur after the previous operation. It is aimed to reshape the nose and provide an aesthetic appearance compatible with the face. It aims to eliminate the collapse of the nasal dorsum (saddle nose deformity), the appearance of the arch on the nasal dorsum, the deviation of the septum (bone curvature), the increase in tissue loss inside or outside the nose, the swelling of the nasal concha and the related breathing complaints.</p>\r\n\r\n<p>The operation takes approximately 2.5-3 hours. Patients are hosted in the hospital for 1 night after the operation. In this process, treatments that accelerate healing and cold applications are made. In order to protect sensitive areas such as cartilage and bones, a plaster and a silicone pad with a hole in the middle are placed. Silicone pads are removed after 2 days, nasal tip sutures are removed after 7 days and the patient returns to his daily life.</p>\r\n', '', '', '', '', 'مراجعة تجميل الأنف', '<p dir=\"rtl\">مراجعة عملية تجميل الأنف هي عملية أجريت من قبل ، ولكن مشاكل التنفس مع تشوهات في الأنف لا تزال قائمة ، وتهدف إلى تصحيح الآثار النفسية التي تحدث مع هذه المشاكل. هذه العملية أكثر صعوبة من عمليات تجميل الأنف. إنها عملية جراحية يكون فيها توقع المريض مرتفعا ولكن معدل النجاح قد يكون أقل مقارنة بالجراحة الأولى. وهي أيضا عملية تتطلب تراكما جراحيا دقيقا يجب إجراؤها بدقة.</p>\r\n\r\n<p dir=\"rtl\">يتم تنفيذ العملية لغرض علاج المشاكل التي نشأت بعد الجراحة السابقة. يهدف إلى إعادة تشكيل الأنف وتوفير مظهر جمالي متوافق مع الوجه. ويهدف إلى القضاء على الشكاوى من انهيار في الجزء الخلفي من الأنف (تشوه الأنف سيمر) ، وظهور قوس في الجزء الخلفي من الأنف ، وانحراف الحاجز (انحناء العظام) ، وزيادة فقدان الأنسجة داخل أو خارج الأنف ، وتورم في لحم الأنف ، وما يرتبط بها من التنفس.&nbsp;</p>\r\n\r\n<p dir=\"rtl\">تستغرق العملية حوالي ساعتين ونصف أو ثلاث ساعات. يتم استضافة المرضى في المستشفى لمدة ليلة واحدة بعد العملية. في هذه العملية ، العلاجات والتطبيقة الباردة لتسريع الشفاء. من أجل حماية المناطق الحساسة مثل الغضروف والعظام ،&nbsp; يتم وضع جبيرة و وحشا من السيليكون مع وجود ثقب في المنتصف. تتم إزالة حفائظ السيليكون بعد يومين ، ويتم إزالة خيوط طرف الأنف بعد سبعة أيام ، ويعود المريض إلى حياته اليومية.</p>\r\n', '', '', '', '', 'Revision Rhinoplastik', '<p>Revision Rhinoplastik ist eine Operation, die zuvor operiert wurde, aber die Deformit&auml;ten der Nase und Atemprobleme bestehen und darauf abzielt, die psychologischen Effekte zu korrigieren, die mit diesen Problemen auftreten. Diese Operation ist schwieriger als Rhinoplastik-Operationen. Es ist eine Operation, bei der die Erwartungen des Patienten hoch sind, aber die Erfolgsrate niedriger sein kann als bei der ersten Operation. Es ist auch eine Operation, die eine pr&auml;zise chirurgische Akkumulation erfordert und sorgf&auml;ltig durchgef&uuml;hrt werden muss.<br />\r\n<br />\r\nDie Operation wird durchgef&uuml;hrt, um Probleme zu behandeln, die nach der Operation aufgetreten sind. Es zielt darauf ab, die Nase neu zu gestalten und ein &auml;sthetisches Aussehen zu bieten, das mit dem Gesicht kompatibel ist. Es zielt darauf ab, den Kollaps des Nasenr&uuml;ckens (Sattelnasendeformit&auml;t), das Auftreten von B&ouml;gen im Nasenr&uuml;cken, die Abweichung des Septums (Knochenneigung), den Anstieg des Gewebeverlustes innerhalb oder au&szlig;erhalb der Nase, Schwellungen des Nasenfleisches und damit verbundene Atembeschwerden zu beseitigen.<br />\r\n<br />\r\nDie Operation dauert ca. 2,5-3 Stunden. Patienten werden 1 Nacht nach der Operation im Krankenhaus untergebracht. In diesem Prozess werden Behandlungen und kalte Anwendungen durchgef&uuml;hrt, die die Heilung beschleunigen. Um empfindliche Bereiche wie Knorpel und Knochen zu sch&uuml;tzen, werden Gips und ein Silikonpuffer mit einem Loch in der Mitte eingesetzt. Silikonpuffer werden nach 2 Tagen entfernt, Nasen-Stiche nach 7 Tagen und der Patient kehrt in seinen Alltag zur&uuml;ck.<br />\r\n<br />\r\n&nbsp;</p>\r\n', '', NULL, NULL, NULL, 'f702d59a3bb376153fac20220320eyalcin953400e5f4c7d9d00ebc', '1', '2022-03-20 17:48:44', NULL, NULL, NULL, '1'),
('20', '42', '2022-03-20', NULL, 'İple Yüz Germe (Fransız Askı)', '<p>Son d&ouml;nemlerde olduk&ccedil;a pop&uuml;lerleşen bu işlem, cerrahi operasyonları tercih etmeyen hastalar tarafından olduk&ccedil;a ilgi g&ouml;ren bir operasyondur. Y&uuml;z hatlarından memnun olmayan, cilt y&uuml;zeyinde sarkma ve kırışma meydana gelmiş kişilerde kullanılan bu y&ouml;ntem, kısmi y&uuml;z felci ge&ccedil;iren hastalarda da kullanılabilen tedavi edici bir y&ouml;ntemdir. Kullanılan &uuml;r&uuml;n&uuml;n biyolojik anlamda insan v&uuml;cuduna uyumlu olması sebebi ile &uuml;r&uuml;n&uuml;n markasına bağlı olarak yıllarca cilt altında kalması m&uuml;mk&uuml;nd&uuml;r.&nbsp;</p>\r\n\r\n<p>Cerrahi operasyonların uzun s&uuml;ren iyileşme s&uuml;re&ccedil;leri ve maliyetleri g&ouml;z &ouml;n&uuml;ne alındığında Fransız askı olduk&ccedil;a konforlu bir tedavi y&ouml;ntemidir. Bu işlemde y&uuml;z germe ameliyatlarında kullanılan medikal iplikler kullanılır. Bu iplerin &uuml;zerinde dokuya tutunmayı sağlayan kıl&ccedil;ıklar yer almaktadır. Operasyon sonrasında y&uuml;zdeki kırışıklıklar ve sarkmaların tedavisi ama&ccedil;lanır.&nbsp;</p>\r\n\r\n<p>Fransız askı uygulamasının cerrahi operasyonlarla tek farkı kalıcılık s&uuml;residir. İşlem s&uuml;resi ortalama 45 dk ile 1 saat arasındadır. Operasyon sonrasında az da olsa &ouml;dem ve iğne izi kalabilir. &nbsp;Bu şikayetler ortalama 1 hafta s&uuml;rer sonrasında g&uuml;nl&uuml;k hayatınıza devam edebilirsiniz. Hızlı hareketler ve &ccedil;ene hareketleri sırasında iplerin bulunduğu yerlerde gerginlik hissedilebilir. Bu şikayetlerde genellikle 2. haftadan sonra kaybolur.</p>\r\n\r\n<p>İşlemden sonra 1 ay s&uuml;re ile y&uuml;z&uuml;st&uuml; yatılması, kabuklu ve sert yiyeceklerin yenilmesi, abartılı mimik hareketi yapılması, &ccedil;enenin &ccedil;ok fazla a&ccedil;ılmasını gerektiren hareketler &ouml;nerilmemektedir.</p>\r\n', '', 'Thread Face Lift (French Strap)', '<p>This procedure, which has become very popular recently, is an operation that attracts a lot of attention by patients who do not prefer surgical operations. This method, which is used in people who are not satisfied with their facial features, and who have sagging and wrinkling on the skin surface, is a therapeutic method that can also be used in patients with partial facial paralysis. Since the product used is biologically compatible with the human body, it is possible to remain under the skin for years depending on the brand of the product.</p>\r\n\r\n<p>Considering the long healing processes and costs of surgical operations, the French sling is a very comfortable treatment method. In this process, medical threads used in face lift surgeries are used. There are awns on these threads that provide attachment to the tissue. After the operation, it is aimed to treat the wrinkles and sagging on the face.</p>\r\n\r\n<p>The only difference between the French sling and surgical operations is the permanence period. The processing time is between 45 minutes and 1 hour on average. After the operation, a little edema and needle scar may remain. These complaints last for an average of 1 week, then you can continue with your daily life. During fast movements and jaw movements, tension may be felt in the places where the ropes are located. These complaints usually disappear after the 2nd week.</p>\r\n\r\n<p>After the procedure, it is not recommended to lie face down for 1 month, eat crusty and hard foods, make exaggerated mimic movements, and movements that require the jaw to be opened too much.</p>\r\n', '', '', '', '', 'شد الوجه بحبل (حزام فرنسي )', '<p dir=\"rtl\">هذا الإجراء ، الذي أصبح شائعا جدا مؤخرا، هو عملية تحظى بشعبية كبيرة لدى المرضى الذين لا يفضلون العمليات الجراحية. هذه الطريقة ، التي تستخدم في الأشخاص غير الراضين عن ملامح وجههم ، وقد حدث ترهل وتجعد على سطح الجلد، هي طريقة علاجية يمكن استخدامها أيضا في المرضى الذين يعانون من شلل جزئي في الوجه. نظرا لحقيقة أن المنتج المستخدم متوافق بيولوجيا مع جسم الإنسان، فمن الممكن أن يبقى المنتج تحت الجلد لسنوات عديدة ، اعتمادا على العلامة التجارية.&nbsp;</p>\r\n\r\n<p dir=\"rtl\">شد الوجه بالحزام الفرنسي هي طريقة مريحة إلى حد ما للعلاج ، نظرا لعمليات الاسترداد الطويلة وتكاليف العمليات الجراحية. في هذه العملية ، يتم استخدام الخيوط الطبية المستخدمة في عمليات شد الوجه. على هذه الحبال ، هناك شوك تسمح لك بالتمسك بالأنسجة. ويهدف إلى علاج التجاعيد والترهل على الوجه بعد العملية.</p>\r\n\r\n<p dir=\"rtl\">الفرق الوحيد بين تطبيق شد الوجه بالحزام الفرنسي والعمليات الجراحية هو مدة الدوام. تستغرق العملية متوسط ٤٥&nbsp; دقائق ل ١&nbsp; ساعة. بعد العملية ، قد يكون هناك وذمة صغيرة وندبة إبرة. هذه الشكاوى تستمر في المتوسط من أسبوعا ، وبعد ذلك يمكنك مواصلة حياتك اليومية. يمكن الشعور بالتوتر في الأماكن التي توجد فيها الحبال أثناء الحركات السريعة وحركات الفك. عادة ما تختفي هذه الشكاوى بعد الأسبوع الثاني.&nbsp;</p>\r\n\r\n<p dir=\"rtl\">بعد هذا الإجراء ، فمن غير المستحسن أن يكذب وجهه لأسفل لمدة شهرا ، وتناول الأطعمة القشرة والصلبة ، وجعل الحركات تقليد مبالغ فيها ، والحركات التي تتطلب الكثير من فتح الفك.&nbsp;</p>\r\n', '', '', '', '', 'Facelift mit Faden (Französischer Riemen)', '<p>Dieses Verfahren, das in letzter Zeit sehr populär geworden ist, ist eine Operation, die viel Aufmerksamkeit von Patienten auf sich zieht, die chirurgische Eingriffe nicht bevorzugen. Diese Methode, die bei Menschen angewendet wird, die mit ihren Gesichtszügen unzufrieden sind und die eine Erschlaffung und Faltenbildung auf der Hautoberfläche haben, ist eine therapeutische Methode, die auch bei Patienten mit partieller Gesichtslähmung angewendet werden kann. Da das verwendete Produkt mit dem menschlichen Körper biologisch verträglich ist, ist es je nach Produktmarke möglich, jahrelang unter der Haut zu bleiben.</p>\r\n\r\n<p>In Anbetracht der langen Heilungsprozesse und Kosten chirurgischer Eingriffe ist die französische Schlinge eine sehr komfortable Behandlungsmethode. Bei diesem Verfahren</p>\r\n\r\n<p>werden medizinische Fäden verwendet, die bei Facelift-Operationen verwendet werden. Auf diesen Fäden befinden sich Grannen, die eine Befestigung am Gewebe ermöglichen. Nach der Operation sollen die Falten und die Erschlaffung des Gesichts behandelt werden.</p>\r\n\r\n<p>Der einzige Unterschied zwischen der französischen Schlinge und chirurgischen Eingriffen ist die Verweildauer. Die Bearbeitungszeit beträgt durchschnittlich zwischen 45 Minuten und 1 Stunde. Nach der Operation kann ein kleines Ödem und eine Nadelnarbe zurückbleiben. Diese Beschwerden halten durchschnittlich 1 Woche an, danach können Sie Ihr tägliches Leben fortsetzen. Bei schnellen Bewegungen und Kieferbewegungen kann an den Stellen, an denen sich die Seile befinden, eine Spannung zu spüren sein. Diese Beschwerden verschwinden in der Regel nach der 2. Woche.</p>\r\n\r\n<p>Nach dem Eingriff wird davon abgeraten, 1 Monat lang mit dem Gesicht nach unten zu liegen, knusprige und harte Speisen zu sich zu nehmen, übertriebene mimische Bewegungen auszuführen und Bewegungen auszuführen, bei denen der Kiefer zu weit geöffnet werden muss.</p>\r\n', '', NULL, NULL, NULL, '02954f0720e18e0a7ff720220320eyalcin7c3c20a2dd49dcaa1cb1', '1', '2022-03-20 17:49:48', NULL, NULL, NULL, '-1'),
('21', '43', '2022-03-20', NULL, 'Badem Göz Estetiği', '<p>Badem g&ouml;z estetiği tamamen estetik ama&ccedil;la ger&ccedil;ekleştirilir. Bu operasyon ile g&ouml;z&uuml;n dış kenarı yukarıya &ccedil;ekilerek daha &ccedil;ekik g&ouml;r&uuml;nmesi ama&ccedil;lanır. Burada dikkat edilmesi gereken en &ouml;nemli husus &ccedil;ekikliğin g&ouml;ze uygun olmasıdır. Genel ama&ccedil; makyajla verilmeye &ccedil;alışılan g&ouml;r&uuml;nt&uuml;n&uuml;n kalıcı hale getirilmesidir.&nbsp;Sanılanın aksine badem g&ouml;z estetiğinde g&ouml;zler b&uuml;y&uuml;mez, sadece daha &ccedil;ekik hale gelir.<br />\r\n<br />\r\nOperasyon ortalama 1 saat s&uuml;rmektedir. Kombine cerrahi&nbsp; yapılıp yapılmamasına g&ouml;re hastanede kalış s&uuml;resi değişebilir. Sadece badem g&ouml;z estetiği olan hasta aynı g&uuml;n taburcu edilir. Genellikle 5-7 g&uuml;n arasında dikişler alınır, bu s&uuml;re sonunda y&uuml;zdeki &ouml;demler &ouml;nemli oranda azalır ve hasta normal hayatına d&ouml;n&uuml;ş yapabilir.&nbsp;</p>\r\n\r\n<p>&nbsp;</p>\r\n', '', 'Almond Eye Aesthetics', '<p>Almond eye aesthetics is performed for purely aesthetic purposes. With this operation, it is aimed to make the outer edge of the eye look more slanted by pulling up. The most important thing to note here is that the slanting is suitable for the eye. The general purpose is to make the image that is tried to be given with make-up permanent. Contrary to popular belief, the eyes do not grow in almond eye aesthetics, they just become more slanting.</p>\r\n\r\n<p>The operation takes an average of 1 hour. Depending on whether or not combined surgery is performed, the length of stay in the hospital may vary. The patient with only almond eye aesthetics is discharged on the same day. Generally, the stitches are removed between 5-7 days, after which the edema on the face decreases significantly and the patient can return to his normal life.</p>\r\n', '', '', '', '', 'جماليات عين اللوز', '<p dir=\"rtl\">يتم إجراء جماليات عين اللوز لأغراض جمالية بحتة. في هذه العملية ، يتم سحب الحافة الخارجية للعين بحيث تبدو مائلة أكثر. أهم شيء يجب ملاحظته هنا هو أن الميل مناسب للعين. الغرض العام هو جعل الصورة التي يُحاول تقديمها بالمكياج دائمة. خلافا للاعتقاد الشائع ، لا تنمو العيون في جماليات عين اللوز ، بل تصبح أكثر ميلًا.&nbsp;</p>\r\n\r\n<p dir=\"rtl\">تستغرق العملية في المتوسط ١ ساعة. اعتمادا على ما إذا تم إجراء عملية جراحية مشتركة ، قد تختلف مدة الإقامة في المستشفى. يتم تفريغ المريض الذي عملية من جماليات عين اللوز فقط في نفس اليوم. عادة ، تؤخذ غرز بين٥ و ٧ أيام ، وبعد ذلك الوقت وذمة على الوجه خفضت بشكل كبير ويمكن للمريض العودة إلى حياته الطبيعية.</p>\r\n', '', '', '', '', 'Mandelaugen-Ästhetik', '<p>Mandel Augen&auml;sthetik wird zu rein &auml;sthetischen Zwecken durchgef&uuml;hrt. Mit dieser Operation soll der &auml;u&szlig;ere Rand des Auges nach oben gezogen werden, um schr&auml;ger auszusehen. Das Wichtigste, was hier zu beachten ist, ist, dass die schr&auml;ge nicht f&uuml;r das Auge geeignet ist. Das allgemeine Ziel ist es, das Bild, das mit Make-up versucht wird, dauerhaft zu machen. Entgegen der landl&auml;ufigen Meinung wachsen die Mandelaugen nicht, sie werden nur schr&auml;ger.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>Die Operation dauert durchschnittlich 1 Stunde. Je nachdem, ob eine kombinierte Operation durchgef&uuml;hrt wird oder nicht, kann sich die Dauer des Krankenhausaufenthalts &auml;ndern. Nur Patienten mit Mandelaugen werden am selben Tag entlassen. In der Regel werden die Stiche zwischen 5-7 Tagen entfernt, nach dieser Zeit werden die &Ouml;deme im Gesicht deutlich reduziert und der Patient kann in sein normales Leben zur&uuml;ckkehren.</p>\r\n', '', NULL, NULL, NULL, '57b94f48f6172d25f52b20220320eyalcin858b89de9e5062ebe328', '1', '2022-03-20 17:50:24', NULL, NULL, NULL, '1'),
('22', '8', '2022-03-21', NULL, 'Yüz Prosedürleri', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', NULL, NULL, NULL, '7153a38555462c248cae20220321eyalcin7bb02bfdaa8d55a54386', '1', '2022-03-21 10:28:47', NULL, NULL, NULL, '1'),
('23', '8', '2022-03-21', NULL, 'Ameliyatsız İşlemler', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', NULL, NULL, NULL, 'd98c220a587ab416b0b920220321eyalcin7b6db737fd3e48fc5e74', '1', '2022-03-21 10:29:29', NULL, NULL, NULL, '1'),
('24', '46', '2022-03-21', NULL, 'Neden Estetiği Tercih Ettiniz ?', '<p>Baktığım her şeyde hekim olarak bir g&uuml;zellik arıyorum. Buna doğa, insan, hayvan ve bitki dahil. Sinema, televizyon ve resim gibi kişisel sanatlara da ilgi duyuyorum.</p>\r\n', '', 'Why Did You Prefer Aesthetics?', '<p>As a doctor, I look for beauty in everything I look at. This includes nature, humans, animals and plants. I am also interested in personal arts such as cinema, television and painting.</p>\r\n', '', '', '', '', 'لماذا اخترت الجماليات؟', '<p dir=\"rtl\">أنا أبحث عن الجمال كطبيب في كل ما ننظر. وهذا يشمل الطبيعة والإنسان والحيوانات والنباتات. أنا مهتم أيضا بالفنون الشخصية مثل السينما والتلفزيون والرسم.&nbsp;</p>\r\n', '', '', '', '', 'Warum haben Sie Ästhetik bevorzugt?', '<p>Als Arzt achte ich bei allem, was ich betrachte, auf Sch&ouml;nheit. Dazu geh&ouml;ren Natur, Menschen, Tiere und Pflanzen. Ich interessiere mich auch f&uuml;r pers&ouml;nliche K&uuml;nste wie Kino, TV und Malerei.</p>\r\n', '', NULL, NULL, NULL, 'e49b8fe3bd029ba5725a20220321eyalcin274ed8e2e22c831ff177', '1', '2022-03-21 11:10:35', NULL, NULL, NULL, '1'),
('25', '46', '2022-03-21', NULL, 'Estetik operasyonlar psikolojiyi nasıl etkiliyor ?', '<p>Estetik operasyonlar psikolojik etkileri olduk&ccedil;a g&uuml;&ccedil;l&uuml; olan işlemlerdir. Benim hastalarımda en &ccedil;ok g&ouml;zlemlediğim nokta &ouml;zg&uuml;ven artışı. Kısacası estetik operasyonların pozitif etkilerini&nbsp;sık&ccedil;a tecr&uuml;be ediyorum.</p>\r\n', '', 'How does plastic surgery affect psychology?', '<p>Aesthetic operations are procedures with very strong psychological effects. The point I have observed most in my patients is the increase in self-confidence. In short, I frequently experience the positive effects of aesthetic operations.</p>\r\n', '', '', '', '', 'كيف تؤثر العمليات الجمالية على علم النفس؟', '<p dir=\"rtl\">العمليات الجمالية هي العمليات التي تكون آثارها النفسية قوية جدا. النقطة الأكثر شيوعا التي ألاحظها في مرضاي هي زيادة الثقة بالنفس. باختصار ، غالبا ما أجرّب الآثار الإيجابية للعمليات الجمالية.</p>\r\n', '', '', '', '', 'Wie wirkt sich plastische Chirurgie auf die Psychologie aus?', '<p>&Auml;sthetische Operationen sind Eingriffe mit sehr starker psychologischer Wirkung. Was ich bei meinen Patienten am meisten beobachte, ist die Steigerung des Selbstbewusstseins. Kurz gesagt erlebe ich h&auml;ufig die positive Wirkung &auml;sthetischer Operationen.</p>\r\n', '', NULL, NULL, NULL, '8ec1ec611ca40fe3fdd720220321eyalcin7ddafe240a51f7c754d2', '1', '2022-03-21 11:10:55', NULL, NULL, NULL, '1'),
('26', '46', '2022-03-21', NULL, 'İşlemim nerede yapılacak?', '<p>Cerrahi gerektirmeyen işlemleri kendi kliniğimde yapıyorum. Ameliyatları ise &ccedil;&ouml;z&uuml;m ortaklığı yaptığımız &Ouml;zel Hastanelerde ger&ccedil;ekleştiriyorum.</p>\r\n', '', 'Where will my procedure be done?', '<p>I do non-surgical procedures in my own clinic. I perform the surgeries in Private Hospitals with which we are solution partners.</p>\r\n', '', '', '', '', 'أين سيتم تنفيذ معاملتي؟', '<p dir=\"rtl\">أقوم بإجراء عمليات لا تتطلب جراحة في عيادتي الخاصة. أقوم بإجراء العمليات الجراحية في المستشفيات الخاصة حيث نحن شريك الحل.&nbsp;</p>\r\n', '', '', '', '', 'Wo wird mein Eingriff durchgeführt?', '<p>Ich f&uuml;hre nicht-chirurgische Eingriffe in meiner eigenen Klinik durch. Operationen, die eine chirurgische Eingriffe erfordern, f&uuml;hre ich in Privatkliniken durch, mit denen wir L&ouml;sungspartner sind.</p>\r\n', '', NULL, NULL, NULL, '23b56b04ca2bb6fe3efc20220321eyalcin9b3f0fdd629c977554a5', '1', '2022-03-21 11:11:17', NULL, NULL, NULL, '1'),
('27', '46', '2022-03-21', NULL, 'Ameliyat Süreci Nasıl İşliyor ?', '<p>&Ouml;ncelikle muayene olmaya geliyorsunuz. Daha sonrasında yapılacak işlemleri konuşuyoruz. Daha sonrasında da ameliyata karar veriyoruz. Ameliyat sonrası 5. g&uuml;n dikiş alma işlemleri ger&ccedil;ekleşiyor. İyileşme s&uuml;reci de ortalama 7-10 g&uuml;n kadar s&uuml;r&uuml;yor.</p>\r\n', '', 'How Does the Surgery Process Work?', '<p>First of all, you come to be examined. We talk about what to do next. Then we decide on the surgery. Stitches are removed on the 5th day after the surgery. The healing process takes about 7-10 days on average.</p>\r\n', '', '', '', '', 'كيف تعمل عملية الجراحة؟', '<p dir=\"rtl\">في البداية ، سوف تأتي لفحصها. فنحن نتحدث عن الإجراءات. ثم نقرر إجراء عملية جراحية مناسب لك. تتم إزالة الغرز في اليوم الخامس بعد الجراحة. تستغرق عملية الشفاء أيضا حوالي ٧ -١٠&nbsp; أيام في المتوسط.&nbsp;</p>\r\n', '', '', '', '', 'Wie funktioniert der Operationsprozess?', '<p>Zun&auml;chst einmal kommen Sie zur Untersuchung. Wir besprechen, was als n&auml;chstes zu tun ist. Dann entscheiden wir uns f&uuml;r die Operation. Die F&auml;den werden am 5. Tag nach der Operation entfernt. Der Heilungsprozess dauert im Durchschnitt etwa 7-10 Tage.</p>\r\n', '', NULL, NULL, NULL, '5701f0783652fb297da620220321eyalcin4acfef181ea95c30abba', '1', '2022-03-21 11:11:37', NULL, NULL, NULL, '1'),
('28', '5', '2022-03-22', NULL, 'Fotogaleri', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', NULL, NULL, NULL, 'c031377fada7c5a64f1d20220322eyalcin432133f2853a4a79a7f9', '1', '2022-03-22 15:48:31', NULL, NULL, NULL, '1'),
('29', '43', '2022-04-07', NULL, 'Rinoplasti', '<p>Rinoplasti burundaki şekil bozukluklarını &ccedil;&ouml;zmeyi ve bu sorunlarla birlikte ortaya &ccedil;ıkan psikolojik etkileri de d&uuml;zeltmeyi ama&ccedil;layan bir operasyondur. Bu operasyonda y&uuml;z, bir b&uuml;t&uuml;n olarak değerlendirilir ve y&uuml;z&uuml;n genel yapısına ve ifadesine g&ouml;re en uygun m&uuml;dahale ger&ccedil;ekleştirilir. &nbsp;</p>\r\n\r\n<p>Hastanın t&uuml;m sağlık ge&ccedil;mişi de burun problemleriyle birlikte operasyon &ouml;ncesinde b&uuml;t&uuml;n olarak g&ouml;z &ouml;n&uuml;nde bulundurulur. Burunda başkaca i&ccedil; bozukluğun olup olmadığı; hastanın alerjik durumları, daha &ouml;nce ge&ccedil;irdiği ameliyatlar veya y&uuml;z travmaları ayrıntılı bir bi&ccedil;imde değerlendirilir. T&uuml;m bu veriler ışığında hasta i&ccedil;in en uygun olan y&ouml;ntem se&ccedil;ilir ve uygulanır. Operasyon a&ccedil;ık ya da kapalı teknikle yapılabilir. Eğri olan ve nefes almada soruna neden olan kemik ve kıkırdaklar &ccedil;ıkarılır, şekil verilerek tekrar burun i&ccedil;erisine yerleştirilir. Operasyonda burun i&ccedil;erisindeki kıkırdak, kemik, bu yapıları bir arada tutan bağlar ve doku m&uuml;mk&uuml;n olduğunca korunmaya &ccedil;alışılır. Ayrıca nefes almada tıkanıklığa neden olan burun eti b&uuml;y&uuml;mesi ya da kist varsa bu patolojilere de aynı anda m&uuml;dahale edilir. &Ouml;zet olarak rinoplasti hassas bir cerrahi birikim gerektiren ve titizlikle yapılması gereken bir ameliyattır.</p>\r\n\r\n<p>Operasyon burnu yeniden şekillendirmek ve y&uuml;zle uyumlu estetik bir g&ouml;r&uuml;n&uuml;m sağlamak amacıyla uygulanır. Bu operasyonla burun k&uuml;&ccedil;&uuml;lt&uuml;lebilir; burnun &uuml;st dudak ile olan a&ccedil;ısı değiştirilebilir, burun ucu onarılıp burundaki girinti, &ccedil;ıkıntı gibi diğer kusurlar d&uuml;zeltilebilir, burnunuza şeklini veren kemikler ve kıkırdak &uuml;zerinde d&uuml;zeltme yapılarak septum yapısı d&uuml;zleştirilir. Septum, burun deliklerinizi ayıran kıkırdak ve kemikten oluşan yapıdır.&nbsp;</p>\r\n\r\n<p>Operasyon yaklaşık 2-3 saat s&uuml;rmektedir. Hastalar ameliyattan sonra 1 gece hastanede misafir edilir. Bu s&uuml;re&ccedil;te iyileşmeyi hızlandırıcı tedaviler ve soğuk uygulamaları yapılır. Kıkırdak ve kemikler gibi hassas b&ouml;lgeleri korumak adına al&ccedil;ı veya plastik bir atel ve ortası delik olan bir silikon tampon konulur. Silikon tamponlar 2 g&uuml;n sonra, burun ucu dikişleri ise 7 g&uuml;n sonra alınır ve hasta g&uuml;nl&uuml;k yaşamına d&ouml;ner.&nbsp;</p>\r\n', '', 'Rhinoplasty', '<p>Rhinoplasty is an operation that aims to solve the deformities of the nose and to correct the psychological effects that occur with these problems. In this operation, the face is evaluated as a whole and the most appropriate intervention is performed according to the general structure and expression of the face.</p>\r\n\r\n<p>The patient&#39;s entire health history, along with nasal problems, is considered as a whole before the operation. Whether there is any other internal disorder in the nose; The patient&#39;s allergic conditions, previous surgeries or facial trauma are evaluated in detail. In the light of all these data, the most appropriate method for the patient is selected and applied. The operation can be performed with open or closed technique. Bone and cartilages that are curved and cause breathing problems are removed, shaped and placed back into the nose. In the operation, the cartilage, bone, ligaments and tissue that hold these structures together in the nose are tried to be preserved as much as possible. In addition, if there is an enlarged nasal cavity or cyst that causes obstruction in breathing, these pathologies are also intervened at the same time. In summary, rhinoplasty is an operation that requires a delicate surgical experience and must be performed meticulously.</p>\r\n\r\n<p>The operation is applied to reshape the nose and provide an aesthetic appearance compatible with the face. With this operation, the nose can be reduced; The angle of the nose with the upper lip can be changed, the tip of the nose is repaired and other defects such as indentation and protrusion in the nose can be corrected, the septum structure is straightened by correcting the bones and cartilage that shape your nose. The septum is the cartilage and bone structure that separates your nostrils.</p>\r\n\r\n<p>The operation takes about 2-3 hours. Patients are hosted in the hospital for 1 night after the operation. In this process, treatments that accelerate healing and cold applications are made. A plaster or plastic splint and a silicone pad with a hole in the middle are placed to protect sensitive areas such as cartilage and bones. Silicone pads are removed after 2 days and nasal tip sutures are removed after 7 days and the patient returns to his daily life.</p>\r\n', '', '', '', '', 'تجميل الأنف', '<p dir=\"rtl\"><strong>تجميل الأنف</strong></p>\r\n\r\n<p dir=\"rtl\">عملية تجميل الأنف هي عملية تهدف إلى حل تشوهات الأنف وتصحيح الآثار النفسية التي تحدث مع هذه المشاكل. في هذه العملية ، يتم تقييم الوجه ككل ويتم تنفيذ التدخل الأنسب وفقا للهيكل العام والتعبير عن الوجه. بالإضافة إلى مشاكل الأنف ، يتم أخذ التاريخ الطبي الكامل للمريض قبل العملية في الاعتبار ككل. ما إذا كانت هناك اضطرابات داخلية أخرى في الأنف ؛ يتم تقييم حالات الحساسية لدى المريض أو العمليات الجراحية السابقة أو صدمات الوجه بالتفصيل. في ضوء كل هذه البيانات ، يتم اختيار الطريقة الأكثر ملاءمة للمريض وتطبيقها. يمكن إجراء العملية بتقنية مفتوحة أو مغلقة. تتم إزالة العظام والغضاريف المنحنية والتي تسبب مشاكل في التنفس وتشكيلها ووضعها مرة أخرى في الأنف. في العملية ، تتم محاولة حماية الغضروف والعظام والروابط والأنسجة في الأنف التي تربط هذه الهياكل معا قدر الإمكان. بالإضافة إلى ذلك ، إذا كان هناك تضخم في لحم الأنف أو كيس يسبب احتقان في التنفس ، فإن هذه المشاكل تتدخل أيضا. باختصار ، عملية تجميل الأنف هي عملية تتطلب تراكما جراحيا دقيقا ويجب إجراؤها بدقة. يتم إجراء العملية من أجل إعادة تشكيل الأنف وتوفير مظهر جمالي متوافق مع الوجه. مع هذه العملية ، يمكن تقليل الأنف ؛ يمكن تغيير زاوية الأنف مع الشفة العليا ، ويمكن إصلاح طرف الأنف ويمكن تصحيح العيوب الأخرى مثل المسافة البادئة ، والبروز في الأنف ، ويتم تسطيح بنية الحاجز عن طريق تصحيح العظام والغضاريف التي تعطي الأنف شكله. الحاجز هو الهيكل الذي يتكون من الغضروف والعظام التي تفصل مناخير.</p>\r\n\r\n<p dir=\"rtl\">تستغرق العملية حوالي ٢ - ٣ ساعات. يتم استضافة المرضى في المستشفى لمدة ليلة واحدة بعد العملية. في هذه العملية ، العلاجات والتطبيقة الباردة لتسريع الشفاء. من أجل حماية المناطق الحساسة مثل الغضروف والعظام ، يتم وضع جبيرة من الجص أو البلاستيك وحشا من السيليكون مع وجود ثقب في المنتصف. تتم إزالة حفائظ السيليكون بعد يومين ، ويتم إزالة خيوط طرف الأنف بعد سبعة أيام ، ويعود المريض إلى حياته اليومية.&nbsp;</p>\r\n', '', '', '', '', 'Rhinoplastik', '<p>Rhinoplastik ist eine Operation, die darauf abzielt, Deformit&auml;ten in der Nase zu l&ouml;sen und die psychologischen Auswirkungen, die mit diesen Problemen auftreten, zu korrigieren. Bei dieser Operation wird das Gesicht als Ganzes bewertet und entsprechend dem Gesichtsausdruck wird die am besten geeignete Intervention durchgef&uuml;hrt.<br />\r\n<br />\r\nDie gesamte Krankengeschichte des Patienten wird auch vor der Operation zusammen mit Nasenproblemen ber&uuml;cksichtigt. Ob es eine andere innere St&ouml;rung in der Nase gibt, der allergische Zustand des Patienten, fr&uuml;here Operationen oder Gesichtsverletzungen werden detailliert bewertet. Angesichts all dieser Daten wird die f&uuml;r den Patienten am besten geeignete Methode ausgew&auml;hlt und angewendet. Die Operation kann mit offener oder geschlossener Technik durchgef&uuml;hrt werden. Knochen und Knorpel, die gekr&uuml;mmt sind und Probleme beim Atmen verursachen, werden entfernt, geformt und wieder in die Nase eingef&uuml;hrt. Bei der Operation werden Knorpel, Knochen in der Nase, B&auml;nder und Gewebe, die diese Strukturen zusammenhalten, so weit wie m&ouml;glich gesch&uuml;tzt. Wenn es auch ein Wachstum des Nasenfleisches oder einer Zyste gibt, die eine Verstopfung der Atmung verursacht, werden diese Pathologien auch gleichzeitig interveniert. Zusammenfassend ist die Rhinoplastik eine Operation, die eine pr&auml;zise chirurgische Akkumulation erfordert und sorgf&auml;ltig durchgef&uuml;hrt werden muss.<br />\r\n<br />\r\nDie Operation wird durchgef&uuml;hrt, um die Nase neu zu gestalten und ein &auml;sthetisches Aussehen zu gew&auml;hrleisten, das mit dem Gesicht harmonisch ist. Mit dieser Operation kann die Nase verkleinert, der Winkel der Nase zur Oberlippe ver&auml;ndert, die Nasenspitze repariert und andere Defekte wie Einbuchtungen und Vorspr&uuml;nge in der Nase korrigiert werden. Die Septumstruktur wird begradigt, indem die Knochen und Knorpel korrigiert werden, die Ihre Nase formen. Das Septum ist die Struktur aus Knorpel und Knochen, die Ihre Nasenl&ouml;cher trennen.<br />\r\n<br />\r\nDie Operation dauert ca. 2-3 Stunden. Patienten werden 1 Nacht nach der Operation im Krankenhaus untergebracht. In diesem Prozess werden Behandlungen und kalte Anwendungen durchgef&uuml;hrt, die die Heilung beschleunigen. Um empfindliche Bereiche wie Knorpel und Knochen zu sch&uuml;tzen, wird eine Gipsschiene oder eine plastikschiene und ein Silikonpuffer mit einem Loch in der Mitte eingesetzt. Silikonpuffer werden nach 2 Tagen, Nasen-Stiche nach 7 Tagen entfernt und der Patient kehrt in seinen Alltag zur&uuml;ck.</p>\r\n', '', NULL, NULL, NULL, '8a689bf177518d84bd3b20220407eyalcind4bf7a8abe98873054d2', '7', '2022-04-07 15:14:29', NULL, NULL, NULL, '1'),
('30', '43', '2022-04-07', NULL, 'Septorinoplasti', '<p>Burun ortasında burun hava yolunu ikiye b&ouml;len, kemik ve kıkırdaktan oluşan yapıya septum denir. Septumda doğumsal ya da edinilmiş olarak eğiklikler oluşabilir. Doğumsal olan eğikliklerin en sık sebebi zor doğum ve doğum travmasıdır. Edinilmiş olan burun septum eğiklikleri ise burun gelişimi devam ederken oluşan y&uuml;z travmalarıdır. Burun ortasında bulunan septumun eğik olması durumuna nazal septum deviasyonu denilmektedir ve bu durumun cerrahi olarak d&uuml;zeltilmesi işlemine septoplasti adı verilir. Septorinoplasti işlemi ise burundaki şekil bozuklukları ile nefes alma problemlerini &ccedil;&ouml;zmeyi ve bu sorunlarla birlikte ortaya &ccedil;ıkan psikolojik etkileri de d&uuml;zeltmeyi ama&ccedil;layan bir operasyondur. Septoplasti ameliyatında hem nefes almayı engelleyen kemik eğikliğine m&uuml;dahale edilir (septoplasti) hem de y&uuml;z&uuml;n genel yapısına ve ifadesine g&ouml;re en uygun estetik m&uuml;dahale (rinoplasti) ger&ccedil;ekleştirilir.&nbsp;<br />\r\n<br />\r\nHastanın t&uuml;m sağlık ge&ccedil;mişi de burun problemleriyle birlikte operasyon &ouml;ncesinde b&uuml;t&uuml;n olarak g&ouml;z &ouml;n&uuml;nde bulundurulur. Burunda başka i&ccedil; bozukluğun olup olmadığı; hastanın alerjik durumları, daha &ouml;nce ge&ccedil;irdiği ameliyatlar veya y&uuml;z travmaları ayrıntılı bir bi&ccedil;imde değerlendirilir. T&uuml;m bu veriler ışığında hasta i&ccedil;in en uygun olan y&ouml;ntem se&ccedil;ilir ve uygulanır. Operasyon a&ccedil;ık ya da kapalı teknikle yapılabilir. Eğri olan ve nefes almada soruna neden olan kemik ve kıkırdaklar &ccedil;ıkarılır, şekil verilerek tekrar burun i&ccedil;erisine yerleştirilir. Operasyonda burun i&ccedil;erisinde kıkırdak, kemik, bu yapıları bir arada tutan bağlar ve doku m&uuml;mk&uuml;n olduğunca korunmaya &ccedil;alışılır. Kemik ve kıkırdağın korunmayıp t&uuml;m&uuml;n&uuml;n alınması gibi bir durumda burun sırtında &ccedil;&ouml;kmeler oluştuğu semer burun deformitesi meydana gelir ve bu durumda ameliyat sonrası şekil bozukluğu ve nefes alma problemlerinin devam etmesine neden olur. &Ouml;zet olarak Septorinoplasti hassas bir cerrahi birikim gerektiren ve titizlikle yapılması gereken bir ameliyattır.</p>\r\n\r\n<p><br />\r\nOperasyon burnu yeniden şekillendirmek, y&uuml;zle uyumlu estetik bir g&ouml;r&uuml;n&uuml;m sağlamak ve bunlarla birlikte burnun fonksiyonel sorunlarını da ortadan kaldırmak&nbsp; amacıyla uygulanır. Hastalarımla g&ouml;r&uuml;şmelerimde her zaman belirttiğim &uuml;zere estetik olarak g&uuml;zel ancak nefes alamadığınız bir burun, şık ama ayağınızı sıkan bir ayakkabıya benzer. Kullanamadığınız nefes alamadığınız bir burun ile yaşamak ise &ccedil;ok eziyetlidir ve eninde sonunda revizyona gider. Bu operasyonla burun k&uuml;&ccedil;&uuml;lt&uuml;lebilir; burnun &uuml;st dudak ile olan a&ccedil;ısı değiştirilebilir, burun ucu onarılıp burundaki girinti, &ccedil;ıkıntı gibi diğer kusurlar d&uuml;zeltilebilir, burnunuza şeklini veren kemikler ve kıkırdak &uuml;zerinde d&uuml;zeltme yapılarak septum yapısı d&uuml;zleştirilir. Ayrıca nefes alma zorluğuna sebep olan problemler tespit edilir. Bu problemlerin başında kemik eğikliği olan tarafın tersinde olan burun eti b&uuml;y&uuml;mesidir. Burun eti b&uuml;y&uuml;mesi de eğer m&uuml;dahale edilmezse burun tıkanıklığının devam etmesine neden olur ve mutlaka m&uuml;dahale edilmeyi gerektirir. Ben septoplasti ya da septorinoplasti ameliyatı olacak olan hastalarımın hepsinin burun i&ccedil;i endoskopik değerlendirmelerini yapıyorum, gerekirse bilgisayarlı tomografi ile ileri g&ouml;r&uuml;nt&uuml;leme y&ouml;ntemlerine başvuruyorum ve mutlaka operasyon sırasında burun etine de işlem ger&ccedil;ekleştiriyorum. &nbsp;</p>\r\n\r\n<p>Operasyon yaklaşık 2-3 saat s&uuml;rmektedir. Hastalar ameliyattan sonra 1 gece hastanede misafir edilir. Bu s&uuml;re&ccedil;te iyileşmeyi hızlandırıcı tedaviler ve soğuk uygulamaları yapılır. Kıkırdak ve kemikler gibi hassas b&ouml;lgeleri korumak adına al&ccedil;ı ve ortası delik olan bir silikon tampon konulur. Silikon tamponlar 2 g&uuml;n sonra, burun ucu dikişleri 7 g&uuml;n sonra alınır ve hasta g&uuml;nl&uuml;k yaşamına d&ouml;ner.&nbsp;</p>\r\n', '', 'Septorhinoplasty', '<p>The structure that divides the nasal airway into two in the middle of the nose and consists of bone and cartilage is called the septum. Congenital or acquired curvature of the septum may occur. The most common cause of congenital curvatures is difficult birth and birth trauma. Acquired nasal septum curvatures are facial traumas that occur while the development of the nose continues. If the septum in the middle of the nose is curved, it is called nasal septum deviation, and the surgical correction of this condition is called septoplasty. Septorhinoplasty is an operation that aims to solve nasal deformities and breathing problems and to correct the psychological effects that occur with these problems. In septoplasty surgery, both the bone curvature that prevents breathing is intervened (septoplasty) and the most appropriate aesthetic intervention (rhinoplasty) is performed according to the general structure and expression of the face.</p>\r\n\r\n<p>The patient&#39;s entire health history, along with nasal problems, is considered as a whole before the operation. Whether there are other internal disorders in the nose; The patient&#39;s allergic conditions, previous surgeries or facial trauma are evaluated in detail. In the light of all these data, the most appropriate method for the patient is selected and applied. The operation can be performed with open or closed technique. Bone and cartilages that are curved and cause breathing problems are removed, shaped and placed back into the nose. In the operation, cartilage, bone, ligaments and tissue that hold these structures together are tried to be preserved as much as possible. In a situation where bone and cartilage are not preserved and all of them are removed, saddle nose deformity occurs in which collapses on the nasal dorsum occur, and in this case, deformity and breathing problems continue after the surgery. In summary, Septorhinoplasty is an operation that requires sensitive surgical accumulation and must be performed meticulously.</p>\r\n\r\n<p><br />\r\nThe operation is performed to reshape the nose, to provide an aesthetic appearance compatible with the face and to eliminate the functional problems of the nose. As I always say in my interviews with my patients, a nose that is aesthetically beautiful but you can&#39;t breathe is like a stylish but tight-fitting shoe. Living with a nose that you cannot use and cannot breathe is very tormenting and eventually goes to revision. With this operation, the nose can be reduced; The angle of the nose with the upper lip can be changed, the tip of the nose is repaired and other defects such as indentation and protrusion in the nose can be corrected, the septum structure is straightened by correcting the bones and cartilage that shape your nose. In addition, problems that cause breathing difficulties are detected. At the beginning of these problems is the growth of the nasal flesh on the opposite side of the bone inclination. The enlargement of the nasal flesh also causes the continuation of nasal congestion if it is not intervened and it definitely requires intervention. I make intranasal endoscopic evaluations of all of my patients who will have septoplasty or septorhinoplasty surgery, if necessary, I apply advanced imaging methods with computed tomography, and I definitely perform operations on the concha during the operation.</p>\r\n\r\n<p>The operation takes about 2-3 hours. Patients are hosted in the hospital for 1 night after the operation. In this process, treatments that accelerate healing and cold applications are made. In order to protect sensitive areas such as cartilage and bones, a plaster and a silicone pad with a hole in the middle are placed. Silicone pads are removed after 2 days, nasal tip sutures are removed after 7 days and the patient returns to his daily life.</p>\r\n', '', '', '', '', 'رأب الحاجز الأنفي', '<p dir=\"rtl\">يسمى الهيكل المكون من العظام والغضاريف الذي يقسم مجرى الهواء الأنفي إلى نصفين في منتصف الأنف الحاجز. قد تحدث انحرافات خلقية أو مكتسبة في الحاجز. السبب الأكثر شيوعا من أبليقوس الخلقية هو العمل الصعب وصدمة الولادة. السبب الأكثر شيوعًا للانحراف الخلقي هو صعوبة الولادة وصدمة الولادة. تقوسات الحاجز الأنفي المكتسبة هي صدمات في الوجه تحدث أثناء استمرار تطور الأنف. تسمى الحالة التي يميل فيها الحاجز الموجود في منتصف الأنف بانحراف الحاجز الأنفي ، وتسمى عملية التصحيح الجراحي لهذه الحالة رأب الحاجز الأنفي. رأب الحاجز الأنفي هو عملية تهدف إلى حل مشاكل التنفس مع تشوهات في الأنف وتصحيح الآثار النفسية التي تحدث مع هذه المشاكل. في جراحة رأب الحاجز الأنفي ، يتم التدخل في كل من انحراف العظام الذي يمنع التنفس (رأب الحاجز الأنفي) ويتم إجراء التدخل الجمالي الأنسب (تجميل الأنف) وفقا للهيكل العام والتعبير عن الوجه.</p>\r\n\r\n<p dir=\"rtl\">&nbsp;بالإضافة إلى مشاكل الأنف ، يتم أخذ التاريخ الطبي الكامل للمريض قبل العملية في الاعتبار ككل. ما إذا كانت هناك اضطرابات داخلية أخرى في الأنف ؛ يتم تقييم حالات الحساسية لدى المريض أو العمليات الجراحية السابقة أو صدمات الوجه بالتفصيل. في ضوء كل هذه البيانات ، يتم اختيار الطريقة الأكثر ملاءمة للمريض وتطبيقها. يمكن إجراء العملية بتقنية مفتوحة أو مغلقة. تتم إزالة العظام والغضاريف المنحنية والتي تسبب مشاكل في التنفس وتشكيلها ووضعها مرة أخرى في الأنف. في العملية ، تتم محاولة حماية الغضروف والعظام والروابط والأنسجة في الأنف التي تربط هذه الهياكل معا قدر الإمكان. في حالة عدم حماية العظام والغضاريف وإزالتها كلها ، يحدث تشوه الأنف ، حيث تحدث الانهيارات في الجزء الخلفي من الأنف ، وفي هذه الحالة يسبب التشوه ومشاكل في التنفس تستمر بعد الجراحة. باختصار ، عملية رأب الحاجز الأنفي هي عملية تتطلب تراكما جراحيا دقيقا ويجب إجراؤها بدقة.</p>\r\n\r\n<p dir=\"rtl\">يتم تنفيذ العملية من أجل إعادة تشكيل الأنف ، وتوفير مظهر جمالي في وئام مع الوجه ، وأيضا القضاء على المشاكل الوظيفية للأنف. كما ذكرت دائما في مقابلاتي مع مرضاي ، فإن الأنف الجميل من الناحية الجمالية الذي لا يمكنك التنفس فيه يشبه الحذاء الأنيق الذي يضغط على قدمك. العيش مع أنف لا تستطيع التنفس واستخدامه مؤلم للغاية ويتم مراجعته في النهاية. مع هذه العملية ، يمكن تقليل الأنف ؛ يمكن تغيير زاوية الأنف مع الشفة العليا ، ويمكن إصلاح طرف الأنف ويمكن تصحيح العيوب الأخرى مثل المسافة البادئة ، والبروز في الأنف ، ويتم تسطيح بنية الحاجز عن طريق تصحيح العظام والغضاريف التي تعطي الأنف شكله. بالإضافة إلى ذلك ، يتم الكشف عن المشاكل التي تسبب صعوبة في التنفس. في بداية هذه المشاكل هو نمو اللحم الأنفي ، الذي هو عكس الجانب مع ميل العظام. يؤدي نمو اللحم الأنف أيضا إلى استمرار احتقان الأنف إذا لم يتم التدخل فيه ويتطلب بالضرورة التدخل. أقوم بإجراء تقييمات بالمنظار لجميع مرضاي الذين سيخضعون لجراحة رأب الحاجز الأنفي ، إذا لزم الأمر ، ألجأ إلى طرق التصوير المتقدمة باستخدام التصوير المقطعي المحوسب ، كما أقوم بإجراء عمليات على لحم الأنف أثناء العملية.&nbsp;</p>\r\n\r\n<p dir=\"rtl\">تستغرق العملية حوالي ٢ - ٣ ساعات. يتم استضافة المرضى في المستشفى لمدة ليلة واحدة بعد العملية. في هذه العملية ، العلاجات والتطبيقة الباردة لتسريع الشفاء. من أجل حماية المناطق الحساسة مثل الغضروف والعظام ،&nbsp; يتم وضع جبيرة و وحشا من السيليكون مع وجود ثقب في المنتصف. تتم إزالة حفائظ السيليكون بعد يومين ، ويتم إزالة خيوط طرف الأنف بعد سبعة أيام ، ويعود المريض إلى حياته اليومية.</p>\r\n', '', '', '', '', 'Septorinoplastik', '<p>Die aus Knochen und Knorpel bestehende Struktur, die die Nasenatmung in der Mitte der Nase halbiert, wird Septum genannt. Im Septum k&ouml;nnen angeborene oder erworbene Neigungen auftreten. Die h&auml;ufigste Ursache f&uuml;r Neigungen ist eine schwierige Geburt und Geburtstrauma. Erworbene Nasenscheidewandverkr&uuml;mmungen sind Gesichtstraumen, die w&auml;hrend der Entwicklung der Nase auftreten. Der Zustand, in dem sich das Septum in der Mitte der Nase befindet, wird als nasale Septumabweichung bezeichnet und der Prozess der chirurgischen Korrektur dieses Zustandes wird Septoplastik genannt. Septorinoplastik ist eine Operation, die darauf abzielt, Entstellungen in der Nase und Atemprobleme zu l&ouml;sen und die psychologischen Auswirkungen, die mit diesen Problemen auftreten, zu korrigieren. Bei der Septoplastik wird sowohl die Beugung des Knochens, die das Atmen verhindert, eingreift (Septoplastik) als auch die am besten geeignete &auml;sthetische Intervention (Rhinoplastik) entsprechend der allgemeinen Struktur und dem Ausdruck des Gesichts durchgef&uuml;hrt.<br />\r\n<br />\r\nDie gesamte Krankengeschichte des Patienten wird auch vor der Operation zusammen mit Nasenproblemen ber&uuml;cksichtigt. Ob es andere innere St&ouml;rungen in der Nase gibt; der allergische Zustand des Patienten, fr&uuml;here Operationen oder Gesichtsverletzungen werden detailliert bewertet. Angesichts all dieser Daten wird die f&uuml;r den Patienten am besten geeignete Methode ausgew&auml;hlt und angewendet. Die Operation kann mit offener oder geschlossener Technik durchgef&uuml;hrt werden. Knochen und Knorpel, die gekr&uuml;mmt sind und Probleme beim Atmen verursachen, werden entfernt, geformt und wieder in die Nase eingef&uuml;hrt. Bei der Operation werden Knorpel, Knochen, B&auml;nder und Gewebe in der Nase, die diese Strukturen zusammenhalten, so weit wie m&ouml;glich gesch&uuml;tzt.<br />\r\n<br />\r\nIn einer Situation, in der Knochen und Knorpel nicht erhalten bleiben und alle entfernt werden, tritt eine Sattelnasendeformit&auml;t auf, bei der es zu Einbr&uuml;chen auf dem Nasenr&uuml;cken kommt, und in diesem Fall f&uuml;hrt dies zu anhaltenden postoperativen Deformit&auml;ten und Atemproblemen. Zusammenfassend ist die Septorinoplastik eine Operation, die eine pr&auml;zise chirurgische Akkumulation erfordert und sorgf&auml;ltig durchgef&uuml;hrt werden muss.<br />\r\n<br />\r\nDie Operation wird durchgef&uuml;hrt, um die Nase neu zu gestalten, um ein &auml;sthetisches Aussehen zu gew&auml;hrleisten, das mit dem Gesicht kompatibel ist, und um funktionelle Probleme der Nase zu beseitigen. Wie ich in Gespr&auml;chen mit meinen Patienten immer erw&auml;hnt habe, ist eine &auml;sthetisch sch&ouml;ne, aber nicht atmende Nase wie ein stilvoller, aber enger Schuh. Das Leben mit einer Nase, die Sie nicht benutzen und nicht atmen k&ouml;nnen, ist sehr qu&auml;lend und f&uuml;hrt schlie&szlig;lich zur Revision. Mit dieser Operation kann die Nase verkleinert, der Winkel der Nase zur Oberlippe ver&auml;ndert, die Nasenspitze repariert und andere Defekte wie Einbuchtungen und Vorspr&uuml;nge in der Nase korrigiert werden. Die Septumstruktur wird begradigt, indem die Knochen und Knorpel korrigiert werden, die Ihre Nase formen. Es werden auch Probleme identifiziert, die Atembeschwerden verursachen. Die Hauptursache f&uuml;r diese Probleme ist das Wachstum des Nasenfleisches, das der Seite mit der Knochenkr&uuml;mmung gegen&uuml;berliegt. Das Wachstum des Nasenfleisches f&uuml;hrt auch dazu, dass die verstopfte Nase anh&auml;lt, wenn sie nicht interveniert wird und unbedingt interveniert werden muss. Ich f&uuml;hre intranasale endoskopische Untersuchungen aller meiner Patienten durch, bei denen eine Septumplastik oder Septorhinoplastik durchgef&uuml;hrt wird. Bei Bedarf greife ich auf fortgeschrittene bildgebende Verfahren mit Computertomographie zur&uuml;ck und f&uuml;hre auf jeden Fall Operationen am Nasenfleisch w&auml;hrend der Operation durch.<br />\r\n<br />\r\nDie Operation dauert ca. 2-3 Stunden. Patienten werden 1 Nacht nach der Operation im Krankenhaus untergebracht. In diesem Prozess werden Behandlungen und kalte Anwendungen durchgef&uuml;hrt, die die Heilung beschleunigen. Um empfindliche Bereiche wie Knorpel und Knochen zu sch&uuml;tzen, werden Gips und ein silikonpuffer mit einem Loch in der Mitte eingesetzt. Silikonpuffer werden nach 2 Tagen entfernt, Nasen-Stiche nach 7 Tagen und der Patient kehrt in seinen Alltag zur&uuml;ck.</p>\r\n', '', NULL, NULL, NULL, '85fbd03181fe67976adb20220407eyalcin6971eda452f3ae441333', '7', '2022-04-07 15:15:33', NULL, NULL, NULL, '1'),
('31', '43', '2022-04-07', NULL, 'Sinüzit Ameliyatı', '<p>Sin&uuml;zit, tedavi edilebilen ve &uuml;lkemizde olduk&ccedil;a sık g&ouml;r&uuml;len bir rahatsızlıktır. Sin&uuml;sleri &ccedil;ok sık iltihaplanan, ila&ccedil;la tedaviye cevap vermeyen ve hastalığı kronikleşen hastaların Sin&uuml;zit Ameliyatı ile tedavi edilmeleri gerekmektedir.</p>\r\n\r\n<p>Operasyon ile sin&uuml;s boşlukları ve kanalları temizlenerek yeniden d&uuml;zenli bir şekilde fonksiyonunu yerine getirmesi sağlanır. Bu işlem sonrasında sin&uuml;slerinize daha rahat hava girmesi ve sin&uuml;slerin buruna drenajı g&uuml;&ccedil;l&uuml;kleri giderilir. Sin&uuml;s boşlukları ve kanallarına yapılan m&uuml;dahaleler, endoskopik g&ouml;r&uuml;ş altında yapılması gereken &ccedil;ok hassas m&uuml;dahalelerdir.&nbsp;</p>\r\n\r\n<p>Operasyon yaklaşık 1 - 1,5 saat s&uuml;rer ve genel anestezi altında yapılır. Hastamız operasyon sonrası 1 gece hastanede misafir edilir ve 1 hafta sonra normal yaşantısına d&ouml;nebilir.</p>\r\n', '', 'Sinusitis Surgery', '<p>Sinusitis is a treatable and very common disease in our country. Patients whose sinuses are frequently inflamed, do not respond to medication, and whose disease becomes chronic should be treated with Sinusitis Surgery.</p>\r\n\r\n<p>With the operation, sinus cavities and channels are cleaned and it is ensured that it functions regularly again. After this procedure, the difficulties of getting air into your sinuses more easily and drainage of the sinuses into the nose are eliminated. Interventions in the sinus cavities and channels are very sensitive interventions that should be performed under endoscopic vision.</p>\r\n\r\n<p>The operation takes approximately 1 - 1.5 hours and is performed under general anesthesia. Our patient is hosted in the hospital for 1 night after the operation and can return to his normal life after 1 week.</p>\r\n', '', '', '', '', 'جراحة الجيوب الأنفية بالمنظار', '<p dir=\"rtl\">التهاب الجيوب الأنفية هو مرض يمكن علاجه وهو شائع جدا في بلدنا. المرضى الذين تلتهب الجيوب الأنفية في كثير من الأحيان ، لا يستجيبون للأدوية ، والذين أصبح مرضهم مزمنا ، يجب علاجهم بجراحة الجيوب الأنفية بالمنظار. جراحة الجيوب الأنفية بالمنظار هي طريقة جراحية أصبحت منتشرة في جميع أنحاء العالم مع تطوير المناظير الداخلية التي توفر صورا عالية الجودة.&nbsp;</p>\r\n\r\n<p dir=\"rtl\">تستخدم هذه الطريقة أيضا لعلاج الاضطرابات مثل انسداد القناة الدمعية ، ووقف نزيف الأنف ، وقرص العصب البصري.&nbsp;</p>\r\n\r\n<p dir=\"rtl\">مع العملية ، يتم تنظيف تجاويف الجيوب الأنفية والقنوات والتأكد من أنها تؤدي وظيفتها بطريقة منتظمة مرة أخرى. بعد هذا الإجراء ، يتم التخلص من وصول الهواء الأكثر راحة إلى الجيوب الأنفية وصعوبات تصريف الجيوب الأنفية إلى الأنف. التدخلات على تجاويف الجيوب الأنفية والقنوات هي تدخلات حساسة للغاية يجب إجراؤها تحت الرؤية بالمنظار.&nbsp;</p>\r\n\r\n<p dir=\"rtl\">تستغرق العملية حوالي ساعة أو ساعة ونصف ويتم إجراؤها تحت التخدير العام. قد يكون لديك احتقان أنفي في غضون ۲٤ أو ٤٨ ساعة بعد العملية وقد تحتاج إلى التنفس من خلال الفم. يتم استضافة مريضنا إلى المستشفى لمدة ليلة واحدة بعد العملية ويمكنه العودة إلى حياته الطبيعية بعد أسبوع.</p>\r\n', '', '', '', '', 'Sinusitis Chirurgie', '<p>Sinusitis ist eine Krankheit, die behandelt werden kann und in unserem Land ziemlich h&auml;ufig ist. Patienten, deren Nebenh&ouml;hlen sich sehr oft entz&uuml;nden, nicht auf die medikament&ouml;se Behandlung ansprechen und deren Krankheit chronisch wird, sollten mit einer Sinusitis-Operation behandelt werden.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>Mit der Operation werden die sinush&ouml;hlen und-Kan&auml;le gereinigt und es wird sichergestellt, dass sie wieder regelm&auml;&szlig;ig funktionieren. Nach diesem Verfahren wird die Schwierigkeit, Luft in Ihre Nebenh&ouml;hlen zu gelangen und die Nebenh&ouml;hlen in die Nase abzulassen, beseitigt. Eingriffe in die Sinush&ouml;hlen und-Kan&auml;le sind sehr empfindliche Eingriffe, die unter endoskopischer Sicht durchgef&uuml;hrt werden m&uuml;ssen.</p>\r\n\r\n<p>Die Operation dauert etwa 1-1,5 Stunden und wird unter Vollnarkose durchgef&uuml;hrt. Unser Patient wird nach der Operation f&uuml;r 1 Nacht im Krankenhaus untergebracht und kann nach 1 Woche in sein normales Leben zur&uuml;ckkehren.</p>\r\n', '', NULL, NULL, NULL, '63c4d50b9d398a23781a20220407eyalcin8b536f5f948b016f429d', '7', '2022-04-07 15:17:22', NULL, NULL, NULL, '1'),
('32', '43', '2022-04-07', NULL, 'Dudak Estetiği (Liplift)', '<p>Dudak estetiği operasyonu, dudak boyutundan şikayet&ccedil;i olan hastalara uygulanan ve kalıcı sonu&ccedil;ları olan bir operasyondur. Yaşlanma ile kaş, g&ouml;z kapakları, yanaklar, boyun gibi &uuml;st dudakta da sarkma meydana gelir.&nbsp; Yaşlanma ile birlikte mukoza ve dudak &ouml;rt&uuml;s&uuml;nde deformasyonlar ve kırışıklıklar oluşabilir. Bu nedenle dudak estetiği ihtiyacı daha &ccedil;ok ileri yaşlarda g&ouml;r&uuml;l&uuml;r. Yaşla beraber dudak burun mesafesinde uzama ve &uuml;st dudak yan taraflarında i&ccedil;e d&ouml;nme gibi dudak yaşlanma belirtileri olmaktadır. Yaş etkisi ile sarkma dışında yapısal olarak da dudak estetiğine ihtiya&ccedil; duyulabilir. Maalesef hatalı dolgu uygulamaları da dudakta kalıcı hasarlara yol a&ccedil;abilmektedir.</p>\r\n\r\n<p>Dudak estetiğine ihtiya&ccedil; duyan hastalar genellikle bu ihtiyacın farkında olmadan dudak dolgusu işlemi ger&ccedil;ekleştirir ancak sonu&ccedil;tan memnun kalmazlar. &Ccedil;&uuml;nk&uuml; yanlış uygulanan dudak dolgusu ile dudaklar daha da uzayabilir ve y&uuml;zle uyumsuz, rahatsız edici bir g&ouml;r&uuml;n&uuml;m kazanır.</p>\r\n\r\n<p>Her ne kadar yaşlanmaya bağlı dudak kaldırma daha sıklıkla yapılsa da son zamanlarda dudak kaldırma isteği ile gelen gen&ccedil; hasta sayısı da artmaktadır. &Ouml;zellikle dudak burun mesafesi uzun ve ince dudak yapısına sahip gen&ccedil; hastalar, dolgu işlemleri ile kademeli dudak b&uuml;y&uuml;tme işlemi yerine kalıcı ve tek seferlik bir tedavi istemektedirler.&nbsp;</p>\r\n\r\n<p>Bu tarz problemlerin &ccedil;&ouml;z&uuml;m&uuml; ise dudak estetiği operasyonudur. Burada iki &ccedil;eşit cerrahi y&ouml;ntem mevcuttur. Birinde burun tabanından yapılan gizli kesiler ile kaldırılmak istenen dudak kısımları yukarı doğru &ccedil;ekilir. Bu işlem aynı zamanda dudak-burun mesafesini kısaltır.&nbsp; Diğer y&ouml;ntem ise dudağın i&ccedil; kısmına yapılan kesiler ile mukoza ve dudak &ouml;rt&uuml;s&uuml;nde d&uuml;zenlemeler yapılır ve dudağın i&ccedil; boyu kısaltılır. Dudağın ters y&ouml;ne doğru &ccedil;evrilmesinin sağlandığı bu işlemle kaslara da sıkılaştırma ama&ccedil;lı m&uuml;dahale yapılır ve dudak iyi bir g&ouml;r&uuml;n&uuml;me kavuşturulur.&nbsp;</p>\r\n\r\n<p>Ameliyat genel ya da lokal anestesi altında yapılabilir ve genellikle 1 saat s&uuml;rer. Ameliyat sonrası hasta doğrudan taburcu edilir. Ameliyattan sonra 10 ila 15 g&uuml;n boyunca travmalardan ka&ccedil;ınmak gerekmektedir.</p>\r\n', '', 'Lip Aesthetics (Liplift)', '<p>Lip aesthetic operation is an operation that is applied to patients who complain about lip size and has permanent results. With aging, sagging occurs in the upper lip such as eyebrows, eyelids, cheeks and neck. With aging, deformations and wrinkles may occur in the mucous membrane and lip cover. For this reason, the need for lip aesthetics is seen more in advanced ages. There are signs of lip aging, such as lengthening of the lip-nose distance and turning inward on the sides of the upper lip with age. In addition to sagging due to age, structural lip aesthetics may be needed. Unfortunately, incorrect filling applications can also cause permanent damage to the lips.</p>\r\n\r\n<p>Patients who need lip aesthetics usually perform lip augmentation without being aware of this need, but they are not satisfied with the result. Because with incorrectly applied lip fillers, the lips can get longer and gain an uncomfortable appearance that is incompatible with the face.</p>\r\n\r\n<p>Although lip lift due to aging is performed more frequently, the number of young patients who come with the request of lip lift has been increasing recently. Especially young patients with long lip-to-nose distance and thin lip structure want a permanent and one-time treatment instead of gradual lip augmentation with filling procedures.</p>\r\n\r\n<p>The solution to such problems is lip aesthetic operation. There are two types of surgical methods here. In one, the lip parts that are desired to be lifted are pulled upwards with hidden incisions made from the base of the nose. This process also shortens the lip-nose distance. The other method is the incisions made on the inner part of the lip, the mucous membrane and lip covering are adjusted and the inner length of the lip is shortened. With this process, in which the lip is turned in the opposite direction, the muscles are also intervened for tightening and the lip is given a good appearance.</p>\r\n\r\n<p>The surgery can be performed under general or local anesthesia and usually takes 1 hour. After the operation, the patient is discharged directly. It is necessary to avoid traumas for 10 to 15 days after the operation.</p>\r\n', '', '', '', '', 'تجميل الشفاه (ليبليفت)', '<p dir=\"rtl\">عملية تجميل الشفاه هي عملية يتم تطبيقها على المرضى الذين يشكون من حجم الشفاه ولها نتائج دائمة. مع الشيخوخة ، يحدث الترهل أيضا على الشفة العليا ، مثل الحاجبين والجفون والخدين والرقبة. مع الشيخوخة ، قد تحدث التشوهات والتجاعيد على الغشاء المخاطي وغطاء الشفاه. لذلك ، فإن الحاجة إلى جماليات الشفاه أكثر شيوعا في سن أكبر. مع التقدم في السن ، وهناك علامات الشيخوخة من الشفاه ، مثل إطالة المسافة بين الشفاه والأنف وتحول الداخل على جانبي الشفة العليا. بصرف النظر عن الترهل مع تأثير العمر ، قد تكون هناك حاجة أيضا إلى جماليات الشفاه من الناحية الهيكلية. لسوء الحظ ، يمكن أن تؤدي تطبيقات الملء غير الصحيحة أيضا إلى تلف دائم للشفة.&nbsp;</p>\r\n\r\n<p dir=\"rtl\">عادة ما يقوم المرضى الذين يحتاجون إلى تجميل الشفاه بإجراء عملية حشو الشفاه دون إدراك هذه الحاجة ، لكنهم غير راضين عن النتيجة. لأنه مع حشو الشفاه المطبق بشكل غير صحيح ، يمكن أن تصبح الشفاه أطول وتكتسب مظهرا متعارضا وغير مريح مع الوجه.</p>\r\n\r\n<p dir=\"rtl\">على الرغم من أن شد الشفاه بسبب الشيخوخة يتم في كثير من الأحيان ، إلا أن عدد المرضى الصغار الذين قدموا مؤخرا بطلب شد الشفاه يتزايد أيضا. على وجه الخصوص ، المرضى الصغار الذين لديهم بنية شفة طويلة ورقيقة مع مسافة طويلة من أنف الشفة يريدون علاجا دائما لمرة واحدة بدلا من تكبير الشفاه التدريجي بإجراءات حشو.&nbsp;</p>\r\n\r\n<p dir=\"rtl\">الحل لمثل هذه المشاكل هو عملية تجميل الشفاه. هناك نوعان من الطرق الجراحية المتاحة. في واحد منهم ، يتم سحب أجزاء الشفاه التي تريد إزالتها مع شقوق خفية مصنوعة من قاعدة الأنف. هذا الإجراء أيضا يقصر المسافة بين الشفاه والأنف. طريقة أخرى هي عمل شقوق في داخل الشفة وإجراء الترتيبات على الغشاء المخاطي وغطاء الشفاه ، ويتم تقصير الطول الداخلي للشفة. مع هذه العملية ، حيث يتم تشغيل الشفة في الاتجاه المعاكس ، يتم تدخل العضلات أيضا لأغراض تشديد ويتم استعادة الشفة إلى مظهر جيد.&nbsp;</p>\r\n\r\n<p dir=\"rtl\">يمكن إجراء العملية تحت التخدير العام أو الموضعي وعادة ما تستغرق ساعة. يخرج المريض مباشرة بعد العملية. من الضروري تجنب الصدمات لمدة ۱۰ إلى ۱٥ يوما بعد العملية.</p>\r\n', '', '', '', '', 'Lippenästhetik (Liplift)', '<p>Lippen&auml;sthetik ist eine dauerhafte Operation, die bei Patienten angewendet wird, die sich &uuml;ber die Lippengr&ouml;&szlig;e beschweren. Mit dem Altern treten Augenbrauen, Augenlider, Wangen, Oberlippe wie Hals Absacken auf. Mit dem Altern k&ouml;nnen Deformationen und Falten auf der Schleimhaut und der Lippe auftreten. Aus diesem Grund wird die Notwendigkeit einer Lippen&auml;sthetik im fortgeschrittenen Alter gesehen. Mit zunehmendem Alter treten Zeichen des Lippenalterns auf, wie z. B. die Verl&auml;ngerung der Lippen im Nasenbereich und die R&uuml;ckkehr nach innen auf den Seiten der Oberlippe.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>Neben dem Durchh&auml;ngen mit dem Lebenseffekt kann auch strukturell eine Lippen&auml;sthetik erforderlich sein. Leider k&ouml;nnen falsche F&uuml;llanwendungen zu bleibenden Sch&auml;den an der Lippe f&uuml;hren.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>Patienten, die eine Lippen&auml;sthetik ben&ouml;tigen, f&uuml;hren oft einen Lippenf&uuml;llvorgang durch, ohne sich dieser Notwendigkeit bewusst zu sein und sind mit diesem Ergebnis nicht zufrieden. Denn mit einer falsch aufgetragenen Lippenf&uuml;llung k&ouml;nnen sich die Lippen weiter ausdehnen und erhalten ein mit dem Gesicht unvereinbares und unangenehmes Aussehen.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>Obwohl Lippenhebung aufgrund des Alterns h&auml;ufiger durchgef&uuml;hrt wird, steigt in letzter Zeit auch die Anzahl junger Patienten, die mit dem Wunsch nach Lippenhebung kommen. Vor allem junge Patienten mit einer langen und d&uuml;nnen Lippenstruktur w&uuml;nschen sich eine dauerhafte und einmalige Behandlung statt einer stufenweisen Lippenvergr&ouml;&szlig;erung mit F&uuml;llverfahren.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>Die L&ouml;sung f&uuml;r solche Probleme ist eine lippen&auml;sthetische Operation. Es gibt zwei Arten von chirurgischen Methoden. Bei einem von ihnen werden die Lippen, die mit versteckten Einschnitten an der Basis der Nase angehoben werden sollen, nach oben gezogen. Dieser Prozess verk&uuml;rzt auch den Abstand zwischen Lippen und Nase. Bei der anderen Methode werden Schnitte an der Lippeninnenseite gesetzt, Schleimhaut und Lippenbedeckung angepasst und die Lippeninnenl&auml;nge gek&uuml;rzt. Bei diesem Vorgang, bei dem die Lippe in die entgegengesetzte Richtung gedreht wird, wird auch die Muskulatur zur Straffung eingegriffen und der Lippe ein gutes Aussehen verliehen.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>Die Operation kann unter Vollnarkose oder &ouml;rtlicher Bet&auml;ubung durchgef&uuml;hrt werden und dauert in der Regel 1 Stunde. Nach der Operation wird der Patient direkt entlassen. Es ist notwendig, Traumata f&uuml;r 10 bis 15 Tage nach der Operation zu vermeiden.</p>\r\n', '', NULL, NULL, NULL, '33cd0e12038c7119ed5220220407eyalcin80e2536ed87ec8789c7f', '7', '2022-04-07 15:18:36', NULL, NULL, NULL, '1'),
('33', '43', '2022-04-07', NULL, 'Yüz Germe (Facelift)', '<p>Yaşlanma ile birlikte y&uuml;z&uuml; kaplayan derinin yapısını oluşturan taşıyıcı proteinlerde azalma g&ouml;r&uuml;l&uuml;r, taşıyıcı h&uuml;cre sayısı ve bu h&uuml;creler arasındaki boşluğu dolduran maddeler azalır.&nbsp; Bu nedenle deri kalınlığını, esnek yapısını ve p&uuml;r&uuml;zs&uuml;z g&ouml;r&uuml;n&uuml;m&uuml;n&uuml; kaybeder ve bazen de birtakım renk değişiklikleri de meydana gelebilir. Elastikiyetini kaybetmiş ve protein yapısı bozulmuş deri kırışır ve sarkar. Bu sorunlar kendini en belirgin olarak yanaklarda, boyunda ve kaşların dış kısımlarında g&ouml;sterir. Sigara, sağlıksız yaşam, g&uuml;neşin zararlı etkileri derinin sarkma s&uuml;recini hızlandıran başlıca etkilerdir. Y&uuml;zde sarkan deriyi hastanın genel sağlık durumu, derideki sarkma miktarı, y&uuml;zdeki diğer deformasyonlar birlikte değerlendirilip birlikte en uygun tedaviye karar verilmelidir.</p>\r\n\r\n<p>&nbsp;Y&uuml;z germe ameliyatında ama&ccedil; yanak b&ouml;lgesi, y&uuml;z&uuml;n alt b&ouml;l&uuml;mleri ve &ccedil;ene/boyun hattındaki sarkmanın giderilmesidir. Y&uuml;z germe operasyonu sonucunda hasta gen&ccedil; ve doğal g&ouml;r&uuml;n&uuml;me kavuşur. Bu operasyon y&uuml;z&uuml;n diğer b&ouml;lgelerine uygulanan operasyonlarla (g&ouml;z kapağı, şakak-alın germe ve yağ enjeksiyonları) kombine edilebilir. Cerrahi operasyonla y&uuml;z&uuml; germe, diğer y&ouml;ntemlerle kıyaslandığında&nbsp; iyileşme s&uuml;reci daha uzun olmasına rağmen kalıcılığı en uzun olan y&ouml;ntemdir.&nbsp;</p>\r\n\r\n<p>Y&uuml;z germe ameliyatında kulak arkasından sa&ccedil;lı deri b&ouml;lgesinden yapılan kesilerle birlikte y&uuml;zdeki tabakalar itina ile a&ccedil;ılır. A&ccedil;ılan deri arkaya ve yukarı doğru gerdirilerek sarkmış dokulara m&uuml;dahale edilir. Yaklaşık 1 hafta sonunda dikişler alınır, bu s&uuml;re sonunda y&uuml;zdeki &ouml;demler &ouml;nemli oranda ortadan kalkacaktır. Ameliyat sonrası ağrılar &ccedil;ok şiddetli değildir, basit ağrı kesiciler ile giderilebilir. Cildin y&uuml;z &uuml;zerine oturması ve son şeklini alması 4-6 ayı bulabilir. Bu s&uuml;re&ccedil;te y&uuml;z&uuml;n fiziksel darbe ve m&uuml;dahalelerden sakınılması gerekmektedir.&nbsp;</p>\r\n', '', 'Face Lift', '<p>With aging, there is a decrease in the carrier proteins that form the structure of the skin covering the face, the number of carrier cells and the substances that fill the space between these cells decrease. For this reason, the skin loses its thickness, flexible structure and smooth appearance, and sometimes some color changes may occur. The skin, which has lost its elasticity and protein structure, wrinkles and sags. These problems manifest themselves most prominently on the cheeks, neck and outer parts of the eyebrows. Smoking, unhealthy life, harmful effects of the sun are the main effects that accelerate the sagging process of the skin. The general health status of the patient, the amount of sagging skin, and other facial deformations should be evaluated together and the most appropriate treatment should be decided together.</p>\r\n\r\n<p>The aim of facelift surgery is to remove sagging in the cheek area, lower parts of the face and chin/neck line. As a result of the face lift operation, the patient regains a young and natural appearance. This operation can be combined with operations applied to other parts of the face (eyelid, temple-forehead lift and fat injections). Facelift with surgical operation is the method with the longest permanence, although the healing process is longer when compared to other methods.</p>\r\n\r\n<p>In face lift surgery, the layers on the face are carefully opened with the incisions made from the scalp area behind the ear. The opened skin is stretched backwards and upwards, and sagging tissues are intervened. At the end of about 1 week, the sutures are removed, at the end of this period, edema on the face will disappear significantly. Post-operative pain is not very severe, it can be relieved with simple painkillers. It may take 4-6 months for the skin to settle on the face and take its final shape. In this process, physical impacts and interventions on the face should be avoided.</p>\r\n', '', '', '', '', 'شد الوجه (فايسليفت)', '<p dir=\"rtl\">مع تقدم العمر ، هناك انخفاض في البروتينات الحاملة التي تشكل بنية الجلد التي تغطي الوجه ، وعدد الخلايا الحاملة والمواد التي تملأ الفراغ بين هذه الخلايا. وبسبب هذا ، يفقد الجلد سمكه وبنيته المرنة ومظهره الناعم ، وفي بعض الأحيان يمكن أن يحدث أيضا عدد من التغييرات في اللون. تحدث التجاعيد والترهل أيضا على الجلد الذي فقد مرونته وله بنية بروتينية. هذه المشاكل تعبر عن نفسها بشكل أكثر وضوحا على الخدين والرقبة والأجزاء الخارجية من الحاجبين. التدخين ، ونمط الحياة غير الصحي ، والآثار الضارة للشمس هي الآثار الرئيسية التي تسرع عملية ترهل الجلد. يجب تقييم الحالة الصحية العامة للمريض الذي يعاني من ترهل الجلد على الوجه ، وكمية الجلد المترهل ، والتشوهات الأخرى على الوجه معا ، ويجب تحديد العلاج الأنسب معا.</p>\r\n\r\n<p dir=\"rtl\">الغرض من جراحة شد الوجه هو القضاء على الترهل في منطقة الخد والأجزاء السفلية من الوجه وخط الفك / الرقبة. نتيجة لعملية شد الوجه ، يحصل المريض على مظهر شاب وطبيعي. يمكن الجمع بين هذه العملية والعمليات المطبقة على أجزاء أخرى من الوجه (الجفن ، شد الجبهة الصدغية وحقن الدهون). شد الوجه مع عملية جراحية هي الطريقة ذات الثبات الأطول ، على الرغم من أن عملية الشفاء أطول مقارنة بالطرق الأخرى.&nbsp;</p>\r\n\r\n<p dir=\"rtl\">في جراحة شد الوجه ، يتم فتح طبقات الوجه بعناية بشقوق مصنوعة من منطقة فروة الرأس خلف الأذن. يتم شد الجلد المفتوح للخلف وللأعلى ، مما يتداخل مع الأنسجة المترهلة. تقريبا في نهاية الأسبوع تتم إزالة الغرز ، بعد هذا الوقت وذمة على الوجه سوف تختفي بشكل ملحوظ. الألم بعد الجراحة ليست شديدة جدا ، ويمكن إزالتها مع مسكنات الألم بسيطة. قد يستغرق الأمر من ٤ إلى ٦ أشهر حتى وجها لجلد على الوجه ويأخذ شكله النهائي. خلال هذه العملية ، من الضروري تجنب التأثير الجسدي والتدخل في الوجه.</p>\r\n', '', '', '', '', 'Facelift', '<p>Mit dem Altern wird eine Abnahme der Tr&auml;gerproteine beobachtet, die die Struktur der Haut bilden, die das Gesicht bedeckt.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>Die Anzahl der Tr&auml;gerzellen und die Substanzen, die den Raum zwischen diesen Zellen f&uuml;llen, nimmt ebenfalls ab. Aus diesem Grund verliert die Haut ihre Dicke, elastische Struktur und ihr glattes Aussehen, und manchmal k&ouml;nnen auch einige Farbver&auml;nderungen auftreten. Die Haut, die ihre Elastizit&auml;t verloren hat und ihre Proteinstruktur beeintr&auml;chtigt ist, wird faltig und schlaff. Diese Probleme manifestieren sich am deutlichsten auf den Wangen, dem Hals und den &auml;u&szlig;eren Teilen der Augenbrauen. Rauchen, ungesunde Lebensweise und die sch&auml;dlichen Auswirkungen der Sonne sind die Haupteffekte, die den schlaffen Prozess der Haut beschleunigen.&nbsp;</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>Der allgemeine Gesundheitszustand des Patienten, die Menge der schlaffen Haut, andere Deformationen im Gesicht sollten gemeinsam bewertet und gemeinsam &uuml;ber die optimale Behandlung entschieden werden. Das Ziel der Facelift-Operation ist es, die schlaffe Wangenregion, die unteren Teile des Gesichts und die Linie des Kinns/Halses zu entfernen. Als Ergebnis der Facelift-Operation erh&auml;lt der Patient ein junges und nat&uuml;rliches Aussehen. Diese Operation kann mit Operationen kombiniert werden, die auf andere Bereiche des Gesichts angewendet werden (Augenlid, Schl&auml;fen-stirnstraffung und Fetteinspritzung). Ein chirurgisches Facelift ist die l&auml;ngste Methode, obwohl der Heilungsprozess im Vergleich zu anderen Methoden l&auml;nger ist.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>Bei einer Facelift-Operation werden die Schichten im Gesicht mit Einschnitten aus dem Bereich der Kopfhaut hinter dem Ohr sorgf&auml;ltig ge&ouml;ffnet. Die ge&ouml;ffnete Haut wird nach hinten und nach oben gestreckt, um schlaffe Gewebe zu st&ouml;ren. Nach etwa 1 Woche werden die Stiche entfernt, nach dieser Zeit verschwinden die &Ouml;deme im Gesicht deutlich. Die Schmerzen nach der Operation sind nicht sehr stark, sie k&ouml;nnen mit einfachen Schmerzmitteln beseitigt werden. Es kann 4-6 Monate dauern, bis die Haut auf dem Gesicht sitzt und ihre endg&uuml;ltige Form annimmt. W&auml;hrend dieses Prozesses m&uuml;ssen k&ouml;rperliche Schl&auml;ge und Eingriffe im Gesicht vermieden werden.</p>\r\n', '', NULL, NULL, NULL, '831afea0062d2c57cc0f20220407eyalcinca9dbbe79a48a266094c', '7', '2022-04-07 15:21:17', NULL, NULL, NULL, '1'),
('34', '43', '2022-04-07', NULL, 'Kepçe Kulak Estetiği (Otoplasti)', '<p>Kep&ccedil;e kulak estetiği, kulağıyla kafatası arasında a&ccedil;ılanmada fazlalık, kulak kıvrımındaki siliklik veya kulak memesi bozuklukları bulunan hastalarımıza kafatası ile uyumlu ve iyi g&ouml;r&uuml;nen bir kulağa kavuşturmak i&ccedil;in uygulanır. Kulak gelişimi genellikle 6 yaşa kadar tamamlanır. Bu nedenle m&uuml;dahale &ccedil;ocukların &ouml;zg&uuml;venli bir başlangı&ccedil; yapmaları i&ccedil;in okul &ouml;ncesinde yapılabilmektedir. Bununla birlikte bu operasyon kulak g&ouml;r&uuml;n&uuml;m&uuml;n&uuml; umursamamış veya bunu d&uuml;zeltmeye fırsat bulamamış yetişkin hastalara da istenildiği zaman yapılabilmektedir.</p>\r\n\r\n<p>Hastanın tıbbi ge&ccedil;mişi, yaşı, kulaktaki deformasyonun boyutu vb kişiye &ouml;zel koşullar g&ouml;z &ouml;n&uuml;nde bulundurularak kulağın anatomisine ve kıkırdak yapısına en uygun operasyon planlaması yapılır. Operasyon lokal anestezi ile yapılabileceği gibi &ouml;zellikle gerekmesi halinde (erişkin panik atağı olan hasta ya da &ccedil;ocuk hasta) genel anestezi ile de yapılabilir. Yaklaşık 1 saat s&uuml;ren operasyonda kulak arkasından kesilerle hastanın ihtiyacına g&ouml;re kıkırdak &ccedil;ıkarma ve/veya dikişlerle kıkırdağa şekil verme işlemleri yapılır. İşlem sonunda kulak arkasına kendiliğinden eriyecek dikişler atılabildiği gibi, kalıcı dikişler de kullanılabilir.</p>\r\n\r\n<p>Hasta yapılan işlemin ağırlığına g&ouml;re genellikle aynı g&uuml;n de taburcu edilir. Taburcu olduktan sonra hastalarımızın bir s&uuml;re kulak &uuml;zerine yatmaması ve 2-3 hafta tenis&ccedil;i bandı takması &ouml;nerilir.&nbsp;</p>\r\n', '', 'Prominent Ear Aesthetics (Otoplasty)', '<p>Prominent ear aesthetics is applied to our patients who have excessive angulation between the ear and the skull, faintness in the ear fold or earlobe disorders, in order to obtain an ear that is compatible with the skull and looks good. Ear development is usually completed by the age of 6 years. For this reason, the intervention can be done in preschool so that children can make a confident start. However, this operation can also be performed on adult patients who did not care about the appearance of the ear or did not have the opportunity to correct it, at any time.</p>\r\n\r\n<p>The most appropriate operation planning is made for the anatomy and cartilage structure of the ear, taking into account the patient&#39;s medical history, age, size of the deformation in the ear, etc., and personal conditions. The operation can be performed with local anesthesia or, if necessary, with general anesthesia (adult panic attack patient or pediatric patient). In the operation, which lasts about 1 hour, cartilage removal and/or cartilage shaping with stitches are performed according to the patient&#39;s needs with incisions behind the ear. At the end of the procedure, self-melting stitches can be placed behind the ear and permanent stitches can be used.</p>\r\n\r\n<p>The patient is usually discharged on the same day, depending on the severity of the procedure. After discharge, it is recommended that our patients do not lie on their ears for a while and wear a tennis band for 2-3 weeks.</p>\r\n', '', '', '', '', 'سكوب تجميل الأذن (اوتوبلاستي)', '<p dir=\"rtl\">يتم تطبيق جماليات الأذن سكوب لمرضانا مع فتح الزائد بين الأذن والجمجمة ديسمبر ، ضآلة في ثنية الأذن أو اضطرابات شحمة الأذن للحصول على الأذن التي تتوافق مع الجمجمة وتبدو جيدة. عادة ما يكتمل نمو الأذن في سن ٦ سنوات. لذلك ، يمكن إجراء التدخل في مرحلة ما قبل المدرسة حتى يتمكن الأطفال من البدء بثقة النفس. ومع ذلك ، يمكن أيضا إجراء هذه العملية في أي وقت للمرضى البالغين الذين لا يهتمون بمظهر الأذن أو لم تتح لهم الفرصة لتصحيحها.&nbsp;</p>\r\n\r\n<p dir=\"rtl\">أنسب تخطيط للعملية يتم إجراؤه للتشريح وتركيب غضروف الأذن ، مع الأخذ في الاعتبار التاريخ الطبي للمريض ، والعمر ، وحجم تشوه الأذن ، وما إلى ذلك. يمكن إجراء العملية بالتخدير الموضعي ، وكذلك بالتخدير العام ، خاصة إذا لزم الأمر (مريض نوبة الهلع البالغ أو مريض الطفل). في عملية تستغرق حوالي ١ ساعة ، يتم تنفيذ إزالة الغضروف و / أو عمليات تشكيل الغضروف وفقا لاحتياجات المريض مع تخفيضات وراء الأذن والغرز. في نهاية الإجراء ، يمكن وضع غرز الذوبان الذاتي خلف الأذن ، وكذلك يمكن استخدام غرز دائمة.&nbsp;</p>\r\n\r\n<p dir=\"rtl\">عادة ما يتم تفريغ المريض في نفس اليوم وفقا لحالة الإجراء المنجز. بعد الخروج من المستشفى ، يوصى بعدم الاستلقاء على آذانهم لفترة من الوقت وارتداء عقال لاعب التنس لمدة ٢ - ٣ أسابيع.&nbsp;</p>\r\n', '', '', '', '', 'Ohrenschmalz (Otoplastik)', '<p>Die Scoop-ohr&auml;sthetik wird bei Patienten mit einem &Uuml;berschuss an &Ouml;ffnung zwischen Ohr und Sch&auml;del, Silikonheit in der Ohrfalte oder Ohrl&auml;ppchen angewendet, um ein mit dem Sch&auml;del Kompatibles und gutaussehendes Ohr wiederherzustellen. Die Entwicklung des Ohres ist in der Regel bis zum Alter von 6 Jahren abgeschlossen. Aus diesem Grund kann die Intervention vor der Schule durchgef&uuml;hrt werden, um den Kindern einen selbstbewussten Start zu erm&ouml;glichen. Diese Operation kann jedoch auch bei erwachsenen Patienten durchgef&uuml;hrt werden, die sich nicht um das Aussehen des Ohres gek&uuml;mmert haben oder keine M&ouml;glichkeit hatten, es zu korrigieren.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>Unter Ber&uuml;cksichtigung der Krankengeschichte des Patienten, des Alters, der Gr&ouml;&szlig;e der Verformung des Ohres usw. werden die f&uuml;r die Anatomie des Ohres und die Knorpelstruktur am besten geeigneten Operationspl&auml;ne erstellt. Die Operation kann mit Lokalan&auml;sthesie oder, wenn n&ouml;tig, mit Vollnarkose durchgef&uuml;hrt werden (erwachsener Patient mit Panikattacke oder Kind Patient). W&auml;hrend der Operation, die etwa 1 Stunde dauert, werden nach den Bed&uuml;rfnissen des Patienten mit Einschnitten hinter dem Ohrknorpelextraktion und/oder Stiche durchgef&uuml;hrt, um den Knorpel zu formen. Am Ende des Verfahrens k&ouml;nnen selbstschmelzende N&auml;hte hinter das Ohr gelegt werden, sowie dauerhafte N&auml;hte k&ouml;nnen verwendet werden.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>Je nach Gewicht des Eingriffs wird der Patient in der Regel am selben Tag entlassen. Nach der Entlassung wird unseren Patienten empfohlen, einige Zeit nicht auf dem Ohr zu liegen und 2-3 Wochen tennisband zu tragen.</p>\r\n', '', NULL, NULL, NULL, 'f67bcdd4d51a5bd9731e20220407eyalcin048a6e28f249eee82541', '7', '2022-04-07 15:22:05', NULL, NULL, NULL, '1'),
('35', '43', '2022-04-07', NULL, 'Yüz Boyun Estetiği ', '<p>Yaşlanma ile birlikte y&uuml;z&uuml; kaplayan derinin yapısını oluşturan taşıyıcı proteinlerde azalma g&ouml;r&uuml;l&uuml;r, taşıyıcı h&uuml;cre sayısı ve bu h&uuml;creler arasındaki boşluğu dolduran maddeler azalır.&nbsp; Bu nedenle deri kalınlığını, esnek yapısını ve p&uuml;r&uuml;zs&uuml;z g&ouml;r&uuml;n&uuml;m&uuml;n&uuml; kaybeder ve bazen de birtakım renk değişiklikleri meydana gelebilir. Elastikiyetini kaybetmiş ve protein yapısı bozulmuş deri kırışır ve sarkar. Bu sorunlar kendini en belirgin olarak yanaklarda, boyunda ve kaşların dış kısımlarında g&ouml;sterir. Sigara, sağlıksız yaşam, g&uuml;neşin zararlı etkileri derinin sarkma s&uuml;recini hızlandıran başlıca etkilerdir. Hastanın genel sağlık durumu, derideki sarkma miktarı, y&uuml;zdeki diğer deformasyonlar birlikte değerlendirilip birlikte en uygun tedaviye karar verilmelidir.</p>\r\n\r\n<p>Boyun germe ameliyatında ama&ccedil; boyun b&ouml;lgesi, y&uuml;z&uuml;n alt b&ouml;l&uuml;mleri ve &ccedil;ene/boyun hattındaki sarkmanın giderilmesidir. Boyun germe operasyonu sonucunda hasta gen&ccedil; ve doğal g&ouml;r&uuml;n&uuml;me kavuşur. Bu operasyon y&uuml;z&uuml;n diğer b&ouml;lgelerine uygulanan operasyonlarla (g&ouml;z kapağı, şakak-alın germe ve yağ enjeksiyonları) birlikte ger&ccedil;ekleştirilebilir. Cerrahi operasyonla boyun germe diğer y&ouml;ntemlerle kıyaslandığında ve iyileşme s&uuml;reci daha uzun olmasına rağmen kalıcılığı en uzun olan y&ouml;ntemdir.&nbsp;</p>\r\n\r\n<p>Boyun germe ameliyatında kulak arkasından sa&ccedil;lı deri b&ouml;lgesinden yapılan kesilerle birlikte y&uuml;zdeki tabakalar itina ile a&ccedil;ılır. A&ccedil;ılan deri arkaya ve yukarı doğru gerdirilerek sarkmış dokulara m&uuml;dahale edilir. Yaklaşık 1 hafta sonunda dikişler alınır, bu s&uuml;re sonunda y&uuml;zdeki &ouml;demler &ouml;nemli oranda ortadan kalkacaktır. Ameliyat sonrası ağrılar &ccedil;ok şiddetli değildir, basit ağrı kesiciler ile giderilebilir. Cildin y&uuml;z &uuml;zerine oturması ve son şeklini alması 4-6 ayı bulabilir. Bu s&uuml;re&ccedil;te y&uuml;z&uuml;n fiziksel darbe ve m&uuml;dahalelerden sakınılması gerekmektedir.&nbsp;</p>\r\n', '', 'Face Neck Aesthetics', '<p>With aging, there is a decrease in the carrier proteins that form the structure of the skin covering the face, the number of carrier cells and the substances that fill the space between these cells decrease. For this reason, the skin loses its thickness, flexible structure and smooth appearance, and sometimes some color changes may occur. The skin, which has lost its elasticity and protein structure, wrinkles and sags. These problems manifest themselves most prominently on the cheeks, neck and outer parts of the eyebrows. Smoking, unhealthy life, harmful effects of the sun are the main effects that accelerate the sagging process of the skin. The general health status of the patient, the amount of sagging in the skin, and other facial deformations should be evaluated together and the most appropriate treatment should be decided together.</p>\r\n\r\n<p>The aim of neck lift surgery is to remove sagging in the neck area, lower parts of the face and chin/neck line. As a result of neck lift operation, the patient regains a young and natural appearance. This operation can be performed together with operations applied to other parts of the face (eyelid, temple-forehead lift and fat injections). Surgical neck lift is the method with the longest permanence when compared to other methods and although the healing process is longer.</p>\r\n\r\n<p>In neck lift surgery, the layers on the face are carefully opened with the incisions made from the scalp area behind the ear. The opened skin is stretched backwards and upwards, and sagging tissues are intervened. At the end of about 1 week, the sutures are removed, at the end of this period, edema on the face will disappear significantly. Post-operative pain is not very severe, it can be relieved with simple painkillers. It may take 4-6 months for the skin to settle on the face and take its final shape. In this process, physical impacts and interventions on the face should be avoided.</p>\r\n', '', '', '', '', 'تجميل الوجه والرقبة', '<p dir=\"rtl\">مع تقدم العمر ، هناك انخفاض في البروتينات الحاملة التي تشكل بنية الجلد التي تغطي الوجه ، وعدد الخلايا الحاملة والمواد التي تملأ الفراغ بين هذه الخلايا. لذلك ، يفقد الجلد سمكه وبنيته المرنة ومظهره الناعم ، وفي بعض الأحيان قد يحدث عدد من التغييرات في اللون. الجلد الذي فقد مرونته وله بنية بروتينية ، مجعد ومترهل. هذه المشاكل تعبر عن نفسها بشكل أكثر وضوحا على الخدين والرقبة والأجزاء الخارجية من الحاجبين. التدخين ، ونمط الحياة غير الصحي ، والآثار الضارة للشمس هي الآثار الرئيسية التي تسرع عملية ترهل الجلد. يجب تقييم الحالة الصحية العامة للمريض ، وكمية الترهل على الجلد ، والتشوهات الأخرى على الوجه معا ، ويجب تحديد العلاج الأنسب معا.</p>\r\n\r\n<p dir=\"rtl\">الغرض من جراحة شد الرقبة هو القضاء على الترهل في منطقة الرقبة والأجزاء السفلية من الوجه وخط الفك / الرقبة. نتيجة لعملية شد الرقبة ، يحصل المريض على مظهر شاب وطبيعي. يمكن إجراء هذه العملية بالاقتران مع العمليات المطبقة على أجزاء أخرى من الوجه (الجفن ، شد الجبهة الصدغي وحقن الدهون. تمتد الرقبة عن طريق العملية الجراحية هي الطريقة ذات الثبات الأطول ، على الرغم من أن عملية الشفاء أطول مقارنة بالطرق الأخرى.</p>\r\n\r\n<p dir=\"rtl\">في جراحة شد الرقبة ، يتم فتح طبقات الوجه بعناية بشقوق مصنوعة من منطقة فروة الرأس خلف الأذن. يتم شد الجلد المفتوح للخلف وللأعلى وتتدخل الأنسجة المترهلة. تقريبا في نهاية أسبوعا ، تتم إزالة الغرز ، بعد هذا الوقت وذمة على الوجه سوف تختفي بشكل ملحوظ. الألم بعد الجراحة ليست شديدة جدا ، ويمكن إزالتها مع مسكنات الألم بسيطة. قد يستغرق الأمر من ٤ إلى ٦ أشهر حتى وجها لجلد على الوجه ويأخذ شكله النهائي. خلال هذه العملية ، من الضروري تجنب التأثير الجسدي والتدخل في الوجه.</p>\r\n', '', '', '', '', 'Gesichts-Hals-Ästhetik', '<p>Mit dem Altern wird eine Abnahme der Tr&auml;gerproteine beobachtet, die die Struktur der Haut bilden, die das Gesicht bedeckt. Die Anzahl der Tr&auml;gerzellen und Substanzen, die den Raum zwischen diesen Zellen f&uuml;llen, nimmt ab.&nbsp; Aus diesem Grund verliert die Haut ihre Dicke, elastische Struktur und ihr glattes Aussehen, und manchmal kann es zu einer Reihe von Farbver&auml;nderungen kommen. Die Haut, die ihre Elastizit&auml;t verloren hat und ihre Proteinstruktur beeintr&auml;chtigt ist, wird faltig und schlaff. Diese Probleme manifestieren sich am deutlichsten auf den Wangen, dem Hals und den &auml;u&szlig;eren Teilen der Augenbrauen. Rauchen, ungesunde Lebensweise und die sch&auml;dlichen Auswirkungen der Sonne sind die Haupteffekte, die den schlaffen Prozess der Haut beschleunigen. Der allgemeine Gesundheitszustand des Patienten mit schlaffer Haut im Gesicht, die Menge der schlaffen Haut, andere Deformationen im Gesicht sollten gemeinsam bewertet und gemeinsam &uuml;ber die optimale Behandlung entschieden werden.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>Bei der Nackenliftoperation ist das Ziel, das Absacken im Nackenbereich, den unteren Teilen des Gesichts und der Kinn - /Nackenlinie zu entfernen. Als Ergebnis der Nackenstraffung erh&auml;lt der Patient ein junges und nat&uuml;rliches Aussehen. Diese Operation kann in Verbindung mit Operationen durchgef&uuml;hrt werden, die auf andere Bereiche des Gesichts angewendet werden (Augenlid, Schl&auml;fen-stirnstraffung und Fetteinspritzung). Im Vergleich zu anderen Methoden und trotz der Tatsache, dass der Heilungsprozess l&auml;nger ist, ist die chirurgische Operation und Halsstraffung die l&auml;ngste Methode der Dauerhaftigkeit.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>Bei einer Halsliftoperation werden die Schichten im Gesicht mit Einschnitten aus dem Bereich der Kopfhaut hinter dem Ohr sorgf&auml;ltig ge&ouml;ffnet. Die ge&ouml;ffnete Haut wird nach hinten und nach oben gestreckt, um schlaffe Gewebe zu st&ouml;ren. Nach etwa 1 Woche werden die Stiche entfernt, nach dieser Zeit verschwinden die &Ouml;deme im Gesicht deutlich. Die Schmerzen nach der Operation sind nicht sehr stark, sie k&ouml;nnen mit einfachen Schmerzmitteln beseitigt werden. Es kann 4-6 Monate dauern, bis die Haut auf dem Gesicht sitzt und ihre endg&uuml;ltige Form annimmt. W&auml;hrend dieses Prozesses m&uuml;ssen k&ouml;rperliche Schl&auml;ge und Eingriffe im Gesicht vermieden werden.</p>\r\n', '', NULL, NULL, NULL, '73c8dc4f9115a10fecd720220407eyalcin0facd308b51ca7d9e791', '7', '2022-04-07 15:24:43', NULL, NULL, NULL, '1'),
('36', '43', '2022-04-07', NULL, 'Kaş Kaldırma', '<p>Kaş kaldırma operasyonu, kaşlardaki g&ouml;r&uuml;n&uuml;m bozukluklarını ortadan kaldırmayı ve mimikleri daha canlı hale getirmeyi ama&ccedil;layan ve sıklıkla tercih edilen operasyonlardan biridir. Yaşlanma ve &ccedil;evresel fakt&ouml;rlere bağlı olarak kaş b&ouml;lgesinde sarkma, solma, d&ouml;k&uuml;lme gibi problemler oluşmaktadır. Bunun yanında y&uuml;z&uuml;n genelinde kırışıklık ve &ccedil;izgilere sahip olan kişiler de bu sorunları ortadan kaldırmak i&ccedil;in tercih eder. Bu operasyon en erken ergenlik d&ouml;nemini hen&uuml;z tamamlamış olan bireylere uygulanabilir ancak bununla birlikte herhangi bir &uuml;st yaş sınırı bulunmamaktadır.</p>\r\n\r\n<p>Sa&ccedil;lı deride a&ccedil;ılan k&uuml;&ccedil;&uuml;k kesiler yardımıyla kaş b&ouml;lgesinin kaldırılması ve cildin gerginleştirilmesi şeklinde ger&ccedil;ekleştirilen bu işlem sonrası hem kaş b&ouml;lgesi kaldırılır hem de ciltte gerginleşme meydana geldiği i&ccedil;in kırışıklıklar, &ccedil;izgiler azalır. Ayrıca kaş kaldırma işlemi y&uuml;z&uuml;n genel yapısını da desteklediği i&ccedil;in g&ouml;r&uuml;n&uuml;m&uuml; genel olarak g&uuml;zelleştirir.</p>\r\n\r\n<p>Uygulanacak olan tedavi y&ouml;ntemine bağlı olarak iyileşme s&uuml;reci 3 ila 5 g&uuml;n arasında değişmektedir. Operasyon sonrası kızarıklık, şişlik ve morarma gibi durumlar g&ouml;r&uuml;lebilir ancak bu durum birka&ccedil; g&uuml;n i&ccedil;inde ortadan kalkar. Eğer dikiş uygulanmışsa 5 ila 7 g&uuml;n arasında alınır ve hasta normal yaşamına d&ouml;n&uuml;ş yapabilir.&nbsp;</p>\r\n', '', 'Brow Lift', '<p>Brow lift operation is one of the frequently preferred operations that aims to eliminate the appearance disorders in the eyebrows and to make the facial expressions more vivid. Depending on aging and environmental factors, problems such as sagging, fading and shedding occur in the eyebrow area. In addition, people who have wrinkles and lines throughout the face also prefer to eliminate these problems. This operation can be applied to individuals who have just completed the earliest puberty period, however, there is no upper age limit.</p>\r\n\r\n<p>After this procedure, which is carried out in the form of lifting the eyebrow area and tightening the skin with the help of small incisions on the scalp, both the eyebrow area is lifted and the wrinkles and lines are reduced as the skin tightens. In addition, as the eyebrow lift process supports the general structure of the face, it improves the appearance in general.</p>\r\n\r\n<p>Depending on the treatment method to be applied, the recovery period varies between 3 and 5 days. Conditions such as redness, swelling and bruising may occur after the operation, but this situation disappears within a few days. If stitches are applied, they are removed between 5 and 7 days and the patient can return to his normal life.</p>\r\n', '', '', '', '', ' رفع الحاجب', '<p dir=\"rtl\">عملية رفع الحاجب هي واحدة من العمليات التي تهدف إلى القضاء على اضطرابات المظهر في الحاجبين وجعل تعابير الوجه أكثر وضوحا ، وغالبا ما يفضل. بسبب الشيخوخة والعوامل البيئية ، تحدث مشاكل مثل الترهل والبهتان والتساقط في منطقة الحاجب. بالإضافة إلى ذلك ، يفضل الأشخاص الذين لديهم تجاعيد وخطوط في جميع أنحاء الوجه أيضا التخلص من هذه المشاكل. يمكن تطبيق هذه العملية على الأفراد الذين أكملوا للتو فترة البلوغ الأقرب، ولكن لا يوجد حد أعلى للسن.&nbsp;</p>\r\n\r\n<p dir=\"rtl\">بعد هذا الإجراء ، الذي يتم إجراؤه على شكل رفع منطقة الحاجب وتمديد الجلد بمساعدة شقوق صغيرة مفتوحة على فروة الرأس ، تتم إزالة كل من منطقة الحاجب وتقليل التجاعيد والخطوط بسبب حدوث توتر على الجلد. بالإضافة إلى ذلك ، يدعم رفع الحاجب أيضا الهيكل العام للوجه ، لذلك فهو يجمل المظهر بشكل عام.&nbsp;</p>\r\n\r\n<p dir=\"rtl\">اعتمادا على طريقة العلاج التي سيتم تطبيقها ، فإن عملية الشفاء من ٣ إلى ٥ أيام. بعد العملية ، قد تحدث حالات مثل الاحمرار والتورم والكدمات ، ولكن هذه الحالة تختفي في غضون أيام قليلة. إذا تم تطبيق الغرزة, يؤخذ بين٥ و ٧ أيام ويمكن للمريض العودة إلى الحياة الطبيعية.&nbsp;</p>\r\n', '', '', '', '', 'Augenbrauen Heben', '<p>Die Augenbrauenlift Operation ist eine der oft bevorzugten Operationen, die darauf abzielt, Sehst&ouml;rungen in den Augenbrauen zu beseitigen und die Mimik lebendiger zu machen. Aufgrund von Alterung und Umweltfaktoren entstehen Probleme wie schlaffe, verblassen, versch&uuml;tten im Augenbrauenbereich. Dar&uuml;ber hinaus bevorzugen Menschen, die Falten und Linien im ganzen Gesicht haben, einen Augenbrauenlift, um diese Probleme zu beseitigen. Diese Operation kann auf Personen angewendet werden, die die fr&uuml;heste Pubert&auml;t noch nicht abgeschlossen haben, aber es gibt keine obere Altersgrenze.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>Nach diesem Verfahren, das mit Hilfe von kleinen Einschnitten in der Kopfhaut durchgef&uuml;hrt wird, um den Augenbrauenbereich zu heben und die Haut zu straffen, werden sowohl der Augenbrauenbereich entfernt als auch Falten und Linien reduziert, da sich die Haut verspannt. Dar&uuml;ber hinaus versch&ouml;nert der Augenbrauenlift das Aussehen insgesamt, da er auch die allgemeine Struktur des Gesichts unterst&uuml;tzt.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>Je nach Behandlungsmethode variiert der Heilungsprozess zwischen 3 und 5 Tagen. Nach der Operation k&ouml;nnen Bedingungen wie R&ouml;tung, Schwellung und Bluterg&uuml;sse auftreten, aber dieser Zustand verschwindet innerhalb weniger Tage. Wenn eine Naht angewendet wird, wird sie zwischen 5 und 7 Tagen entfernt und der Patient kann zu seinem normalen Leben zur&uuml;ckkehren.</p>\r\n', '', NULL, NULL, NULL, '2f332863d28a71aecd4e20220407eyalcinc1baa580bb5af1847e68', '7', '2022-04-07 15:25:19', NULL, NULL, NULL, '1'),
('37', '43', '2022-04-07', NULL, 'Göz Kapağı Estetiği', '<p>G&ouml;z kapağı estetiği yaşlanma veya başkaca sebeplerle &uuml;st veya alt g&ouml;z kapağındaki dokuların gevşemesi nedeniyle meydana gelen deformasyon ve sarkmaları d&uuml;zeltmek amacıyla yapılır. Bu operasyon genellikle estetik kaygılarla g&ouml;r&uuml;n&uuml;m&uuml; g&uuml;zelleştirmek i&ccedil;in yapılır. Bazı vakalarda ise g&ouml;r&uuml;n&uuml;m&uuml; d&uuml;zeltmenin yanında g&ouml;z kapaklarındaki ağırlık ve g&ouml;rmeye engel olan bozuklukları da d&uuml;zeltir. Alt g&ouml;z kapağı ve &uuml;st g&ouml;z kapağına ayrı ayrı m&uuml;dahale edilebildiği gibi alt ve &uuml;st g&ouml;z kapağına birlikte de m&uuml;dahale edilebilir. G&ouml;z kapağı estetiği operasyonu kaş d&uuml;ş&uuml;kl&uuml;ğ&uuml;, y&uuml;z sarkması veya g&ouml;z kapağı d&uuml;ş&uuml;kl&uuml;ğ&uuml;n&uuml;n giderilmesi operasyonlarıyla birlikte ger&ccedil;ekleştirilebilir. &nbsp;</p>\r\n\r\n<p>&Uuml;st g&ouml;z kapağının doğal &ccedil;izgileri &uuml;zerinden kesilerle bu b&ouml;lgede gerekli g&ouml;r&uuml;len cilt, kas, yağ dokularına m&uuml;dahale ile &uuml;st g&ouml;z kapağına şekil verilir. Alt g&ouml;z kapağı operasyonu ise alt kirpikli kenar dibinden veya g&ouml;z kapağının i&ccedil; tarafından yapılır. G&ouml;z kapağına yapılan m&uuml;dahalede ama&ccedil; gevşemiş dokuları sıkılaştırmaktır. Bazen bu m&uuml;dahaleler, kaş kaldırma, badem g&ouml;z veya y&uuml;z germe işlemleri ile birlikte yapılabilir.&nbsp;</p>\r\n\r\n<p>Yapılan işlemin ağırlığına g&ouml;re hasta aynı g&uuml;n de taburcu edilir. Genellikle 5-6 g&uuml;n i&ccedil;erisinde dikişler alınır, bu s&uuml;re sonunda y&uuml;zdeki &ouml;demler &ouml;nemli oranda azalır.</p>\r\n', '', 'Eyelid aesthetic', '<p>Eyelid aesthetics are performed to correct deformations and sagging caused by loosening of the tissues in the upper or lower eyelids due to aging or other reasons. This operation is usually performed to beautify the appearance due to aesthetic concerns. In some cases, in addition to correcting the appearance, it also corrects the heaviness of the eyelids and the disorders that prevent vision. The lower and upper eyelids can be treated separately, as well as the upper and lower eyelids together. Eyelid aesthetic operation can be performed together with eyebrow drooping, facial sagging or droopy eyelid operations.</p>\r\n\r\n<p>With incisions over the natural lines of the upper eyelid, the upper eyelid is shaped by intervening the skin, muscle and fat tissues required in this area. The lower eyelid operation is performed from the bottom of the lower eyelash margin or from the inside of the eyelid. The purpose of the intervention on the eyelid is to tighten the loose tissues. Sometimes these interventions can be combined with eyebrow lifting, almond eye or face lift procedures.</p>\r\n\r\n<p>Depending on the severity of the procedure, the patient is discharged on the same day. Generally, the sutures are removed within 5-6 days, after which the edema on the face is significantly reduced.</p>\r\n', '', '', '', '', 'جماليات الجفن', '<p dir=\"rtl\">يتم إجراء جماليات الجفن من أجل تصحيح التشوهات والترهل الناجم عن ارتخاء أنسجة الجفن العلوي أو السفلي بسبب الشيخوخة أو لأسباب أخرى. عادة ما يتم تنفيذ هذه العملية لتجميل المظهر مع المخاوف الجمالية. في بعض الحالات ، بالإضافة إلى تصحيح المظهر ، فإنه يصحح أيضا ثقل الجفون والاضطرابات التي تتداخل مع الرؤية. يمكن التدخل في الجفن السفلي والجفن العلوي بشكل منفصل ، وكذلك يمكن التدخل في الجفون السفلية والعلوية معا. يمكن إجراء جراحة تجميل الجفن بالاقتران مع عمليات تصغير الحاجب أو ترهل الوجه أو تصغير الجفن.&nbsp;</p>\r\n\r\n<p dir=\"rtl\">يتم تشكيل الجفن العلوي عن طريق التدخل على الجلد ، نوفمبر ، والأنسجة الدهنية التي تعتبر ضرورية في هذا المجال مع شقوق من خلال الخطوط الطبيعية للجفن العلوي. يتم إجراء عملية الجفن السفلي من أسفل حافة الأهداب السفلية أو من الجانب الداخلي للجفن. الغرض من تدخل الجفن هو تشديد الأنسجة المخففة. في بعض الأحيان يمكن إجراء هذه التدخلات بالاشتراك مع رفع الحاجب أو عين اللوز أو شد الوجه.&nbsp;</p>\r\n\r\n<p dir=\"rtl\">وفقا لحالة الإجراء المنجز ، يتم تفريغ المريض في نفس اليوم. عادة ، تتم إزالة الغرز في غضون ٥ - ٦ أيام، وبعد ذلك يتم تقليل الوذمة على الوجه بشكل كبير.</p>\r\n', '', '', '', '', 'Augenlidästhetik', '<p>Die Augenlid&auml;sthetik wird durchgef&uuml;hrt, um Verformungen und schlaffe zu korrigieren, die durch das Altern oder die Entspannung der Gewebe im oberen oder unteren Augenlid aus anderen Gr&uuml;nden auftreten. Diese Operation wird normalerweise durchgef&uuml;hrt, um das Aussehen mit &auml;sthetischen Bedenken zu versch&ouml;nern. In einigen F&auml;llen korrigiert es neben der Korrektur des Aussehens auch das Gewicht der Augenlider und die St&ouml;rungen, die das sehen behindern. Das untere Augenlid und das obere Augenlid k&ouml;nnen separat behandelt werden, sowie das untere und obere Augenlid k&ouml;nnen zusammen interveniert werden. Die Operation der Augenlid&auml;sthetik kann zusammen mit Operationen zur Entfernung von augenbrauenschw&auml;che, gesichtsabsacken oder augenlidschw&auml;che durchgef&uuml;hrt werden.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>Mit Einschnitten durch die nat&uuml;rlichen Linien des oberen Augenlids wird das obere Augenlid durch Eingriffe in Haut, Muskeln und Fettgewebe geformt, die in diesem Bereich als notwendig erachtet werden. Die Operation des unteren Augenlids wird von der Unterseite der unteren wimpernkante oder von der Innenseite des Augenlids durchgef&uuml;hrt. Das Ziel des Eingriffs auf das Augenlid ist es, das lose Gewebe zu straffen. Manchmal k&ouml;nnen diese Eingriffe in Kombination mit Augenbrauenlift, Mandelauge oder Facelift durchgef&uuml;hrt werden.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>Je nach Gewicht des Eingriffs wird der Patient am selben Tag entlassen. In der Regel werden die Stiche innerhalb von 5-6 Tagen entfernt, nach dieser Zeit werden die &Ouml;deme im Gesicht deutlich reduziert.</p>\r\n', '', NULL, NULL, NULL, '5a50f7290e5a9a8c444d20220407eyalcind3ff0438eb9088a899e3', '7', '2022-04-07 15:26:04', NULL, NULL, NULL, '1'),
('38', '42', '2022-04-07', NULL, 'Botulinum Toksin Uygulaması', '<p>Yaşın ilerlemesi ile mimik &ccedil;izgilerinin belirginleşmesi herkesi rahatsız eder. Bu &ccedil;izgiler sıklıkla &uuml;st y&uuml;z b&ouml;lgesinde yer alır. Kaş &ccedil;atmaya bağlı oluşan yatay ve dikey kaş arası kırışıklıklar, g&ouml;z &ccedil;evresinde g&uuml;lmeye bağlı oluşan kaz ayağı kırışıklıkları ve yine alında kaş hareketine bağlı oluşan yatay alın &ccedil;izgileri hastalarımın başlıca şikayetlerini oluşturmaktadır.&nbsp;</p>\r\n\r\n<p>Botulinum Toksin tedavisinden daha etkili mimik &ccedil;izgilerini a&ccedil;an, kırışıklıkların daha iyi g&ouml;r&uuml;nmesini sağlayan bir tedavi yoktur.&nbsp; Klinik pratikte botulinum toksin tedavisi sıklıkla &uuml;st y&uuml;z b&ouml;lgesine uygulanır. Bu b&ouml;lgeler: kaş arası, alın ve g&ouml;z kenarlarıdır.&nbsp; Ancak alt y&uuml;z b&ouml;lgesinde ağız k&ouml;şelerini y&uuml;kseltme, portakal &ccedil;ene g&ouml;r&uuml;n&uuml;m&uuml;n&uuml; iyileştirme, boyun bantlarını yok etmede de botulinum toksinden sıklıkla faydalanılır.&nbsp;</p>\r\n\r\n<p>İşlemin toplam s&uuml;resi 5 dakikadır. İşlem neredeyse hi&ccedil; ağrılı değildir. Bunun sebebi kliniğimizde g&ouml;r&uuml;nmez (hayalet) iğne kullanımıdır. İşlemden hemen sonra hasta g&uuml;nl&uuml;k rutinine d&ouml;nebilir. Toksin tedavisinin etkisi 3-4. G&uuml;nler arasında başlar, 15. G&uuml;n maksimum d&uuml;zeye ulaşır. Genellikle 2 ila 3. Haftalar arasında kontrol muayenesi yapılarak gerek g&ouml;r&uuml;len yerlere ek dozlar ya da d&uuml;zeltmeler yapılır.&nbsp; Hasta memnuniyeti olduk&ccedil;a y&uuml;ksek olan bu uygulamanın etkinliği, kişiden kişiye değişmekle beraber 4-5 ay kadardır.&nbsp;</p>\r\n', '', 'Botulinum Toxin Application', '<p>With the advancement of age, the prominence of mimic lines bothers everyone. These lines are often located in the upper face area. The main complaints of my patients are horizontal and vertical wrinkles between the eyebrows due to frown, crow&#39;s feet wrinkles due to laughing around the eyes and horizontal forehead lines due to eyebrow movement on the forehead.</p>\r\n\r\n<p>There is no treatment more effective than Botulinum Toxin treatment, which opens the lines of expression and makes the wrinkles look better. In clinical practice, botulinum toxin therapy is often applied to the upper face area. These areas are between the eyebrows, forehead and eye corners. However, botulinum toxin is frequently used to raise the corners of the mouth, improve the orange chin appearance, and destroy the neck bands in the lower face area.</p>\r\n\r\n<p>The total duration of the procedure is 5 minutes. The procedure is almost never painful. The reason for this is the use of invisible (ghost) needles in our clinic. The patient can return to his daily routine immediately after the procedure. Effect of toxin treatment 3-4. It starts between days and reaches the maximum level on the 15th day. Usually, between the 2nd and 3rd weeks, a control examination is made and additional doses or corrections are made where necessary. The effectiveness of this application, which has a very high patient satisfaction, is about 4-5 months, although it varies from person to person.</p>\r\n', '', '', '', '', 'تطبيق توكسين البوتولينوم', '<p dir=\"rtl\">مع تقدم العمر, بروز خطوط الإيماء يزعج الجميع. غالبا ما توجد هذه الخطوط في منطقة الوجه العلوي. الشكاوى الرئيسية لمرضاي هي تجاعيد الحاجب الأفقية والعمودية الناتجة عن العبوس ، تجاعيد الغراب الناتجة عن الضحك حول العينين ، وخطوط الجبهة الأفقية الناتجة عن حركة الحاجب على الجبهة.&nbsp;</p>\r\n\r\n<p dir=\"rtl\">لا يوجد علاج يفتح خطوط الوجه بشكل أكثر فعالية من علاج توكسين البوتولينوم ويجعل التجاعيد تبدو أفضل. في الممارسة السريرية ، غالبا ما يتم تطبيق علاج توكسين البوتولينوم على منطقة الوجه العليا. هذه المناطق هي: بين الحاجبين, الجبين وحواف العينين. ولكن غالبا ما يستخدم توكسين البوتولينوم لزيادة زوايا الفم في منطقة الوجه السفلى ، وتحسين مظهر يشبه قشر البرتقال ، وأيضا تدمير العصابات الرقبة.&nbsp;</p>\r\n\r\n<p dir=\"rtl\">الوقت الإجمالي للعملية هو٥ دقائق. العملية يكاد يكون مؤلما أبدا. والسبب في ذلك هو استخدام الإبر غير المرئية (الشبح) في عيادتنا. مباشرة بعد العملية ، يمكن للمريض العودة إلى روتينه اليومي. يبدأ تأثير العلاج بالسموم في اليومين الثالث والرابع ، ويصل إلى الحد الأقصى في اليوم الخامس عشر. عادة من الثاني إلى ثالث أسابيع, يتم إجراء فحص السيطرة ويتم إجراء جرعات إضافية أو تصحيحات عند الضرورة. فعالية هذا التطبيق ، الذي لديه رضا المريض عالية جدا ، يختلف من شخص لآخر، ولكن هو ما يصل الى ٤-٥ أشهر.</p>\r\n', '', '', '', '', 'Anwendung von Botulinumtoxin', '<p>Mit fortschreitendem Alter stört die Prominenz mimischer Linien jeden. Diese Linien befinden sich oft im oberen Gesichtsbereich. Die Hauptbeschwerden meiner Patienten sind horizontale und vertikale Falten zwischen den Augenbrauen durch Stirnrunzeln, Krähenfü&szlig;e durch Lachen um die Augen und horizontale Stirnfalten durch Augenbrauenbewegungen auf der Stirn.</p>\r\n\r\n<p>Es gibt keine wirksamere Behandlung als die Botulinumtoxin-Behandlung, die Mimik Fältchen öffnet und Falten besser erscheinen lässt. In der klinischen Praxis wird die Botulinumtoxin- Therapie häufig im oberen Gesichtsbereich angewendet. Diese Bereiche befinden sich zwischen den Augenbrauen, der Stirn und den Augenwinkeln. Botulinumtoxin wird jedoch häufig verwendet, um die Mundwinkel anzuheben, das orangefarbene Kinn zu verbessern und die Nackenbänder im unteren Gesichtsbereich zu zerstören.</p>\r\n\r\n<p>Die Gesamtdauer des Verfahrens beträgt 5 Minuten. Das Verfahren ist fast nie schmerzhaft. Der Grund dafür ist die Verwendung von unsichtbaren Nadeln in unserer Klinik. Der Patient kann unmittelbar nach dem Eingriff in seinen Alltag zurückkehren. Die Wirkung der Toxinbehandlung setzt zwischen dem 3. und 4. Tag ein und erreicht am 15. Tag das Maximum. In der Regel wird zwischen der 2. und 3. Woche eine Kontrolluntersuchung durchgeführt und gegebenenfalls nachdosiert oder korrigiert. Die Wirksamkeit dieser Anwendung, die eine sehr hohe Patientenzufriedenheit aufweist, beträgt ca. 4-5 Monate, obwohl sie von Person zu Person unterschiedlich ist.</p>\r\n', '', NULL, NULL, NULL, '53f8f361cd66bf74def420220407eyalcinc87b470815b860917bdd', '7', '2022-04-07 15:33:12', NULL, NULL, NULL, '-1'),
('39', '42', '2022-04-07', NULL, 'Dolgu', '<p>Yaşlanma s&uuml;reci ile birlikte y&uuml;z derisi &ouml;zellikle de elmacık kemikleri, &ccedil;ene ve g&ouml;z altı b&ouml;lgesi sıkı ve dolgun g&ouml;r&uuml;n&uuml;ml&uuml; yapısını yitirmektedir. Dolgu uygulamaları ile cilt ve yumuşak dokularda kaybolan hacmi yerine koyarak y&uuml;z&uuml; yeniden bi&ccedil;imlendirmek ve yaşlanma belirtilerinden arındırmak m&uuml;mk&uuml;n olabilmektedir. Dolgu uygulamalarında kullanılan hyal&uuml;ronik asit, insan v&uuml;cudunda doğal olarak bulunan bir maddedir. Dolguların erime s&uuml;resi kullanılan dolgu &uuml;r&uuml;n&uuml;ne ve uygulanan b&ouml;lgeye g&ouml;re değişiklik g&ouml;sterir. Dudak b&ouml;lgesi gibi hareketli alanlarda 8-10 ay kalırken, kemik &uuml;st&uuml;nde 12-18 ay kadar kalıcılık mevcuttur.&nbsp;</p>\r\n\r\n<p>Her tıbbi uygulamada olduğu gibi, hastanın ihtiya&ccedil;larının ve genel sağlık durumunun tespiti sonrasında y&uuml;z b&ouml;lgesinde dolgu uygulamasına gerek duyulan alanlar belirlenmektedir. Dolgu uygulamaları &ouml;ncesinde anestezi kremleri kullanılarak hastanın ağrı duyması tamamen engellenir.</p>\r\n\r\n<p>Dolgu uygulaması olduk&ccedil;a pratik bir medikal m&uuml;dahaledir ve iyileşme s&uuml;reci bulunmamaktadır. Kişi uygulamanın hemen sonrasında yaşamına sorunsuzca geri d&ouml;nebilmektedir ancak uygulama yapılan alanda birka&ccedil; g&uuml;n &ouml;dem olması doğaldır. Bu &ouml;demler, hafif şişkinlikler ve kızarıklıklar ge&ccedil;icidir ve uygulamadan birka&ccedil; g&uuml;n sonra tamamen normale d&ouml;necektir.<br />\r\n&nbsp;</p>\r\n', '', 'Filling', '<p>With the aging process, the skin of the face, especially the cheekbones, chin and under-eye area, loses its tight and full-looking structure. With filler applications, it is possible to reshape the face and remove the signs of aging by replacing the lost volume in the skin and soft tissues. Hyaluronic acid, which is used in filling applications, is a naturally occurring substance in the human body. The melting time of the fillings varies according to the filling product used and the applied area. While it stays for 8-10 months in mobile areas such as the lip area, there is a permanence of 12-18 months on the bone.</p>\r\n\r\n<p>As in every medical practice, after the determination of the patient&#39;s needs and general health status, the areas that need filling application in the face area are determined. Before the filling applications, anesthetic creams are used to completely prevent the patient from feeling pain.</p>\r\n\r\n<p>Filling application is a very practical medical intervention and there is no recovery process. The person can return to his life without any problems immediately after the application, but it is natural to have edema for a few days in the application area. These edemas, mild swellings and redness are temporary and will completely return to normal a few days after the application.</p>\r\n', '', '', '', '', 'حشو', '<p dir=\"rtl\">مع الشيخوخة ، يفقد جلد الوجه ، وخاصة عظام الخد والذقن ومنطقة تحت العين ، هيكله الضيق والممتلئ. من خلال استبدال الحجم المفقود في الجلد والأنسجة الرخوة بتطبيقات الحشو، من الممكن إعادة تهيئة الوجه وتحريره من علامات الشيخوخة. حمض الهيالورونيك ، الذي يستخدم في تطبيقات الحشو ، هو مادة تحدث بشكل طبيعي في جسم الإنسان. يختلف وقت ذوبان الحشوات اعتمادا على منتج الحشو المستخدم والمنطقة المطبقة. هناك دوام من ٨-١٠ أشهر في المناطق المتنقلة مثل منطقة الشفة و ١٢ -١٨&nbsp; شهرا على العظم.&nbsp;</p>\r\n\r\n<p dir=\"rtl\">كما هو الحال في أي ممارسة طبية ، بعد تحديد احتياجات المريض والحالة الصحية العامة ، يتم تحديد المناطق التي تتطلب تطبيق حشو في منطقة الوجه. يمنع المريض تماما من الشعور بالألم باستخدام كريمات التخدير قبل ملء الطلبات. الحشو هو تدخل طبي عملي للغاية ولا توجد عملية شفاء. يمكن للشخص العودة إلى حياته دون مشاكل مباشرة بعد التطبيق، ولكن من الطبيعي أن يكون هناك وذمة في المنطقة التي تم تنفيذ التطبيق لعدة أيام. هذه الوذمة والانتفاخ الطفيف والاحمرار مؤقتة وستعود تماما إلى طبيعتها بعد أيام قليلة من التطبيق.</p>\r\n', '', '', '', '', 'Füllung', '<p>Mit dem Alterungsprozess verliert die Gesichtshaut, insbesondere die Wangenknochen, das Kinn und die Augenpartie, ihre straffe und prall wirkende Struktur. Mit Filler-Anwendungen ist es möglich, das Gesicht neu zu formen und die Zeichen der Hautalterung zu beseitigen, indem das verlorene Volumen in der Haut und im Weichgewebe ersetzt wird. Hyaluronsäure, die in Füllungsanwendungen verwendet wird, ist eine natürlich im menschlichen Körper vorkommende Substanz. Die Schmelzzeit der Füllungen variiert je nach verwendetem Füllprodukt und Anwendungsbereich. Während es in beweglichen Bereichen wie der Lippenpartie 8-10 Monate verbleibt, beträgt die Haltbarkeit am Knochen 12-18 Monate.</p>\r\n\r\n<p>Wie in jeder Arztpraxis werden nach der Feststellung der Bedürfnisse und des allgemeinen Gesundheitszustandes des Patienten die Bereiche bestimmt, die im Gesichtsbereich aufgefüllt werden müssen. Vor den Füllungsanwendungen werden Anästhesiecremes verwendet, um das Schmerzempfinden des Patienten vollständig zu verhindern.</p>\r\n\r\n<p>Die Füllungsanwendung ist ein sehr praktischer medizinischer Eingriff und es gibt keinen Heilungsprozess. Die Person kann sofort nach der Anwendung problemlos in ihr Leben zurückkehren, aber es ist natürlich, dass im Anwendungsbereich für einige Tage Ödeme auftreten. Diese Ödeme, leichten Schwellungen und Rötungen sind vorübergehend und normalisieren sich einige Tage nach der Anwendung vollständig.</p>\r\n', '', NULL, NULL, NULL, 'd736f06edef210a411a120220407eyalcin036755c57063491d3c92', '7', '2022-04-07 15:33:43', NULL, NULL, NULL, '1'),
('40', '42', '2022-04-07', NULL, 'Göz Altı Işık Dolgusu', '<p>Uykusuzluk, genetik etkenler, d&uuml;zensiz beslenme ve stresli hayat estetik sorunları da beraberinde getirir. Bunlardan birisi de g&ouml;z altında yaşanan morluklar ve &ccedil;&ouml;kmelerdir. Bu sorunların tedavisinde g&ouml;z altı ışık dolgusu kullanılır.&nbsp;</p>\r\n\r\n<p>Dolgu uygulamalarında kullanılan hyal&uuml;ronik asit, insan v&uuml;cudunda hali hazırda bulunan doğal bir maddedir. Dolguların erime s&uuml;resi kullanılan dolgu &uuml;r&uuml;n&uuml;ne ve uygulanan b&ouml;lgeye g&ouml;re değişiklik g&ouml;sterir. G&ouml;z altı gibi hareketin alt y&uuml;z b&ouml;lgesine g&ouml;re daha az olduğu b&ouml;lgelerde 12-18 ay kadar kalıcılık mevcuttur. Uygulama &ouml;ncesinde anestezi kremleri kullanılarak hastanın ağrı duyması tamamen engellenir.</p>\r\n\r\n<p>G&ouml;z Altı Işık Dolgusu uygulaması olduk&ccedil;a pratik bir medikal m&uuml;dahaledir ve iyileşme s&uuml;reci bulunmamaktadır. Kişi uygulamanın hemen sonrasında yaşamına sorunsuzca geri d&ouml;nebilmektedir. Uygulama yapılan alanda birka&ccedil; g&uuml;n &ouml;dem olması doğaldır. Bu &ouml;demler, hafif şişkinlikler ve kızarıklıklar ge&ccedil;icidir ve uygulamadan birka&ccedil; g&uuml;n sonra tamamen normale d&ouml;necektir. Bu uygulama diğer dolgu uygulamaların aksine deri altına değil, kemik &uuml;zerine uygulanır.&nbsp;</p>\r\n\r\n<p>G&ouml;z altı dolgu uygulaması iğne ile yapılabildiği gibi kan&uuml;l ile de ger&ccedil;ekleştirilir. Ben hastalarıma g&ouml;z altı dolgu uygulamasını kan&uuml;lle ger&ccedil;ekleştirmekteyim. Kan&uuml;l, dolgu vermede kullanılan ucu k&uuml;nt bir aparattır. &nbsp;G&ouml;z &ccedil;evresi gibi ağrı a&ccedil;ısından hassas ve damar y&ouml;n&uuml;nden zengin bir b&ouml;lgede, g&ouml;z altı parlaklığı istemi ile başvuran hastalara iğne ile yapılan işlemler her zaman değil ama bazen ağrılı olabilir ve damarın iğne ile hasarı sonucu kanamaya bağlı uzun s&uuml;re morluğa neden olabilir. Kan&uuml;l hem ağrı ve acıyı ortadan kaldırır hem de kanama riskini en aza indirir. Tecr&uuml;beli ellerde yapıldığında sıfır kanama ile 5 dakikayı ge&ccedil;meyen bir işlemdir ve işlemden hemen sonra hasta g&uuml;nl&uuml;k rutinine d&ouml;nebilir.&nbsp;</p>\r\n\r\n<p>İşlemden sonra 15 g&uuml;n boyunca bol su t&uuml;ketilmesi &ouml;nerilmektedir. 15 g&uuml;n sonra kontrol amacıyla hasta tekrar değerlendirilir.&nbsp;<br />\r\n&nbsp;</p>\r\n', '', 'Under Eye Light Filling', '<p>Insomnia, genetic factors, irregular diet and stressful life bring along aesthetic problems. One of them is bruises and collapses under the eyes. In the treatment of these problems, under-eye light filling is used.</p>\r\n\r\n<p>Hyaluronic acid, which is used in filling applications, is a natural substance already present in the human body. The melting time of the fillings varies according to the filling product used and the applied area. In areas where the movement is less than the lower face, such as under the eyes, there is a permanence of 12-18 months. Before the application, anesthetic creams are used to completely prevent the patient from feeling pain.</p>\r\n\r\n<p>Under-Eye Light Fill application is a very practical medical intervention and there is no recovery process. The person can return to his/her life without any problem immediately after the application. It is natural to have edema in the treated area for a few days. These edemas, mild swellings and redness are temporary and will completely return to normal a few days after the application. Unlike other filling applications, this application is applied on the bone, not under the skin.</p>\r\n\r\n<p>Under-eye filler can be applied with a needle as well as with a cannula. I perform the under-eye filler application to my patients with a cannula. The cannula is a blunt device used for filling. In an area that is sensitive to pain and rich in blood vessels, such as the area around the eyes, needle procedures may be painful sometimes, but not always, and may cause long-term bruising due to bleeding as a result of needle damage to the patients who apply with the request of under-eye brightness. The cannula both eliminates pain and suffering and minimizes the risk of bleeding. It is a procedure that does not exceed 5 minutes with zero bleeding when performed in experienced hands, and the patient can return to his daily routine immediately after the procedure.</p>\r\n\r\n<p>It is recommended to consume plenty of water for 15 days after the procedure. After 15 days, the patient is re-evaluated for control purposes.</p>\r\n', '', '', '', '', 'حشو الضوء تحت العينين', '<p dir=\"rtl\">الأرق والعوامل الوراثية والنظام الغذائي غير المنتظم والحياة المجهدة تجلب أيضا مشاكل جمالية. واحد منهم هو كدمات وانهيارات تحت العينين. في علاج هذه المشاكل ، يتم استخدام حشو الضوء تحت العينين.&nbsp;</p>\r\n\r\n<p dir=\"rtl\">حمض الهيالورونيك ، الذي يستخدم في تطبيقات الحشو ، هو مادة طبيعية موجودة بالفعل في جسم الإنسان. يختلف وقت ذوبان الحشوات اعتمادا على منتج الحشو المستخدم والمنطقة المطبقة. الثبات متاح لمدة تصل إلى ١٢ -١٨&nbsp; شهرا في المناطق التي تكون فيها الحركة أقل ، مثل تحت العينين ، مقارنة بمنطقة الوجه السفلية. قبل التطبيق ، يتم منع المريض تماما من الشعور بالألم باستخدام كريمات التخدير.&nbsp;</p>\r\n\r\n<p dir=\"rtl\">تطبيق حشو الضوء تحت العينين هو تدخل طبي عملي جدا وليس هناك عملية الشفاء. يمكن للشخص العودة إلى حياته دون مشاكل مباشرة بعد التطبيق. من الطبيعي أن يكون لديك وذمة في المنطقة المطبقة لعدة أيام. هذه الوذمة والانتفاخ الطفيف والاحمرار مؤقتة وستعود تماما إلى طبيعتها بعد أيام قليلة من التطبيق. على عكس تطبيقات الحشو الأخرى ، يتم تطبيق هذا التطبيق على العظام وليس تحت الجلد.</p>\r\n\r\n<p dir=\"rtl\">حشو التطبيق تحت العينين يمكن القيام به مع إبرة ، وكذلك مع قنية. أنا أداء تطبيق حشو تحت العينين مع قنية لمرضاي. قنية هو جهاز حادة العضوية المستخدمة لحشو. قد تكون إجراءات الحقن مؤلمة في بعض الأحيان ، ولكن ليس دائمًا ، للمرضى الذين يتقدمون بطلب للحصول على سطوع تحت العين في منطقة حساسة للألم وغنية بالأوعية الدموية مثل المنطقة حول العينين و قد يسبب كدمات لفترة طويلة بسبب النزيف نتيجة تلف الوعاء الذي يحتوي على الإبرة. قنية على حد سواء يزيل الألم والمعاناة ، ويقلل من خطر النزيف. عندما يقوم بها أشخاص من ذوي الخبرة ، هو إجراء لا يدوم أكثر من ٥ دقائق دون نزيف ، وبعد العملية مباشرة ، يمكن للمريض العودة إلى روتينه اليومي.&nbsp;</p>\r\n\r\n<p dir=\"rtl\">بعد العملية ، يوصى باستهلاك الكثير من الماء لمدة ١٥&nbsp; يوما. بعد ١٥&nbsp; يوما ، يتم إعادة تقييم المريض لأغراض التحكم.</p>\r\n', '', '', '', '', 'Unteraugen Lichtfüllung', '<p>Schlaflosigkeit, genetische Faktoren, unregelmä&szlig;ige Ernährung und ein stressiges Leben bringen ästhetische Probleme mit sich. Einer von ihnen ist Prellungen und kollabiert unter den Augen. Bei der Behandlung dieser Probleme wird eine Unteraugen-Lichtfüllung verwendet.</p>\r\n\r\n<p>Hyaluronsäure, die in Füllungsanwendungen verwendet wird, ist eine natürliche Substanz, die bereits im menschlichen Körper vorhanden ist. Die Schmelzzeit der Füllungen variiert je nach verwendetem Füllprodukt und Anwendungsbereich. In Bereichen, in denen die Bewegung geringer ist als im unteren Gesichtsbereich, z. B. unter den Augen, beträgt die Haltbarkeit 12 bis 18 Monate. Vor der Anwendung werden Anästhesiecremes verwendet, um das Schmerzempfinden des Patienten vollständig zu verhindern.</p>\r\n\r\n<p>Die Anwendung von Unteraugen-Lichtfüllung ist ein sehr praktischer medizinischer Eingriff und es gibt keinen Wiederherstellungsprozess. Unmittelbar nach der Anwendung kann die Person problemlos in ihr Leben zurückkehren. Ödeme im behandelten Bereich für einige Tage sind natürlich. Diese Ödeme, leichten Schwellungen und Rötungen sind vorübergehend und normalisieren sich einige Tage nach der Anwendung vollständig. Im Gegensatz zu anderen Füllungsanwendungen wird diese Anwendung auf den Knochen aufgetragen, nicht unter die Haut.</p>\r\n\r\n<p>Augenfüller können sowohl mit einer Nadel als auch mit einer Kanüle aufgetragen werden. Bei meinen Patienten führe ich die Anwendung des Augenfüllers mit einer Kanüle durch. Die Kanüle ist ein stumpfes Gerät, das zum Füllen verwendet wird. In einem Bereich, der schmerzempfindlich und reich an Blutgefä&szlig;en ist, wie z. B. im Bereich um die Augen, können Nadeleingriffe manchmal, aber nicht immer, schmerzhaft sein und aufgrund von Blutungen infolge von Nadelschäden zu langfristigen Blutergüssen führen die Patienten, die sich mit der Bitte um Helligkeit unter den Augen bewerben. Die Kanüle beseitigt Schmerzen und Leiden und minimiert das Blutungsrisiko. Es handelt sich um einen Eingriff, der 5 Minuten nicht überschreitet, ohne Blutungen, wenn er in erfahrenen Händen durchgeführt wird, und der Patient kann sofort nach dem Eingriff zu seinem Alltag zurückkehren.</p>\r\n\r\n<p>Es wird empfohlen, nach dem Eingriff 15 Tage lang viel Wasser zu sich zu nehmen. Nach 15 Tagen wird der Patient zu Kontrollzwecken erneut untersucht.</p>\r\n', '', NULL, NULL, NULL, '6a8a896bc0f50ef1665820220407eyalcina3cfc363aacfbc03c33f', '7', '2022-04-07 15:35:32', NULL, NULL, NULL, '1'),
('41', '42', '2022-04-07', NULL, 'Mezoterapi', '<p>Mezoterapi işlemi erken yaşlanan dokuyu yeniden canlandıran ve tedavi eden bir y&ouml;ntemdir. G&uuml;nl&uuml;k hayatımızda kullanmış olduğumuz kozmetik &uuml;r&uuml;nleri deri &uuml;zerine uygulanır. Fakat asıl canlandırılması gereken kısım &nbsp;derinin epidermis ile&nbsp;deri&nbsp;altı doku arasında bulunan,&nbsp;bağ dokudan oluşan ve v&uuml;cudu darbelere karşı koruyan <strong>Dermis</strong> katmanıdır. Mezoterapi y&ouml;ntemiyle, &ouml;zel olarak hazırlanan &uuml;r&uuml;nler, &ccedil;ok ince u&ccedil;lu iğnelerle bu b&ouml;lgeye enjeksiyo y&ouml;ntemiyle verilir.<br />\r\n<br />\r\nMezoterapi ;<br />\r\n* Cildin yaşlanmasını yavaşlatmak<br />\r\n* Y&uuml;z&uuml;n yorgun g&ouml;r&uuml;n&uuml;m&uuml;n&uuml; gidermek<br />\r\n* Yaz &ouml;ncesi g&uuml;neş ışınlarının zararlarına karşı &ouml;nlem almak<br />\r\n* Ciltte nem kaybını engellemek<br />\r\n* Elastikiyet kaybını engellemek<br />\r\n* Yaşlanmaya başlamış h&uuml;crelerin yenilenmesini sağlamak i&ccedil;in ve bu sorunların tedavisinde kullanılır.<br />\r\n<br />\r\nİşlem ortalama 5 dk s&uuml;rer ve aynı g&uuml;n normal yaşantınıza devam edebilirsiniz.&nbsp;</p>\r\n', '', 'Mesotherapy', '<p>Mesotherapy is a method that regenerates and treats prematurely aging tissue. Cosmetic products that we use in our daily life are applied on the skin. However, the part that needs to be revitalized is the Dermis layer of the skin, which is located between the epidermis and subcutaneous tissue, consists of connective tissue and protects the body against impacts. With the mesotherapy method, specially prepared products are injected into this area with very fine-tipped needles.</p>\r\n\r\n<p>Mesotherapy ;<br />\r\n* Slowing down skin aging<br />\r\n* Removing the tired look of the face<br />\r\n* To take precautions against the damages of sun rays before summer<br />\r\n* To prevent moisture loss in the skin<br />\r\n* Prevent loss of elasticity<br />\r\n* It is used to regenerate aging cells and to treat these problems.</p>\r\n\r\n<p>The procedure takes 5 minutes on average and you can continue your normal life on the same day.</p>\r\n', '', '', '', '', 'ميزوثيرابي تجديد الوجه', '<p dir=\"rtl\">الميزوثيرابي هو طريقة تجدد وتعالج أنسجة الشيخوخة المبكرة. يتم تطبيق مستحضرات التجميل التي نستخدمها في حياتنا اليومية على الجلد. ولكن الجزء الذي يحتاج حقا إلى تنشيط هو طبقة الأدمة ، والذي يقع بين البشرة والأنسجة من الجلد ، ويتألف من النسيج الضام وحماية الجسم من الضربات. باستخدام طريقة الميزوثيرابي ، يتم حقن المنتجات المعدة خصيصا في هذه المنطقة بإبر رفيعة جدا عن طريق الحقن.&nbsp;</p>\r\n\r\n<p dir=\"rtl\"><strong>الميزوثيرابي</strong></p>\r\n\r\n<p dir=\"rtl\">* إبطاء شيخوخة الجلد</p>\r\n\r\n<p dir=\"rtl\">* إزالة نظرة متعب من الوجه</p>\r\n\r\n<p dir=\"rtl\">* اتخاذ الاحتياطات ضد أضرار أشعة الشمس قبل الصيف</p>\r\n\r\n<p dir=\"rtl\">* منع فقدان الرطوبة على الجلد</p>\r\n\r\n<p dir=\"rtl\">* منع فقدان المرونة</p>\r\n\r\n<p dir=\"rtl\">* يتم استخدامه لتجديد الخلايا الشيخوخة ولعلاج هذه المشاكل.</p>\r\n\r\n<p dir=\"rtl\">تستغرق العملية ٥&nbsp; دقائق في المتوسط ويمكنك مواصلة حياتك الطبيعية في نفس اليوم.</p>\r\n', '', '', '', '', 'Mesotherapie', '<p>Die Mesotherapie ist eine Methode, die vorzeitig alterndes Gewebe regeneriert und behandelt. Kosmetische Produkte, die wir in unserem täglichen Leben verwenden, werden auf die Haut aufgetragen. Was jedoch revitalisiert werden muss, ist die Dermisschicht der Haut, die sich zwischen der Epidermis und dem Unterhautgewebe befindet, aus Bindegewebe besteht und den Körper vor Stö&szlig;en schützt. Bei der Mesotherapie-Methode werden speziell präparierte Produkte mit sehr feinen Nadelspitzen in diesen Bereich injiziert.</p>\r\n\r\n<p>Mesotherapie;<br />\r\n* Verlangsamung der Hautalterung<br />\r\n* Entfernen des müden Aussehens des Gesichts<br />\r\n* Vor dem Sommer Vorkehrungen gegen Schäden durch Sonnenstrahlen treffen<br />\r\n* Um Feuchtigkeitsverlust in der Haut zu verhindern<br />\r\n* Elastizitätsverlust verhindern<br />\r\n* Es wird verwendet, um alternde Zellen zu regenerieren und diese Probleme zu behandeln.</p>\r\n\r\n<p>Der Eingriff dauert durchschnittlich 5 Minuten und Sie können Ihr normales Leben noch am selben Tag fortsetzen.</p>\r\n', '', NULL, NULL, NULL, '2453bed163cf20f55d6520220407eyalcin1713dcdc84005051f94a', '7', '2022-04-07 15:38:06', NULL, NULL, NULL, '-1'),
('42', '42', '2022-04-07', NULL, 'Dudak Dolgusu', '<p>Yaşın ilerlemesiyle birlikte dudaklar hacimlerini kaybedebilirler, bu durum dudaklardaki yağ dokusunun bozulması ve kaybolması sebebiyle ger&ccedil;ekleşir. Bunun yanında dudaklar doğuştan veya başka sebeplerle de ince yapıda olabilir. B&ouml;yle durumlarda dudakların yeniden yapılandırılması, hacim ve g&ouml;r&uuml;n&uuml;rl&uuml;k kazanması i&ccedil;in dudak dolgusu uygulanarak dudaklar daha estetik bir g&ouml;r&uuml;n&uuml;me kavuşturulur. Dudak dolgusuyla kalınlaştırma ve yeniden şekil verme işlemi en &ccedil;ok tercih edilen estetik operasyonlardandır. Dudakların başta burun olmak &uuml;zere y&uuml;z&uuml;n genel hatlarıyla uyumlu hale gelmesi yaşlanma belirtilerini ortadan kaldırır ve etkileyici g&ouml;r&uuml;n&uuml;m sağlar.</p>\r\n\r\n<p>Her tıbbi uygulamada olduğu gibi, hastanın ihtiya&ccedil;larının ve genel sağlık durumunun tespiti sonrasında y&uuml;z b&ouml;lgesinde dolgu uygulamasına gerek duyulan alanlar belirlenmektedir. Dudak dolgusu işlemleri lokal anestezi altında ger&ccedil;ekleşir. Anestezi, işlem sırasında enjeksiyondan kaynaklanabilecek ağrıyı ortadan kaldırmak i&ccedil;in kullanılır.</p>\r\n\r\n<p>Dudak Dolgusu uygulaması olduk&ccedil;a pratik bir medikal m&uuml;dahaledir ve iyileşme s&uuml;reci bulunmamaktadır. Kişi uygulamanın hemen sonrasında yaşamına sorunsuzca geri d&ouml;nebilmektedir ancak uygulama yapılan alanda birka&ccedil; g&uuml;n &ouml;dem olması doğaldır. Bu &ouml;demler, hafif şişkinlikler ve kızarıklıklar ge&ccedil;icidir ve uygulamadan birka&ccedil; g&uuml;n sonra tamamen normale d&ouml;necektir.</p>\r\n', '', 'Lip filler', '<p>With the advancing age, the lips may lose their volume, this is due to the deterioration and loss of the fat tissue in the lips. In addition, the lips may be thin due to congenital or other reasons. In such cases, lips are given a more aesthetic appearance by applying lip augmentation in order to restructure the lips and gain volume and visibility. Thickening and reshaping with lip augmentation is one of the most preferred aesthetic operations. Harmonizing the lips with the general contours of the face, especially the nose, eliminates the signs of aging and provides an impressive appearance.</p>\r\n\r\n<p>As in every medical practice, after the determination of the patient&#39;s needs and general health status, the areas that need filling application in the face area are determined. Lip augmentation procedures are performed under local anesthesia. Anesthesia is used during the procedure to eliminate the pain that may result from the injection.</p>\r\n\r\n<p>Lip Filling application is a very practical medical intervention and there is no recovery process. The person can return to his life without any problems immediately after the application, but it is natural to have edema for a few days in the application area. These edemas, mild swellings and redness are temporary and will completely return to normal a few days after the application.</p>\r\n', '', '', '', '', 'حشو الشفاه', '<p dir=\"rtl\">مع تقدم العمر ، قد تفقد الشفاه حجمها ، وهذا يحدث بسبب تدهور وفقدان الأنسجة الدهنية على الشفاه. بالإضافة إلى ذلك ، يمكن أن تكون الشفاه رقيقة أيضا لأسباب خلقية أو لأسباب أخرى. في مثل هذه الحالات ، يتم استعادة الشفاه إلى مظهر أكثر جمالية من خلال تطبيق حشو الشفاه لإعادة هيكلة الشفاه ، وزيادة الحجم والرؤية. سماكة وإعادة تشكيل مع حشو الشفاه هي واحدة من العمليات الجمالية الأكثر تفضيلا. مواءمة الشفاه مع الخطوط العامة للوجه ، وخاصة الأنف ، ويزيل علامات الشيخوخة ويوفر مظهر مثير للإعجاب.</p>\r\n\r\n<p dir=\"rtl\">كما هو الحال في أي ممارسة طبية ، بعد تحديد احتياجات المريض والحالة الصحية العامة ، يتم تحديد المناطق التي تتطلب تطبيق حشو في منطقة الوجه. تتم إجراءات حشو الشفاه تحت التخدير الموضعي. يستخدم التخدير للقضاء على الألم الذي قد يكون ناجما عن الحقن أثناء العملية.&nbsp;</p>\r\n\r\n<p dir=\"rtl\">تطبيق حشو الشفاه هو تدخل طبي عملي للغاية ولا توجد عملية شفاء. يمكن للشخص العودة إلى حياته دون مشاكل مباشرة بعد التطبيق. من الطبيعي أن يكون لديك وذمة في المنطقة المطبقة لعدة أيام. هذه الوذمة والانتفاخ الطفيف والاحمرار مؤقتة وستعود تماما إلى طبيعتها بعد أيام قليلة من التطبيق.</p>\r\n', '', '', '', '', 'Lippenfüllung', '<p>Mit fortschreitendem Alter können die Lippen an Volumen verlieren, dies ist auf die Verschlechterung und den Verlust des Fettgewebes in den Lippen zurückzuführen. Au&szlig;erdem können die Lippen aus angeborenen oder anderen Gründen dünn sein. In solchen Fällen erhalten die Lippen durch eine Lippenvergrö&szlig;erung ein ästhetischeres Aussehen, um die Lippen neu zu strukturieren und an Volumen und Sichtbarkeit zu gewinnen. Die Verdickung und Umformung mit Lippenvergrö&szlig;erung sind eine der am meisten bevorzugten ästhetischen Operationen. Die Harmonisierung der Lippen mit den allgemeinen Gesichtskonturen,</p>\r\n\r\n<p>insbesondere der Nase, beseitigt die Zeichen der Hautalterung und sorgt für ein beeindruckendes Aussehen.</p>\r\n\r\n<p>Wie in jeder Arztpraxis werden nach der Feststellung der Bedürfnisse und des allgemeinen Gesundheitszustandes des Patienten die Bereiche bestimmt, die im Gesichtsbereich aufgefüllt werden müssen. Lippenvergrö&szlig;erungen werden unter örtlicher Betäubung durchgeführt. Während des Eingriffs wird eine Anästhesie verwendet, um die Schmerzen zu beseitigen, die durch die Injektion entstehen können.</p>\r\n\r\n<p>Die Anwendung der Lippenfüllung ist ein sehr praktischer medizinischer Eingriff und es gibt keinen Wiederherstellungsprozess. Die Person kann sofort nach der Anwendung problemlos in ihr Leben zurückkehren, aber es ist natürlich, dass im Anwendungsbereich für einige Tage Ödeme auftreten. Diese Ödeme, leichten Schwellungen und Rötungen sind vorübergehend und normalisieren sich einige Tage nach der Anwendung vollständig.</p>\r\n', '', NULL, NULL, NULL, '0152e7cfc22ff7a8fc4b20220407eyalcine782761e6bca29913f23', '7', '2022-04-07 15:38:42', NULL, NULL, NULL, '1'),
('43', '42', '2022-04-07', NULL, 'Ameliyatsız Kaş Kaldırma', '<p>Kaş kaldırma, y&uuml;zdeki yorgun bakışları, yıllarca yavaş yavaş ilerleyen sarkmaları ve estetik olmayan g&ouml;r&uuml;n&uuml;m&uuml; d&uuml;zeltmek, daha gen&ccedil; bir bakış ve ifade kazandırmak i&ccedil;in yapılan bir işlemdir.</p>\r\n\r\n<p>Yaşlanma, s&uuml;rekli kas hareketleri, yağ kaybı, yer&ccedil;ekimi, g&uuml;neş hasarı, sigara ve alkol t&uuml;ketimi gibi sebeplerle &ouml;zellikle kaş ve &ccedil;evresindeki y&uuml;z dokusu zarar g&ouml;r&uuml;r. Kaş kaldırma uygulamaları y&uuml;z &ccedil;izgilerinin g&ouml;r&uuml;n&uuml;m&uuml;n&uuml; iyileştirmeye yardımcı olur ve gen&ccedil; bir g&ouml;r&uuml;n&uuml;m kazandırır.</p>\r\n\r\n<p>Ameliyatsız kaş kaldırma işlemi, botulinum toksin, dolgu uygulaması, ip askı y&ouml;ntemlerinin tekli ya da kombine uygulamalarıyla ger&ccedil;ekleştirilebilir. Gen&ccedil; hastalara botulinum toksin uygulaması yeterli gelirken, yaşı ileri ve sarkması fazla olan hastalarda kombine işlemler tercih edilmektedir.&nbsp;</p>\r\n', '', 'Non-Surgical Brow Lift', '<p>Brow lift is a procedure performed to correct the tired look of the face, sagging that has gradually progressed for years, and to correct the unaesthetic appearance, and to give a younger look and expression.</p>\r\n\r\n<p>Especially the eyebrows and the surrounding facial tissue are damaged due to aging, constant muscle movements, fat loss, gravity, sun damage, smoking and alcohol consumption. Brow lift applications help improve the appearance of facial lines and give a youthful appearance.</p>\r\n\r\n<p>Non-surgical eyebrow lifting can be performed with single or combined applications of botulinum toxin, filling application, and rope suspension methods. While botulinum toxin application is sufficient for young patients, combined procedures are preferred in patients with advanced age and sagging.</p>\r\n', '', '', '', '', 'رفع الحاجب بدون جراحة', '<p dir=\"rtl\">رفع الحاجب هو إجراء لتصحيح المظهر المتعب على الوجه والترهل والمظهر غير الجمالي الذي يتقدم ببطء لسنوات عديدة ، لإضفاء مظهر وتعبير أصغر سنا.&nbsp;</p>\r\n\r\n<p dir=\"rtl\">تتلف الحواجب وأنسجة الوجه المحيطة بشكل خاص بسبب الشيخوخة ، وحركات العضلات المستمرة ، وفقدان الدهون ، والجاذبية ، وأضرار أشعة الشمس ، والتدخين واستهلاك الكحول. تساعد تطبيقات رفع الحواجب على تحسين مظهر خطوط الوجه وإعطاء مظهر شبابي.&nbsp;</p>\r\n\r\n<p dir=\"rtl\">يمكن إجراء رفع الحاجب بدون الجراحي باستخدام تطبيقات مفردة أو مجمعة توكسين البوتولينوم ، وتطبيق الحشو ، وطرق الحبل. في حين أن تطبيق توكسين البوتولينوم كاف للمرضى الصغار ، إلا أن الإجراءات المشتركة مفضلة في المرضى الذين يعانون من تقدم العمر والترهل المفرط.</p>\r\n', '', '', '', '', 'Nicht-chirurgisches Augenbrauenlifting', '<p>Das Augenbrauenlifting ist ein Verfahren, das durchgeführt wird, um das müde Aussehen des Gesichts, die seit Jahren allmählich fortschreitende Erschlaffung und das unästhetische Erscheinungsbild zu korrigieren und ein jüngeres Aussehen und einen jüngeren Ausdruck zu verleihen.</p>\r\n\r\n<p>Besonders die Augenbrauen und das umliegende Gesichtsgewebe werden durch Alterung, ständige Muskelbewegungen, Fettabbau, Schwerkraft, Sonnenschäden, Rauchen und Alkoholkonsum geschädigt. Augenbrauenlifting Anwendungen helfen, das Erscheinungsbild von Gesichtslinien zu verbessern und ein jugendliches Aussehen zu verleihen.</p>\r\n\r\n<p>Das nicht-chirurgische Augenbrauenlifting kann mit einzelnen oder kombinierten Anwendungen von Botulinumtoxin, Füllungsanwendung und Seilaufhängungsmethoden durchgeführt werden. Während bei jungen Patienten die Gabe von Botulinumtoxin ausreicht, werden kombinierte Verfahren bei Patienten mit fortgeschrittenem Alter und Erschlaffung bevorzugt.</p>\r\n', '', NULL, NULL, NULL, '10b34e03c5184005e8d120220407eyalcin865cad71ceb1737227d3', '7', '2022-04-07 15:39:16', NULL, NULL, NULL, '1'),
('44', '42', '2022-04-07', NULL, 'Botoks ile Kaş Kaldırma', '<p>Ameliyatsız kaş kaldırma y&ouml;ntemlerinden biri botoks ile kaş kaldırmadır. Hastanın y&uuml;z&uuml;n&uuml;n genel yapısına uyumlu bir kaş şekli planlandıktan sonra dolgu uygulanarak kaş y&uuml;zde en uygun pozisyona &ccedil;ekilir ve daha sağlıklı ve gen&ccedil; bir g&ouml;r&uuml;n&uuml;m elde edilir.&nbsp;</p>\r\n\r\n<p>Bu işlem yaklaşık 1 dakika s&uuml;rer. İşlemin etkileri 4 ila 5 g&uuml;n sonra belli olur ve 5 ila 6 ay etki g&ouml;sterir.</p>\r\n', '', 'Brow Lift with Botox', '<p>One of the non-surgical eyebrow lifting methods is eyebrow lifting with botox. After planning an eyebrow shape that is compatible with the general structure of the patient&#39;s face, filling is applied and the eyebrow is pulled to the most suitable position on the face and a healthier and younger appearance is obtained.</p>\r\n\r\n<p>This process takes about 1 minute. The effects of the procedure become apparent after 4 to 5 days and take effect for 5 to 6 months.</p>\r\n', '', '', '', '', 'رفع الحاجب مع البوتوكس', '<p dir=\"rtl\">واحدة من طرق رفع الحاجب بدون الجراحي هو رفع الحاجب مع البوتوكس. بعد التخطيط لشكل الحاجب المتوافق مع الهيكل العام لوجه المريض ، يتم وضع الحشوة وسحب الحاجب إلى الوضع الأنسب على الوجه والحصول على مظهر أكثر صحة وشبابا.&nbsp;</p>\r\n\r\n<p dir=\"rtl\">تستغرق هذه العملية حوالي ١&nbsp; دقيقة. تصبح آثار الإجراء واضحة بعد ٤&nbsp; إلى ٥&nbsp; أيام ويكون لها تأثير لمدة ٥&nbsp; إلى ٦&nbsp; أشهر.</p>\r\n', '', '', '', '', 'Stirnlifting mit Botox', '<p>Eine der nicht-chirurgischen Methoden des Augenbrauenliftings ist das Augenbrauenlifting mit Botox. Nach der Planung einer Augenbrauenform, die mit der allgemeinen Gesichtsstruktur des Patienten kompatibel ist, wird die Füllung aufgetragen und die Augenbraue an die am besten geeignete Position im Gesicht gezogen, wodurch ein gesünderes und jüngeres Aussehen erzielt wird. Dieser Vorgang dauert ca. 1 Minute. Die Wirkung des Verfahrens zeigt sich nach 4 bis 5 Tagen und hält 5 bis 6 Monate an.</p>\r\n', '', NULL, NULL, NULL, 'd6c476d468d35dab3e9320220407eyalcin1d472afbd8d092eed5d1', '7', '2022-04-07 15:41:53', NULL, NULL, NULL, '-1'),
('45', '42', '2022-04-07', NULL, 'Dolgu ile Kaş Kaldırma', '<p>Ameliyatsız kaş kaldırma y&ouml;ntemlerinden bir diğeri dolgu ile yapılmaktadır. Kaş altına ve şakağa uygulanan dolgu uygulamaları ile kaşta istenen kalkıklık elde edilebilir. 35-45 yaş arasında sık tercih edilen kaş kaldırma y&ouml;ntemlerinden biridir ve sıklıkla botulinum toksin uygulamaları ile komine edilir.&nbsp;</p>\r\n\r\n<p>İşlemin s&uuml;resi ortalama 2 dakikadır. İşlemin etkisi işlemden hemen sonra g&ouml;r&uuml;l&uuml;r ve etkisi 1 yıl s&uuml;rer.</p>\r\n', '', 'Eyebrow Lift with Fillers', '<p>Another non-surgical eyebrow lifting method is done with filling. With the filling applications applied under the eyebrows and temples, the desired lift in the eyebrows can be achieved. It is one of the most preferred eyebrow lifting methods between the ages of 35-45 and is often combined with botulinum toxin applications.</p>\r\n\r\n<p>The duration of the procedure is on average 2 minutes. The effect of the procedure is seen immediately after the procedure and the effect lasts for 1 year.</p>\r\n', '', '', '', '', 'رفع الحاجب مع حشو', '<p dir=\"rtl\">يتم إجراء آخر من طرق إزالة الحاجب بدون الجراحية باستخدام حشو. يمكن تحقيق الرفع المطلوب للحاجب من خلال تطبيقات الحشو المطبقة تحت الحاجب والمعبد. إنها واحدة من أكثر طرق رفع الحاجب المفضلة بين سن ٣٥ -٤٥&nbsp; وغالبًا ما يتم دمجها مع تطبيقات توكسين البوتولينوم.</p>\r\n\r\n<p dir=\"rtl\">مدة الإجراء في المتوسط دقيقتين. لوحظ تأثير الإجراء مباشرة بعد الإجراء ، ويستمر تأثيره لمدة عام.&nbsp;</p>\r\n', '', '', '', '', 'Brauen Lifting mit Filler', '<p>Eine weitere nicht-chirurgische Methode zum Anheben der Augenbrauen ist das Füllen. Mit den unter den Augenbrauen und Schläfen aufgetragenen Füllung-Applikationen lässt sich das gewünschte Lifting der Augenbrauen erzielen. Es ist eine der beliebtesten</p>\r\n\r\n<p>Augenbrauenlifting-Methoden im Alter zwischen 35 und 45 Jahren und wird oft mit Botulinumtoxin-Anwendungen kombiniert.</p>\r\n\r\n<p>Die Dauer des Verfahrens beträgt durchschnittlich 2 Minuten. Die Wirkung des Eingriffs ist unmittelbar nach dem Eingriff sichtbar und hält 1 Jahr an.</p>\r\n', '', NULL, NULL, NULL, 'e386878b91a430e8d65920220407eyalcin9bbc383f35806b891ed8', '7', '2022-04-07 15:43:42', NULL, NULL, NULL, '1'),
('46', '42', '2022-04-07', NULL, 'İple Kaş Kaldırma', '<p>Bir diğer kaş kaldırma y&ouml;ntemi ise iple kaş kaldırmadır. Bu y&ouml;ntemde sa&ccedil; &ccedil;izgisinin hemen altından kesi yapılmaksızın kıl&ccedil;ıklı ipler ge&ccedil;irilir.&nbsp; Bazen de kaşın hemen bitiminden ipler yerleştirilebilir. Hekiminiz size en uygun yaklaşım y&ouml;ntemini değerlendirdikten sonra işlemi ger&ccedil;ekleştirir. İşlem s&uuml;resi 15 dakikadır. Bu y&ouml;ntemde iyileşme s&uuml;reci olduk&ccedil;a kısadır, hasta 1-2 g&uuml;n i&ccedil;erisinde normal yaşantısına d&ouml;nebilir ve kullanılan iplerin &ouml;mr&uuml;ne g&ouml;re uygulama 6 &ndash; 24 ay arası etki g&ouml;sterir.</p>\r\n', '', 'Eyebrow Thread Lift', '<p>Another eyebrow lifting method is eyebrow lifting with thread. In this method, awn threads are passed just below the hairline without making an incision. Sometimes threads can be placed just from the end of the eyebrow. Your doctor will perform the procedure after evaluating the most appropriate approach for you. Processing time is 15 minutes. In this method, the recovery period is very short, the patient can return to his normal life within 1-2 days, and the application takes between 6 and 24 months, depending on the life of the threads used.</p>\r\n', '', '', '', '', 'رفع الحاجب بحبل', '<p dir=\"rtl\">طريقة أخرى لرفع الحاجب هي رفع الحاجب بحبل. في هذه الطريقة ، يتم تمرير خيوط عون تحت خط الشعر دون قطع الجلد. في بعض الأحيان يمكن وضع خيوط قبل نهاية ذيل الحاجب. سيقوم طبيبك بإجراء العملية بعد تقييم طريقة النهج الأنسب لك. وقت المعالجة هو ١٥ دقيقة. في هذه الطريقة ، عملية الشفاء قصيرة جدا ، يمكن للمريض العودة إلى الحياة الطبيعية في غضون ١ -٢&nbsp; أيام ، ويظهر التطبيق تأثير بين ٦&nbsp; و ٢٤&nbsp; شهرا وفقا لحياة الحبال المستخدمة.&nbsp;</p>\r\n', '', '', '', '', 'Augenbrauenlifting mit Faden', '<p>Eine weitere Methode zum Augenbrauenlifting ist das Augenbrauenlifting mit Faden. Bei dieser Methode werden Grannen Fäden direkt unter dem Haaransatz geführt, ohne einen Schnitt zu machen. Manchmal können Fäden direkt am Ende der Augenbraue platziert werden. Ihr Arzt wird das Verfahren durchführen, nachdem er den für Sie am besten geeigneten Ansatz bewertet hat. Die Bearbeitungszeit beträgt 15 Minuten. Bei dieser Methode ist die Erholungszeit sehr kurz, der Patient kann innerhalb von 1-2 Tagen in sein normales Leben zurückkehren und die Anwendung dauert je nach Lebensdauer der verwendeten Fäden zwischen 6 und 24 Monaten.</p>\r\n', '', NULL, NULL, NULL, '062f22ecd38e8e9378e020220407eyalcinf6c24a77cb3b9838588d', '7', '2022-04-07 15:44:37', NULL, NULL, NULL, '1'),
('47', '42', '2022-04-07', NULL, 'Migren Tedavisi', '<p>G&uuml;n&uuml;m&uuml;z d&uuml;nyasının en yaygın hastalıklarından biri de hi&ccedil; ş&uuml;phesiz ki migren rahatsızlığıdır. Halk arasında kronik baş ağrısı olarak da bilinen migren, baş b&ouml;lgesinde yaşanılan ağrı, sancı ve baskıların s&uuml;rekli olarak devam etmesi sonrası ortaya &ccedil;ıkar. Migren bireyin hayatını ciddi &ouml;l&ccedil;&uuml;de olumsuz etkilemekle birlikte y&uuml;ksek derecede ila&ccedil; kullanımına da y&ouml;nlendirir. Migrenin oluşum nedenleri ise beyindeki bazı damarların gevşemesi ve kasılması şeklinde tanımlanabilmektedir. Migren sebebiyle ortaya &ccedil;ıkan ağrı ve acının yanı sıra ila&ccedil;ların zararlı yan etkilerinden ve ağrılardan kurtulmak isteyen hastaların bu sorunları ameliyatsız migren tedavisi ile giderilebilmektedir.&nbsp;</p>\r\n\r\n<p>Ameliyatsız migren tedavisi uygulaması sayesinde yapılan birka&ccedil; enjeksiyon işlemi ile ameliyatsız, kesisiz ve dikişsiz bir şekilde migren hastalığından kurtulmak m&uuml;mk&uuml;nd&uuml;r. Bu y&ouml;nteminin başarıya ulaşmasında en &ouml;nemli detay ise uygun dozun en doğru yerlere enjekte edilmesidir. Migren tedavisinde ağrı mezoterapisinde kullanılan mezoterap&ouml;tik karışımlardan faydalanabildiği gibi botulinum toksin uygulaması da faydalı olmaktadır. Kendi pratiğimde her iki tedavi protokol&uuml;n&uuml; de uygulamakla birlikte &ouml;zellikle botulinum toksin tedavisini daha sıklıkla yapmaktayım. Amerikan gıda ve ila&ccedil; dairesi (FDA) tarafından &ouml;nerilen 31 nokta botulinum toksin protokol&uuml;n&uuml; kliniğimizde uygulamaktayız. Bu uygulama &ouml;zellikle yurt dışından gelen hastalarımız tarafından da sıklıkla talep edilmektedir. Uygulama sonrasında ağrılar ortalama 3 g&uuml;n i&ccedil;erisinde azalmakla ve hasta ağrılardan 5 ila 6 ay kadar kurtulmaktadır.</p>\r\n', '', 'Migraine Treatment', '<p>One of the most common diseases in today&#39;s world is undoubtedly migraine. Migraine, also known as chronic headache among the people, occurs after the pain, aches and pressures in the head region continue. Migraine affects the life of the individual seriously, but also leads to high level of drug use. The causes of migraine can be defined as the relaxation and contraction of some vessels in the brain. These problems of patients who want to get rid of the pain and pain caused by migraine, as well as the harmful side effects of drugs and pain, can be eliminated with migraine treatment without surgery.</p>\r\n\r\n<p>Thanks to the non-surgical migraine treatment application, it is possible to get rid of migraine disease without surgery, incision and stitches with a few injections. The most important detail in the success of this method is to inject the appropriate dose into the most accurate places. In the treatment of migraine, mesotherapeutic mixtures used in pain mesotherapy can benefit, as well as botulinum toxin application. Although I apply both treatment protocols in my own practice, I especially do botulinum toxin treatment more frequently. We apply the 31 point botulinum toxin protocol recommended by the American Food and Drug Administration (FDA) in our clinic. This application is also frequently requested by our patients coming from abroad. After the application, the pain decreases within 3 days on average and the patient gets rid of the pain for 5 to 6 months.</p>\r\n', '', '', '', '', 'علاج الصداع النصفي', '<p dir=\"rtl\">واحدة من أكثر الأمراض شيوعا في العالم الحديث هو بلا شك الصداع النصفي. يحدث الصداع النصفي ، المعروف أيضًا باسم الصداع المزمن بين الناس ، بعد استمرار الألم والأوجاع والضغوط في منطقة الرأس بشكل مستمر. على الرغم من أن الصداع النصفي يؤثر سلبا على حياة الفرد بشكل خطير، إلا أنه يؤدي أيضا إلى درجة عالية من دواء. يمكن تعريف أسباب الصداع النصفي على أنها استرخاء وتقلص بعض الأوعية في الدماغ. بالإضافة إلى الألم الناجم عن الصداع النصفي ، يمكن القضاء على هذه المشاكل للمرضى الذين يرغبون في التخلص من الآثار الجانبية الضارة وآلام الأدوية عن طريق علاج الصداع النصفي غير الجراحي.&nbsp;</p>\r\n\r\n<p dir=\"rtl\">بفضل تطبيق علاج الصداع النصفي دون جراحة ، فمن الممكن للتخلص من الصداع النصفي دون جراحة ، دون تخفيضات ودون طبقات مع العديد من إجراءات الحقن. أهم التفاصيل في تحقيق نجاح هذه الطريقة هي أن الجرعة المناسبة يتم حقنها في الأماكن الصحيحة. تستخدم مخاليط الميزوثيرابيوتيك المستخدمة في علاج الميزوثيرابي للألم لعلاج الصداع النصفي ، كما أن تطبيق توكسين البوتولينوم مفيد أيضا. على الرغم من أنني أتابع كلا بروتوكولات العلاج في ممارستي الخاصة ، إلا أنني أقوم بعلاج توكسين البوتولينوم في كثير من الأحيان. نحن نطبق بروتوكول توكسين البوتولينوم ٣١&nbsp; نقطة الموصى به من قبل إدارة الغذاء والدواء الأمريكية في عيادتنا. غالبا ما يطلب مرضانا هذا التطبيق ، خاصة من الخارج. بعد التطبيق ، تنخفض الآلام في المتوسط في غضون ٣&nbsp; أيام ، ويتخلص المريض من الآلام لمدة ٥&nbsp; إلى ٦&nbsp; أشهر.&nbsp;</p>\r\n', '', '', '', '', 'Migräne-Behandlung', '<p>Eine der häufigsten Krankheiten in der heutigen Welt ist zweifellos Migräne. Migräne, bei den Menschen auch als chronischer Kopfschmerz bekannt, tritt auf, nachdem die Schmerzen, Schmerzen und Druckgefühle in der Kopfregion anhalten. Migräne beeinträchtigt das Leben des Einzelnen ernsthaft, führt aber auch zu einem hohen Drogenkonsum. Die Ursachen der Migräne können als Entspannung und Kontraktion einiger Gefä&szlig;e im Gehirn definiert werden. Diese Probleme von Patienten, die die durch Migräne verursachten Schmerzen und Schmerzen sowie die schädlichen Nebenwirkungen von Medikamenten und Schmerzen loswerden möchten, können mit einer Migränebehandlung ohne Operation beseitigt werden.</p>\r\n\r\n<p>Dank der nicht-chirurgischen Anwendung der Migränebehandlung ist es möglich, die Migräne ohne Operation, Schnitt und Stiche mit wenigen Injektionen loszuwerden. Das wichtigste Detail für den Erfolg dieser Methode besteht darin, die richtige Dosis an den genauesten Stellen zu injizieren. Bei der Behandlung von Migräne können mesotherapeutische Mischungen, die in der Schmerzmesotherapie verwendet werden, sowie die Anwendung von Botulinumtoxin von Nutzen sein. Obwohl ich beide Behandlungsprotokolle in meiner eigenen Praxis anwende, mache ich vor allem Botulinumtoxin-Behandlungen häufiger. Wir wenden in unserer Klinik das von der amerikanischen Food and Drug Administration (FDA) empfohlene 31-Punkte-Botulinumtoxin-Protokoll an. Diese Anwendung wird auch häufig von unseren Patienten aus dem Ausland nachgefragt. Nach der Anwendung lässt der Schmerz im Durchschnitt innerhalb von 3 Tagen nach und der Patient wird die Schmerzen für 5 bis 6 Monate los.</p>\r\n', '', NULL, NULL, NULL, '3bfa8f1ef1049e5b0fe920220407eyalcinea8d3e1bf56e2665aae0', '7', '2022-04-07 15:45:14', NULL, NULL, NULL, '1'),
('48', '42', '2022-05-30', NULL, 'Yüz Mezoterapisi', '<p>Mezoterapi işlemi erken yaşlanan dokuyu yeniden canlandıran ve tedavi eden bir y&ouml;ntemdir. G&uuml;nl&uuml;k hayatımızda kullanmış olduğumuz kozmetik &uuml;r&uuml;nleri deri &uuml;zerine uygulanır. Fakat asıl canlandırılması gereken kısım &nbsp;derinin epidermis ile deri altı doku arasında bulunan, bağ dokudan oluşan ve v&uuml;cudu darbelere karşı koruyan Dermis katmanıdır. Mezoterapi y&ouml;ntemiyle, &ouml;zel olarak hazırlanan &uuml;r&uuml;nler, &ccedil;ok ince u&ccedil;lu iğnelerle bu b&ouml;lgeye enjeksiyon y&ouml;ntemiyle verilir.&nbsp;</p>\r\n\r\n<p>Mezoterapi ;<br />\r\n* Cildin yaşlanmasını yavaşlatmak<br />\r\n* Y&uuml;z&uuml;n yorgun g&ouml;r&uuml;n&uuml;m&uuml;n&uuml; gidermek<br />\r\n* Yaz &ouml;ncesi g&uuml;neş ışınlarının zararlarına karşı &ouml;nlem almak<br />\r\n* Ciltte nem kaybını engellemek<br />\r\n* Elastikiyet kaybını engellemek<br />\r\n* Yaşlanmaya başlamış h&uuml;crelerin yenilenmesini sağlamak i&ccedil;in ve bu sorunların tedavisinde kullanılır.&nbsp;</p>\r\n\r\n<p>İşlem ortalama 5 dk s&uuml;rer ve aynı g&uuml;n normal yaşantınıza devam edebilirsiniz.&nbsp;<br />\r\n&nbsp;</p>\r\n', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', NULL, NULL, NULL, 'e0fcc3f35e0507dd894820220530eyalcina17d5332f658b66e47e0', '7', '2022-05-30 19:10:34', NULL, NULL, NULL, '-1'),
('49', '42', '2022-05-30', NULL, 'Gıdı Liposuction', '<p>Gıdı b&ouml;lgesi &ccedil;ene altında kalan boyun &uuml;st kısmında bulunan yağ dokusudur. Bu doku başın aşağı ve &ouml;ne doğru hareketinde olduk&ccedil;a belirgin hale gelmektedir. Yaşa ve genetik fakt&ouml;rlere bağlı olarak gıdı b&ouml;lgesinde sarkma olabilir. &nbsp;Bazen yaştan bağımsız olarak fazla kiloya bağlı olarak ya da ani kilo kayıplarında da &nbsp;gıdı sarkması g&ouml;r&uuml;lebilir. Gıdı b&ouml;lgesindeki fazla yağ dokusu &ccedil;ene hattının belirgin olmaması, &ccedil;ift &ccedil;ene g&ouml;r&uuml;n&uuml;m&uuml;, kalın boyun g&ouml;r&uuml;n&uuml;m&uuml; ve hatları belirsiz &ccedil;ene g&ouml;r&uuml;n&uuml;m&uuml; gibi sorunlara yol a&ccedil;abilmektedir.&nbsp;</p>\r\n\r\n<p>Gıdı Liposution, boyun b&ouml;lgesindeki fazla yağların alınıp gevşek derinin toplanmasıyla t&uuml;m bu sorunların &ccedil;&ouml;z&uuml;m&uuml; olan bir estetik cerrahi operasyondur. Operasyon, hastanın ihtiya&ccedil;larına g&ouml;re lokal anestezi veya genel anestezi altında ger&ccedil;ekleştirilebilir. Anesteziden sonra, iz bırakmayan kan&uuml;llerle &ccedil;ene altında k&uuml;&ccedil;&uuml;k kesiler meydana getirilir ve fazla yağlar t&uuml;p ile &ccedil;ekilir. Operasyon 30 ila 60 dakika s&uuml;rebilir. Operasyon sonrası kesiler dikiş ve bandajlarla kapatılır, kısa bir s&uuml;re (gıdı maskesi) kullanılarak &ccedil;ene b&ouml;lgesi desteklenir. Hasta operasyondan sonra aynı g&uuml;n i&ccedil;erisinde taburcu edilir. Hastanın tamamen iyileşmesi 2 haftaya kadar s&uuml;rebilir.</p>\r\n', '', 'Tickle Liposuction', '<p>The jowl area is the adipose tissue in the upper part of the neck under the chin. This tissue becomes quite evident when the head moves downwards and forwards. There may be sagging in the jowl area depending on age and genetic factors. Sometimes, regardless of age, chin sagging can also be seen due to excess weight or sudden weight loss. Excess fat tissue in the jowl area can cause problems such as indistinct chin line, double chin appearance, thick neck appearance and chin appearance with unclear lines.</p>\r\n\r\n<p>Tickle Liposuction is an aesthetic surgery operation that solves all these problems by removing excess fat from the neck area and collecting loose skin. The operation can be performed under local anesthesia or general anesthesia according to the needs of the patient. After anesthesia, small incisions are made under the chin with non-marking cannulas and excess fat is removed with a tube. The operation may take 30 to 60 minutes. After the operation, the incisions are closed with stitches and bandages, and the chin area is supported for a short time (a tickle mask). The patient is discharged on the same day after the operation. It may take up to 2 weeks for the patient to fully recover.</p>\r\n', '', '', '', '', 'شفط دهون الذقن', '<p dir=\"rtl\">هي الأنسجة الدهنية الموجودة في الجزء العلوي من الرقبة ، والتي تقع تحت الذقن. يصبح هذا النسيج ملحوظا جدا في حركة الرأس لأسفل وإلى الأمام. قد يكون هناك ترهل في منطقة ذقن اعتمادا على العمر والعوامل الوراثية. في بعض الأحيان ، بغض النظر عن العمر ، بسبب الوزن الزائد ، أو فقدان الوزن المفاجئ ، قد يحدث في ذقن أيضا. يمكن أن تسبب الأنسجة الدهنية الزائدة في منطقة الذقن مشاكل مثل خط الذقن غير الواضح ، ومظهر الذقن المزدوج ، ومظهر الرقبة السميك ومظهر الذقن مع خطوط غير واضحة.&nbsp;</p>\r\n\r\n<p dir=\"rtl\">شفط دهون الذقن هو عملية جراحية تجميلية هي الحل لجميع هذه المشاكل عن طريق إزالة الدهون الزائدة في منطقة الرقبة وجمع الجلد المترهل. يمكن إجراء العملية تحت التخدير الموضعي أو التخدير العام ، حسب احتياجات المريض. بعد التخدير ، يتم إجراء شقوق صغيرة تحت الفك مع قنية لا تترك أي آثار ، ويتم إزالة الدهون الزائدة مع أنبوب. قد تستغرق العملية من ٣٠ إلى ٦٠ دقيقة. بعد العملية ، يتم إغلاق الشقوق مع غرز والضمادات ، ويدعم منطقة الفك باستخدام وقت قصير قناع ذقن. يتم تفريغ المريض في نفس اليوم بعد العملية. قد يستغرق الأمر أسبوعين حتى يتعافى المريض تماما.</p>\r\n', '', '', '', '', 'Kitzel-Fettabsaugung', '<p>Der Wangenbereich ist das Fettgewebe im oberen Teil des Halses unter dem Kinn. Dieses Gewebe wird deutlich, wenn es sich verkehrt herum und vorw&auml;rts bewegt. Je nach Alter und genetischen Faktoren kann es im Wangenbereich zu einem Durchh&auml;ngen kommen. Manchmal, unabh&auml;ngig vom Alter, kann ein H&auml;ngebacken auch aufgrund von &Uuml;bergewicht oder pl&ouml;tzlichem Gewichtsverlust auftreten. &Uuml;bersch&uuml;ssiges Fettgewebe im Wangenbereich kann Probleme wie eine undeutliche Kinnlinie, ein Doppelkinn, einen dicken Hals und ein Kinn mit unklaren Linien verursachen.</p>\r\n\r\n<p>Die Kitzel-Liposuktion ist eine Operation der &auml;sthetischen Chirurgie, die all diese Probleme l&ouml;st, indem &uuml;bersch&uuml;ssiges Fett aus dem Halsbereich entfernt und lose Haut gesammelt wird. Die Operation kann je nach Bedarf des Patienten in &ouml;rtlicher Bet&auml;ubung oder Vollnarkose durchgef&uuml;hrt werden. Nach der An&auml;sthesie werden mit nicht abf&auml;rbenden Kan&uuml;len kleine Schnitte unter dem Kinn gesetzt und &uuml;bersch&uuml;ssiges Fett mit einer Sonde entfernt. Die Operation kann 30 bis 60 Minuten dauern. Nach der Operation werden die Schnitte mit N&auml;hten und Verb&auml;nden verschlossen und der Kinnbereich kurzzeitig gest&uuml;tzt (Kittelmaske). Der Patient wird am selben Tag nach der Operation entlassen. Es kann bis zu 2 Wochen dauern, bis sich der Patient vollst&auml;ndig erholt hat.</p>\r\n', '', NULL, NULL, NULL, '6f62d1b3cdcccba53e9320220530eyalcin54d464393776313c1d25', '7', '2022-05-30 19:14:11', NULL, NULL, NULL, '1'),
('50', '42', '2022-05-30', NULL, 'Çene Estetiği ( Mentoplasti )', '<p>Mentoplasti, &ccedil;enenin y&uuml;z&uuml;n geri kalanıyla daha uyumlu hale getirilmesi amacıyla uygulanan bir cerrahi işlemdir. Operayon; &ccedil;enesini b&uuml;y&uuml;tmek isteyen hastaların implantla veya v&uuml;cudun başka bir yerinden alınan dokularla &ccedil;enesinin b&uuml;y&uuml;t&uuml;lmesi, şekil bozukluğu olan hastaların ise &ccedil;ene konumunun d&uuml;zeltilmesi veya &ccedil;enesinin t&ouml;rp&uuml;lenmesi şeklinde ger&ccedil;ekleştirilir. Mentoplasti işlemleri gıdı, boyun ve y&uuml;z germe gibi y&uuml;z ve v&uuml;cut estetikleri ile birlikte ger&ccedil;ekleştirilebilir. &nbsp;</p>\r\n\r\n<p>Operasyon lokal veya genel anestezi altında ger&ccedil;ekleştirilir, &ccedil;enenin durumuna ve uygulanacak işleme bağlı olarak, 30 dakika ila 3 saat s&uuml;rebilir. Operasyon sırasında eğer gerekirse &ccedil;ene altından veya ağız i&ccedil;erisinde kesiler yapılabilir, bu kesiler iz bırakmaz. &nbsp;Hasta işlemin ağırlığına bağlı olarak aynı g&uuml;n taburcu olabilir. Yapılan kesiler ve &ccedil;enedeki şişlikler 1-2 hafta i&ccedil;erisinde tamamen iyileşir.&nbsp;</p>\r\n', '', 'Jaw Aesthetics ( Mentoplasty )', '<p>Mentoplasty is a surgical procedure applied to make the chin more compatible with the rest of the face. operation; It is performed by enlarging the chin of patients who want to enlarge their chin with implants or tissues taken from another part of the body, and by correcting the chin position or filing the chin of patients with deformities. Mentoplasty procedures can be performed together with face and body aesthetics such as jowl, neck and face lift.</p>\r\n\r\n<p>The operation is performed under local or general anesthesia, depending on the condition of the jaw and the procedure to be performed, it can take from 30 minutes to 3 hours. During the operation, if necessary, incisions can be made under the chin or in the mouth, these incisions do not leave any traces. Depending on the severity of the procedure, the patient can be discharged on the same day. The incisions and swellings on the chin heal completely within 1-2 weeks.</p>\r\n', '', '', '', '', 'تجميل الفك (مينتوبلاستي)', '<p dir=\"rtl\">مينتوبلاستي هو إجراء جراحي يتم إجراؤه لجعل الذقن أكثر انسجاما مع بقية الوجه. عملية؛ يتم إجراؤه عن طريق تكبير ذقن المرضى الذين يرغبون في تكبير ذقنهم بواسطة غرسات أو أنسجة مأخوذة من جزء آخر من الجسم ، وبتصحيح وضع الذقن أو برد ذقن المرضى الذين يعانون من تشوهات. يمكن إجراء إجراءات مينتوبلاستي جنبا إلى جنب مع جماليات الوجه والجسم مثل ذقن والرقبة وشد الوجه.&nbsp;</p>\r\n\r\n<p dir=\"rtl\">يتم تنفيذ العملية تحت التخدير الموضعي أو العام ، اعتمادا على حالة الفك والإجراء الذي يتعين القيام به ، يمكن أن يستغرق من ٣٠&nbsp; دقيقة إلى ٣&nbsp; ساعات. خلال العملية ، إذا لزم الأمر ، يمكن إجراء شقوق تحت الذقن أو في الفم، وهذه الشقوق لا تترك آثار. قد يتم تفريغ المريض في نفس اليوم اعتمادا على حالة الإجراء. الشقوق التي تم إجراؤها والتورم في الفك تلتئم تماما في غضون أسبوع أو أسبوعين.</p>\r\n', '', '', '', '', 'Kinnästhetik (Mentoplastik)', '<p>Die Mentoplastik ist ein chirurgischer Eingriff, der angewendet wird, um das Kinn mit dem Rest des Gesichts besser kompatibel zu machen. Patienten, die ihr Kinn vergr&ouml;&szlig;ern m&ouml;chten, k&ouml;nnen mit Implantaten oder Gewebe, das aus einem anderen K&ouml;rperteil entnommen wird, vergr&ouml;&szlig;ert werden. Bei Patienten mit Deformit&auml;t wird sie durch Korrektur der Kinnposition oder Feilen des Kinns durchgef&uuml;hrt. Mentoplastik-Verfahren k&ouml;nnen zusammen mit Gesichts- und K&ouml;rper&auml;sthetik wie Wangen-, Hals- und Facelifting durchgef&uuml;hrt werden.</p>\r\n\r\n<p>Die Operation wird unter &ouml;rtlicher Bet&auml;ubung oder Vollnarkose durchgef&uuml;hrt. Je nach Zustand des Kiefers und dem durchzuf&uuml;hrenden Eingriff kann es zwischen 30 Minuten und 3 Stunden dauern. W&auml;hrend der Operation k&ouml;nnen bei Bedarf Schnitte unter dem Kinn oder im Mund vorgenommen werden, diese Schnitte hinterlassen keine Spuren. Je nach Schwere des Eingriffs kann der Patient noch am selben Tag entlassen werden. Die Schnitte und Schwellungen am Kinn heilen innerhalb von 1-2 Wochen vollst&auml;ndig ab.</p>\r\n', '', NULL, NULL, NULL, 'b63617e9f5a25070e77520220530eyalcin88acccb9f7f38b74a413', '7', '2022-05-30 19:15:29', NULL, NULL, NULL, '1'),
('51', '43', '2022-05-30', NULL, 'Yüze Yağ Enjeksiyonu & Kök Hücre Tedavisi', '<p>Yaşlanma ve &ccedil;evresel fakt&ouml;rlere bağlı olarak y&uuml;zde sarkma, solma gibi problemler oluşmaktadır. K&ouml;k h&uuml;cre bakımından zenginleştirilmiş yağ enjeksiyonu ile bu problemler &ouml;nemli &ouml;l&ccedil;&uuml;de giderilmektedir. Y&uuml;ze Yağ Enjeksiyonu ve K&ouml;k H&uuml;cre Uygulaması v&uuml;cutta fazla bulunan yağın alınarak k&ouml;k h&uuml;cre ile zenginleştirilmesi ve ihtiya&ccedil; duyulan b&ouml;lgelere aktarılmasıdır. Bu işlem; k&ouml;k h&uuml;cre yapısı, bulunduğu doku ve organda h&uuml;cre &ccedil;oğalmasını ve yenilenmesini sağladığından standart yağ enjeksiyonundan &ccedil;ok daha kalıcı bir sonu&ccedil; sağlar.&nbsp;</p>\r\n\r\n<p>K&ouml;k h&uuml;cre ve yağ enjeksiyonu operasyonu lokal veya genel anestezi altında ger&ccedil;ekleştirilir, 2 ila 4 saat arasında s&uuml;rebilmektedir. Hasta operasyondan sonra aynı g&uuml;n i&ccedil;erisinde taburcu edilir. &nbsp;K&ouml;k h&uuml;creli yağ enjeksiyonu sonrası operasyon uygulanan b&ouml;lgede hafif sızlama, ağrı, morarma, şişme ve &ouml;dem gibi semptomlar g&ouml;r&uuml;lebilir. Ağrı g&ouml;r&uuml;ld&uuml;ğ&uuml; takdirde ağrı kesici kullanımı uygundur. Ağrı ve sızlama bir ile iki g&uuml;n kadar s&uuml;rebilmekte iken, morluk ve şişlik bi hafta sonra iyileşmektedir.</p>\r\n', '', 'Facial Fat Injection and Stem Cell Therapy', '<p>Due to aging and environmental factors, problems such as sagging and fading occur on the face. These problems are eliminated to a great extent with stem cell-enriched fat injection. Facial Fat Injection and Stem Cell Application is the removal of excess fat in the body, enriching it with stem cells and transferring it to the needed areas. This process; Since the stem cell structure provides cell proliferation and regeneration in the tissue and organ, it provides a much more permanent result than standard fat injection.</p>\r\n\r\n<p>Stem cell and fat injection operation is performed under local or general anesthesia, it can take between 2 and 4 hours. The patient is discharged on the same day after the operation. After the stem cell fat injection, symptoms such as mild tingling, pain, bruising, swelling and edema can be seen in the operated area. In case of pain, the use of painkillers is appropriate. While pain and tingling may last for one to two days, bruising and swelling heal after a week.</p>\r\n', '', '', '', '', 'حقن الزيت في الوجه و تطبيق الخلايا الجذعية', '<p dir=\"rtl\">اعتمادا على الشيخوخة والعوامل البيئية ، تحدث مشاكل مثل ترهل وتلاشي الوجه. يتم التخلص من هذه المشاكل بشكل كبير عن طريق حقن الزيت المخصبة في الخلايا الجذعية. حقن الزيت وتطبيق الخلايا الجذعية على الوجه هو إزالة الدهون الزائدة في الجسم ، وإثرائها بالخلايا الجذعية ونقلها إلى المناطق التي تحتاج إليها. هذه العملية؛ نظرًا لأن بنية الخلايا الجذعية تضمن تكاثر الخلايا وتجديدها في الأنسجة والعضو الموجود بها ، فإنها توفر نتيجة دائمة أكثر بكثير من حقن الدهون القياسي.&nbsp;</p>\r\n\r\n<p dir=\"rtl\">يتم تنفيذ عملية ديك الخلايا الجذعية وحقن الزيت تحت التخدير الموضعي أو العام ، ويمكن أن يستغرق من ساعتين إلى ٤&nbsp; ساعات. يتم تفريغ المريض في نفس اليوم بعد العملية. قد تحدث أعراض مثل الوخز الخفيف والألم والكدمات والتورم والوذمة في المنطقة التي أجريت فيها العملية بعد حقن زيت الخلايا الجذعية. إذا لوحظ الألم ، فإن استخدام مسكنات الألم مناسب. في حين أن الألم والأنين يمكن أن يستمر ما بين يوم إلى يومين، تلتئم الكدمة والتورم بعد أسبوعا.&nbsp;</p>\r\n', '', '', '', '', 'Gesichtsfettinjektion und Stammzellenanwendung', '<p>Aufgrund von Alterungs- und Umweltfaktoren treten im Gesicht Probleme wie Absacken und Verblassen auf. Diese Probleme werden mit der stammzellangereicherten Fettinjektion weitgehend beseitigt. Gesichtsfettinjektion und Stammzellenanwendung ist die Entfernung von &uuml;bersch&uuml;ssigem Fett im K&ouml;rper, die Anreicherung mit Stammzellen und die &Uuml;bertragung auf die ben&ouml;tigten Bereiche. Dieser Prozess liefert ein viel dauerhafteres Ergebnis als die herk&ouml;mmliche Fettinjektion, da die Stammzellstruktur die Zellproliferation und -regeneration in dem Gewebe und Organ, in dem sie sich befindet, gew&auml;hrleistet.</p>\r\n\r\n<p>Die Stammzellen- und Fettinjektionsoperation wird unter &ouml;rtlicher Bet&auml;ubung oder Vollnarkose durchgef&uuml;hrt und kann zwischen 2 und 4 Stunden dauern. Der Patient wird am selben Tag nach der Operation entlassen. Nach der Stammzellfettinjektion sind im operierten Bereich Symptome wie leichtes Kribbeln, Schmerzen, Bluterg&uuml;sse, Schwellungen und &Ouml;deme zu sehen. Wenn Schmerzen beobachtet werden, wird die Verwendung von Schmerzmitteln angewendet. W&auml;hrend Schmerzen und Kribbeln ein bis zwei Tage anhalten k&ouml;nnen, heilen Bluterg&uuml;sse und Schwellungen nach einer Woche ab.</p>\r\n', '', NULL, NULL, NULL, '98ca55bb965c66aae54220220530eyalcinb56b3dacc64b91102da8', '7', '2022-05-30 19:17:35', NULL, NULL, NULL, '-1'),
('52', '42', '2022-05-30', NULL, 'Lipoliz(İnceltme) Mezoterapisi', '<p>Lipoliz, b&ouml;lgesel yağlanma ve sel&uuml;lit olan b&ouml;lgelerde yağ dokusunun par&ccedil;alanmasını sağlayan etken maddelerinin enjeksiyon yoluyla uygulandığı tedavi y&ouml;ntemidir. &nbsp;Bu işlemle yağ dokusunun dağılması sağlanarak sel&uuml;lit g&ouml;r&uuml;n&uuml;m&uuml; giderilir ve p&uuml;r&uuml;zs&uuml;z bir g&ouml;r&uuml;n&uuml;m elde edilir. Lipoliz mezoterapisi incelme ve sel&uuml;lit tedavisinde uzun yıllardan beri uygulan ve başarısı kanıtlanmış bir y&ouml;ntemdir. Yaşlılık, genetik fakt&ouml;rler, hormon bozuklukları, k&ouml;t&uuml; beslenme, hareketsizlik, yaşam tarzı gibi sebeplerle ortaya &ccedil;ıkan cilt yağlanması sorunların giderilmesinde en etkili y&ouml;ntemlerden biridir. Bu y&ouml;ntemde doğal &ouml;zler, amino asitler ve vitaminler deri altına enjekte edilir. Bu bileşikler yağ erimesini hızlandırarak kimyasal liposuction etkisi elde edilmesini sağlar.</p>\r\n\r\n<p>Mezoterapi uygulaması olduk&ccedil;a pratik ve konforlu bir işlemdir ve 20 yaşın &uuml;zerindeki hemen herkese uygulanabilir. Genellikle 15 g&uuml;n arayla 4 ila 6 seans uygulanmaktadır. &nbsp;Hastalar uygulamadan hemen sonra taburcu edilir ve g&uuml;ndelik yaşamına d&ouml;nebilir. İşlemden sonra bol su i&ccedil;meleri ve b&ouml;lgeye masaj yapmaları gerekebilmektedir.&nbsp;</p>\r\n', '', 'Lipolysis (Thinning) Mesotherapy', '<p>Lipolysis is a treatment method in which the active ingredients that provide the breakdown of adipose tissue in areas with regional lubrication and cellulite are applied by injection. With this process, the fat tissue is dispersed, the appearance of cellulite is removed and a smooth appearance is obtained. Lipolysis mesotherapy is a proven method that has been used for many years in the treatment of thinning and cellulite. It is one of the most effective methods of eliminating skin lubrication problems that occur due to aging, genetic factors, hormonal disorders, malnutrition, inactivity and lifestyle. In this method, natural extracts, amino acids and vitamins are injected under the skin. These compounds accelerate fat melting and provide chemical liposuction effect.</p>\r\n\r\n<p>Mesotherapy application is a very practical and comfortable procedure and can be applied to almost everyone over the age of 20. Generally, 4 to 6 sessions are applied with an interval of 15 days. Patients are discharged immediately after the application and can return to their daily life. After the procedure, they may need to drink plenty of water and massage the area.</p>\r\n', '', '', '', '', 'تحلل الدهون (ترقيق) ميزوثيرابي', '<p dir=\"rtl\">تحلل الدهون هو طريقة العلاج التي يتم فيها إعطاء المواد الفعالة التي تضمن انهيار الأنسجة الدهنية في المناطق ذات التشحم الإقليمية والسيلوليت عن طريق الحقن. مع هذا الإجراء ، يتم القضاء على ظهور السيلوليت من خلال ضمان تشتت الأنسجة الدهنية ويتم تحقيق مظهر سلس. وقد استخدم ميزوثيرابي تحلل الدهون لسنوات عديدة في علاج ترقق والسيلوليت وقد ثبت نجاحها. تزييت الجلد الناجم عن الشيخوخة ، والعوامل الوراثية ، واضطرابات الهرمونات ، وسوء التغذية ، والخمول ، ونمط الحياة هي واحدة من أكثر الطرق فعالية للقضاء على المشاكل. في هذه الطريقة ، يتم حقن المستخلصات الطبيعية والأحماض الأمينية والفيتامينات تحت الجلد. هذه المركبات تسريع ارتشاف الدهون ، والذي يسمح لتحقيق تأثير شفط الدهون الكيميائية.&nbsp;</p>\r\n\r\n<p dir=\"rtl\">الميزوثيرابي هو إجراء عملي ومريح للغاية ويمكن تطبيقه على كل شخص تقريبا فوق سن العشرين. عادة ، يتم تنفيذ ٤ إلى ٦ جلسات مع فاصل من ١٥ يوما. يتم تفريغ المرضى مباشرة بعد التطبيق ويمكنهم العودة إلى حياتهم اليومية. بعد العملية ، قد يحتاجون إلى شرب الكثير من الماء وتدليك المنطقة.</p>\r\n', '', '', '', '', 'Lipolyse (Ausdünnung) Mesotherapie', '<p>Die Lipolyse ist eine Behandlungsmethode, bei der die Wirkstoffe, die f&uuml;r den Abbau des Fettgewebes in Bereichen mit regionaler Schmierung und Cellulite sorgen, durch Injektion appliziert werden. Mit diesem Verfahren wird das Fettgewebe aufgel&ouml;st, das Erscheinungsbild von Cellulite beseitigt und ein glattes Aussehen erzielt. Die Lipolyse-Mesotherapie ist eine bew&auml;hrte Methode, die seit vielen Jahren bei der Behandlung von Ausd&uuml;nnung und Cellulite eingesetzt wird. Es ist eine der effektivsten Methoden zur Beseitigung von Hautschmierproblemen, die aufgrund von Alterung, genetischen Faktoren, hormonellen St&ouml;rungen, Unterern&auml;hrung, Inaktivit&auml;t und Lebensstil auftreten. Bei dieser Methode werden nat&uuml;rliche Extrakte, Aminos&auml;uren und Vitamine unter die Haut gespritzt. Diese Verbindungen beschleunigen die Fettschmelze und sorgen f&uuml;r eine chemische Fettabsaugung.</p>\r\n\r\n<p>Die Anwendung der Mesotherapie ist ein sehr praktisches und komfortables Verfahren und kann bei fast jedem &uuml;ber 20 Jahren angewendet werden. In der Regel werden 4 bis 6 Sitzungen im Abstand von 15 Tagen durchgef&uuml;hrt. Die Patienten werden unmittelbar nach der Anwendung entlassen und k&ouml;nnen in ihren Alltag zur&uuml;ckkehren. Nach dem Eingriff m&uuml;ssen sie m&ouml;glicherweise viel Wasser trinken und den Bereich massieren.</p>\r\n', '', NULL, NULL, NULL, '9da54467b2e342ccfd8820220530eyalcinc3a685845158d83b5de3', '7', '2022-05-30 19:49:03', NULL, NULL, NULL, '-1'),
('53', '42', '2022-05-30', NULL, 'Prp Uygulaması', '<p>PRP uygulaması (platelet-rich plasma) v&uuml;cuda enjeksiyon yoluyla trombosit a&ccedil;ısından zengin plazma verilmesi işlemidir. Hastanın v&uuml;cudundan alınan kanın &ccedil;eşitli işlemlerden ge&ccedil;irilerek trombositten zengin plazma haline getirilip daha sonra hastaya enjekte edilmesi seklinde uygulanır.&nbsp;</p>\r\n\r\n<p>PRP uygulaması y&uuml;z, boyun, dekolte b&ouml;lgesi, el ve v&uuml;cuttaki ince &ccedil;izgi ve kırışıklıkların giderilmesinde, sivilce izleri, lekeler ve sa&ccedil; d&ouml;k&uuml;lmelerinin tedavisinde kullanılan bir y&ouml;ntemdir. Olduk&ccedil;a y&uuml;ksek etkiye sahip olan PRP uygulaması pratik ve konforlu bir işlemdir ve 18 yaşın &uuml;zerindeki herkese uygulanabilir. &nbsp;Otoimmun rahatsızlıkları olan kişilerde &ouml;nerilmemektedir. Genellikle 15 g&uuml;n arayla 4 ila 6 seans uygulanmaktadır. &nbsp;Hastalar uygulamadan hemen sonra g&uuml;ndelik yaşama d&ouml;nebilir.</p>\r\n', '', 'Prp Application', '<p>PRP application (platelet-rich plasma) is the process of giving platelet-rich plasma to the body by injection. It is applied in the form of blood taken from the patient&#39;s body, passing through various processes, turning it into platelet-rich plasma and then injecting it into the patient.</p>\r\n\r\n<p>PRP application is a method used in the removal of fine lines and wrinkles on the face, neck, d&eacute;collet&eacute; area, hands and body, and in the treatment of acne scars, spots and hair loss. PRP application, which has a very high effect, is a practical and comfortable procedure and can be applied to anyone over the age of 18. It is not recommended for people with autoimmune disorders. Generally, 4 to 6 sessions are applied with an interval of 15 days. Patients can return to daily life immediately after the application.</p>\r\n', '', '', '', '', 'تطبيق ﺑﻼزﻣﺎ ﻏﻧﯾﺔ ﺑﺎﻟﺻﻔﺎﺋﺢ اﻟدﻣوﯾﺔ', '<p dir=\"rtl\">تطبيق ﺑﻼزﻣﺎ ﻏﻧﯾﺔ ﺑﺎﻟﺻﻔﺎﺋﺢ اﻟدﻣوﯾﺔ هي عملية توصيل البلازما الغنية بالصفائح الدموية إلى الجسم عن طريق الحقن. يتم تطبيقه على شكل تمرير الدم المأخوذ من جسم المريض من خلال عمليات مختلفة ، وتحويله إلى بلازما غنية بالصفائح الدموية، ثم حقنه في المريض.&nbsp;</p>\r\n\r\n<p dir=\"rtl\">تطبيق البلازما الغنية بالصفائح الدموية هو طريقة تستخدم للقضاء على الخطوط الدقيقة والتجاعيد على الوجه والرقبة ومنطقة اليدين والجسم ، لعلاج ندبات حب الشباب والعيوب وتساقط الشعر. تطبيق البلازما الغنية بالصفائح الدموية ، الذي له تأثير كبير إلى حد ما ، هو إجراء عملي ومريح ويمكن تطبيقها على أي شخص فوق ثمانية عشر عامًا. لا ينصح به للأشخاص الذين يعانون من اضطرابات المناعة الذاتية. عادة ، يتم تنفيذ ٤&nbsp; إلى ٦&nbsp; جلسات مع فاصل من ١٥ يوما. يمكن للمرضى العودة إلى الحياة اليومية مباشرة بعد التطبيق.</p>\r\n', '', '', '', '', 'PRP-Anwendung', '<p>PRP-Anwendung (pl&auml;ttchenreiches Plasma) ist der Prozess, bei dem dem K&ouml;rper pl&auml;ttchenreiches Plasma durch Injektion zugef&uuml;hrt wird. Es wird in Form von Blut verabreicht, das dem K&ouml;rper des Patienten entnommen wird, verschiedene Prozesse durchl&auml;uft, es in pl&auml;ttchenreiches Plasma umwandelt und es dann dem Patienten injiziert.</p>\r\n\r\n<p>Die PRP-Anwendung ist eine Methode zur Entfernung feiner Linien und Falten im Gesicht, am Hals, im Dekollet&eacute;bereich, an den H&auml;nden und am K&ouml;rper sowie zur Behandlung von Aknenarben, Pickeln und Haarausfall. Die PRP-Anwendung, die eine sehr hohe Wirkung hat, ist ein praktisches und komfortables Verfahren und kann von jeder Person &uuml;ber 18 Jahren angewendet werden. Es wird nicht f&uuml;r Menschen mit Autoimmunerkrankungen empfohlen. In der Regel werden 4 bis 6 Sitzungen im Abstand von 15 Tagen durchgef&uuml;hrt. Die Patienten k&ouml;nnen unmittelbar nach der Anwendung in den Alltag zur&uuml;ckkehren.</p>\r\n', '', NULL, NULL, NULL, '2f4f9f82f5dbce7962f520220530eyalcin63dc8e0863aaf311381e', '7', '2022-05-30 19:50:14', NULL, NULL, NULL, '-1'),
('54', '42', '2022-05-30', NULL, 'Ozon Uygulaması', '<p>Ozon, oksijenin renksiz ve doğal bir izotopudur. Bağışıklık sistemini g&uuml;&ccedil;lendirici etkilerinin yanı sıra hastalıkların tedavinde de olduk&ccedil;a etkilidir. Ozon uygulaması hastadan alınan kanın ozon bakımından zenginleştirilerek v&uuml;cuda geri verilmesi şeklinde uygulanır.&nbsp;</p>\r\n\r\n<p>Gen&ccedil;lik iksiri olarak da bilinen ozon kronik hastalıkların tedavisinde olduk&ccedil;a etkilidir. Damar i&ccedil;i uygulamalarda kırmızı kan h&uuml;crelerinin oksijen taşıma kapasitesini ve kanın akışkanlığını artırarak oksijen azlığını giderir ve b&ouml;ylece h&uuml;cre yenilenmesini hızlandırır. Bunun yanında kolesterol&uuml; azaltarak v&uuml;cut yağ oranını ve kan şeker d&uuml;zeyini d&uuml;ş&uuml;r&uuml;r. Eklem b&ouml;lgelerine uygulamada kire&ccedil;lenmeyi ortadan kaldırır, kıkırdak kaybını azaltır ve eklem ağrılarını azaltır.&nbsp;</p>\r\n\r\n<p>Ozon uygulaması olduk&ccedil;a pratik ve konforlu bir işlemdir ve hemen herkese uygulanabilir. Hasta uygulamadan hemen sonra g&uuml;ndelik yaşamına d&ouml;nebilir.&nbsp;</p>\r\n', '', 'Ozone Application', '<p>Ozone is a colorless and natural isotope of oxygen. In addition to its immune system strengthening effects, it is also very effective in the treatment of diseases. Ozone application is applied in the form of enriching the blood taken from the patient in terms of ozone and returning it to the body.</p>\r\n\r\n<p>Ozone, also known as the elixir of youth, is very effective in the treatment of chronic diseases. In intravenous applications, it increases the oxygen carrying capacity of red blood cells and increases the fluidity of the blood, thereby eliminating oxygen deficiency and thus accelerating cell regeneration. In addition, it reduces body fat rate and blood sugar level by reducing cholesterol. When applied to the joint areas, it eliminates calcification, reduces cartilage loss and reduces joint pain.</p>\r\n\r\n<p>Ozone application is a very practical and comfortable procedure and can be applied to almost everyone. The patient can return to his daily life immediately after the application.</p>\r\n', '', '', '', '', 'علاج بالأوزون', '<p dir=\"rtl\">الأوزون هو نظير عديم اللون و الطبيعي للأكسجين. بالإضافة إلى آثاره على تقوية جهاز المناعة ، فهو أيضا فعال جدا في علاج الأمراض. يتم تطبيق علاج بالأوزون في شكل إثراء الدم المأخوذ من المريض بالأوزون وإعادته إلى الجسم.&nbsp;</p>\r\n\r\n<p dir=\"rtl\">الأوزون ، المعروف أيضا باسم إكسير الشباب ، فعال للغاية في علاج الأمراض المزمنة. في التطبيقات الوريدية ، يزيد من قدرة حمل الأكسجين لخلايا الدم الحمراء وسيولة الدم ، مما يؤدي إلى القضاء على نقص الأكسجين وبالتالي تسريع تجديد الخلايا. بالإضافة إلى ذلك ، فهو يقلل من الدهون في الجسم ومستويات السكر في الدم عن طريق تقليل الكوليسترول. أنه يزيل تكلس عند تطبيقها على المناطق المفصلية ، ويقلل من فقدان الغضروف ويقلل من آلام المفاصل.&nbsp;</p>\r\n\r\n<p dir=\"rtl\">علاج بالأوزون هو عملية ومريحة للغاية ويمكن تطبيقها على الجميع تقريبا. يمكن للمريض العودة إلى حياته اليومية مباشرة بعد التطبيق.</p>\r\n', '', '', '', '', 'Ozonanwendung', '<p>Ozon ist ein farbloses und nat&uuml;rliches Sauerstoffisotop. Neben seiner immunst&auml;rkenden Wirkung ist es auch sehr wirksam bei der Behandlung von Krankheiten. Die Ozonanwendung erfolgt in Form der Anreicherung des dem Patienten entnommenen Blutes mit Ozon und dessen R&uuml;ckf&uuml;hrung in den K&ouml;rper.</p>\r\n\r\n<p>Ozon, auch bekannt als Elixier der Jugend, ist sehr wirksam bei der Behandlung chronischer Krankheiten. Bei intraven&ouml;ser Anwendung erh&ouml;ht es die Sauerstofftransportkapazit&auml;t der roten Blutk&ouml;rperchen und erh&ouml;ht die Flie&szlig;f&auml;higkeit des Blutes, wodurch Sauerstoffmangel beseitigt und somit die Zellregeneration beschleunigt wird. Dar&uuml;ber hinaus senkt es den K&ouml;rperfettanteil und den Blutzuckerspiegel, indem es den Cholesterinspiegel senkt. Wenn es auf die Gelenkbereiche aufgetragen wird, beseitigt es Verkalkungen, reduziert den Knorpelschwund und lindert Gelenkschmerzen.</p>\r\n\r\n<p>Die Ozonanwendung ist ein sehr praktisches und komfortables Verfahren und kann bei fast jedem angewendet werden. Der Patient kann unmittelbar nach der Anwendung in sein t&auml;gliches Leben zur&uuml;ckkehren.</p>\r\n', '', NULL, NULL, NULL, 'bf1de3a04a49a038a81520220530eyalcin497c766789174acfb728', '7', '2022-05-30 19:51:08', NULL, NULL, NULL, '1'),
('55', '42', '2022-05-30', NULL, 'Damar içine Glutatyon Uygulaması', '<p>Glutatyon glutamik asit, sistein ve glisin adlı 3 amino asitten oluşan ve v&uuml;cutta doğal olarak bulunan yapıya verilen isimdir. Bu yapı bağışıklık sisteminin en &ouml;nemli yapı taşlarından olup olduk&ccedil;a etkili bir antioksidandır. Glutatyon seviyesini artırmanın en etkili yolu glutatyonu oluşturan Koenzim Q10, C vitamini, alfa lipoik asit bileşenlerini damardan almaktır. Bu bileşenlerin ağız yoluyla alınması mide asidinin &ccedil;&ouml;z&uuml;c&uuml; etkisi sebebiyle istenilen sonu&ccedil;ları doğurmayacaktır.</p>\r\n\r\n<p>Yaşlılık, k&ouml;t&uuml; beslenme, ila&ccedil; yan etkileri, sigara ve alkol kullanımına bağlı olarak ortaya &ccedil;ıkan rahatsızlıkların ve hastalıkların ortadan kaldırılmasında glutatyon tedavisinin &ouml;nemi b&uuml;y&uuml;kt&uuml;r. &nbsp;Glutatyon uygulaması; bağışıklık sistemini g&uuml;&ccedil;lendirir, cildi yeniler, uyku kalitesini artırır, ins&uuml;lin direncini azaltır.&nbsp;</p>\r\n\r\n<p>Glutatyon uygulaması olduk&ccedil;a pratik ve konforlu bir işlemdir ve hemen herkese uygulanabilir. Hasta uygulamadan hemen sonra g&uuml;ndelik yaşamına d&ouml;nebilir.</p>\r\n', '', 'Intravenous Glutathione Administration', '<p>Glutathione is the name given to the structure naturally found in the body, consisting of 3 amino acids: glutamic acid, cysteine ​​and glycine. This structure is one of the most important building blocks of the immune system and is a very effective antioxidant. The most effective way to increase glutathione level is to take Coenzyme Q10, vitamin C, alpha lipoic acid components, which form glutathione, intravenously. Oral intake of these components will not produce the desired results due to the dissolving effect of stomach acid.</p>\r\n\r\n<p>Glutathione therapy is of great importance in eliminating the diseases and diseases caused by old age, malnutrition, drug side effects, smoking and alcohol use. Glutathione administration; strengthens the immune system, renews the skin, improves sleep quality, reduces insulin resistance.</p>\r\n\r\n<p>Glutathione application is a very practical and comfortable procedure and can be applied to almost everyone. The patient can return to his daily life immediately after the application.</p>\r\n', '', '', '', '', 'تطبيق جلوتاثيون في الوريد', '<p dir=\"rtl\">الجلوتاثيون هو الاسم الذي يطلق على الهيكل المكون من ٣ أحماض أمينية تسمى حمض الجلوتاميك والسيستين والجليسين وتوجد بشكل طبيعي في الجسم. هذه البنية هي واحدة من أهم اللبنات الأساسية لجهاز المناعة وهي أحد مضادات الأكسدة الفعالة للغاية. الطريقة الأكثر فعالية لزيادة مستوى الجلوتاثيون هي تناول مكونات الإنزيم المساعد كيو ١٠ وفيتامين ج وحمض ألفا ليبويك عن طريق الوريد والتي تشكل الجلوتاثيون. إن تناول هذه المكونات عن طريق الفم لن ينتج النتائج المرجوة بسبب تأثير المذيب لحمض المعدة.&nbsp;</p>\r\n\r\n<p dir=\"rtl\">العلاج الجلوتاثيون له أهمية كبيرة في القضاء على الأمراض والأمراض التي تحدث بسبب الشيخوخة وسوء التغذية والآثار الجانبية للمخدرات والتدخين وتعاطي الكحول. تطبيق الجلوتاثيون ؛ يقوي جهاز المناعة ، ويجدد الجلد ، ويحسن نوعية النوم ، ويقلل من مقاومة الأنسولين.&nbsp;</p>\r\n\r\n<p dir=\"rtl\">تطبيق الجلوتاثيون هي إجراء عملي ومريح للغاية ويمكن تطبيقها على الجميع تقريبا. يمكن للمريض العودة إلى حياته اليومية مباشرة بعد التطبيق.</p>\r\n', '', '', '', '', 'Intravenöse Glutathion-Verabreichung', '<p>Glutathion ist die Bezeichnung f&uuml;r die nat&uuml;rlich im K&ouml;rper vorkommende Struktur, die aus 3 Aminos&auml;uren besteht: Glutamins&auml;ure, Cystein und Glycin. Diese Struktur ist einer der wichtigsten Bausteine des Immunsystems und ein sehr wirksames Antioxidans. Der effektivste Weg, den Glutathionspiegel zu erh&ouml;hen, ist die intraven&ouml;se Einnahme von Coenzym Q10, Vitamin C, Alpha-Lipons&auml;ure-Komponenten, die Glutathion bilden. Die orale Einnahme dieser Komponenten f&uuml;hrt aufgrund der aufl&ouml;senden Wirkung der Magens&auml;ure nicht zu den gew&uuml;nschten Ergebnissen.</p>\r\n\r\n<p>Die Glutathiontherapie ist von gro&szlig;er Bedeutung bei der Beseitigung von Krankheiten und Krankheiten, die durch Alter, Mangelern&auml;hrung, Nebenwirkungen von Medikamenten, Rauchen und Alkoholkonsum verursacht werden. Glutathion-Verabreichung; st&auml;rkt das Immunsystem, erneuert die Haut, verbessert die Schlafqualit&auml;t, reduziert die Insulinresistenz.</p>\r\n\r\n<p>Die Glutathion-Anwendung ist ein sehr praktisches und komfortables Verfahren und kann bei fast jedem angewendet werden. Der Patient kann unmittelbar nach der Anwendung in sein t&auml;gliches Leben zur&uuml;ckkehren.</p>\r\n', '', NULL, NULL, NULL, 'e0296af8b0fbd1fa546020220530eyalcin29b94366d0cbd54295ea', '7', '2022-05-30 19:52:00', NULL, NULL, NULL, '1'),
('56', '42', '2022-05-30', NULL, 'Bişektomi', '<p>Bişektomi, yanak i&ccedil;i yağlarının alınmasıyla daha belirgin elmacık kemikleri ve daha ince bir y&uuml;z hattına sahip olmayı sağlayan bir operasyondur. Yaşlanmayla birlikte yanak i&ccedil;i yağ dokularında b&uuml;y&uuml;me meydana gelir ve y&uuml;zde yuvarlak bir g&ouml;r&uuml;nt&uuml; ortaya &ccedil;ıkar. Bişektomi operasyonuyla y&uuml;z hatlarındaki yuvarlak ve orantısız g&ouml;r&uuml;n&uuml;m giderilir ve altın orana uygun olarak y&uuml;z&uuml;n daha ince bir g&ouml;r&uuml;n&uuml;m kazanmasını sağlanır.&nbsp;</p>\r\n\r\n<p>Bişektomi işlemi olduk&ccedil;a pratik ve konforlu bir cerrahi m&uuml;dahaledir, 18-45 yaş aralığındaki herkese uygulanabilir. Operasyon genellikle lokal anestezi altında uygulanır ancak gerekmesi halinde genel anestezi altında da uygulanabilir. Bişektomi ameliyatı ortalama 30 ila 45 dakika arasında s&uuml;rer. Hasta operasyondan hemen sonra taburcu edilir ve g&uuml;ndelik yaşamınıza d&ouml;nebilir. Bişektomi ile ortaya &ccedil;ıkan g&ouml;r&uuml;n&uuml;m kalıcıdır ancak ilerleyen d&ouml;nemlerde hastanın aşırı kilo alması operasyonun sonu&ccedil;larının kaybolmasına sebep olabilir.</p>\r\n', '', 'Bichectomy', '<p>Bichectomy is an operation that provides more prominent cheekbones and a thinner facial line by removing the inner cheek fat. With aging, the inner cheek fat tissues grow and a round appearance appears on the face. With the bichectomy operation, the round and disproportionate appearance of the facial features is removed and the face is provided with a thinner appearance in accordance with the golden ratio.</p>\r\n\r\n<p>Bichectomy is a very practical and comfortable surgical intervention, it can be applied to anyone between the ages of 18-45. The operation is usually performed under local anesthesia, but it can also be performed under general anesthesia if necessary. Bichectomy surgery takes between 30 and 45 minutes on average. The patient is discharged immediately after the operation and can return to your daily life. The appearance that occurs with bichectomy is permanent, but in the future, excessive weight gain of the patient may cause the results of the operation to be lost.</p>\r\n', '', '', '', '', 'استخراج الوسادة الدهنية الشدقية', '<p dir=\"rtl\">استخراج الوسادة الدهنية الشدقية هي عملية تسمح لك بالحصول على عظام وجنتين أكثر بروزا وخط وجه أرق عن طريق إزالة الدهون داخل الخد. مع الشيخوخة ، يحدث النمو في الأنسجة الدهنية من داخل الخد ، ويظهر مظهر مستدير على الوجه. مع استخراج الوسادة الدهنية الشدقية ، تتم إزالة المظهر المستدير وغير المتناسب لملامح الوجه ويتم تزويد الوجه بمظهر أرق وفقًا للنسبة الذهبية.&nbsp;</p>\r\n\r\n<p dir=\"rtl\">إجراء استخراج الوسادة الدهنية الشدقية هي تدخل جراحي عملي ومريح للغاية ، ويمكن تطبيقه على الجميع الذين تتراوح أعمارهم بين ١٨ -٤٥ عاما. عادة ما يتم إجراء العملية تحت التخدير الموضعي ، ولكن يمكن أيضا إجراؤها تحت التخدير العام إذا لزم الأمر. تستغرق جراحة استخراج الوسادة الدهنية الشدقية ما متوسطه ٣٠ إلى ٤٥ دقيقة. يتم تفريغ المريض مباشرة بعد العملية ويمكنه العودة إلى حياة اليومية. المظهر الذي يحدث مع استخراج الوسادة الدهنية الشدقية دائم ، ولكن في الفترات التالية ، قد يؤدي زيادة الوزن الزائد للمريض إلى فقدان نتائج العملية.</p>\r\n', '', '', '', '', 'Bichektomie', '<p>Die Bichektomie ist eine Operation, die durch Entfernung des inneren Wangenfetts f&uuml;r markantere Wangenknochen und eine d&uuml;nnere Gesichtslinie sorgt. Mit zunehmendem Alter w&auml;chst das innere Wangenfettgewebe und im Gesicht erscheint ein rundes Aussehen. Bei der Bichektomie-Operation wird das runde und disproportionierte Erscheinungsbild der Gesichtsz&uuml;ge entfernt und das Gesicht entsprechend dem Goldenen Schnitt schmaler gestaltet.</p>\r\n\r\n<p>Die Bichektomie ist ein sehr praktischer und komfortabler chirurgischer Eingriff, der bei jedem zwischen 18 und 45 Jahren angewendet werden kann. Die Operation wird in der Regel in &ouml;rtlicher Bet&auml;ubung durchgef&uuml;hrt, kann aber bei Bedarf auch in Vollnarkose durchgef&uuml;hrt werden. Eine Bichektomie-Operation dauert im Durchschnitt zwischen 30 und 45 Minuten. Der Patient wird unmittelbar nach der Operation entlassen und kann in Ihren Alltag zur&uuml;ckkehren. Das Erscheinungsbild, das bei der Bichektomie auftritt, ist dauerhaft, aber in Zukunft kann eine &uuml;berm&auml;&szlig;ige Gewichtszunahme des Patienten dazu f&uuml;hren, dass die Ergebnisse der Operation verloren gehen.</p>\r\n', '', NULL, NULL, NULL, '6ef5ba18f9632c4ab8e620220530eyalcinbf7a6273f2c6ffc2ad2e', '7', '2022-05-30 19:52:55', NULL, NULL, NULL, '1'),
('57', '43', '2022-05-30', NULL, 'Gamze Estetiği', '<p>Gamze, v&uuml;cudun herhangi bir yerinde bulunan &ccedil;ukurumsu b&ouml;lgelerdir. Genellikle y&uuml;zde g&ouml;r&uuml;l&uuml;r ancak omuzlarda, bel &uuml;st&uuml;nde de g&ouml;r&uuml;lebilir. &Ccedil;ekici bir g&ouml;r&uuml;n&uuml;m sağlayan gamze aslında kas ve bağ dokusunun d&uuml;zensiz gelişimiyle oluşur. Ancak g&uuml;n&uuml;m&uuml;zde olduk&ccedil;a pop&uuml;ler bir estetik uygulama olmuştur. Pratik ve konforlu olan gamze estetiği ile &ccedil;ok kısa bir s&uuml;rede istenilen b&ouml;lgede gamze g&ouml;r&uuml;n&uuml;m&uuml; sağlanabilir.&nbsp;</p>\r\n\r\n<p>Gamze estetiği, y&uuml;ze estetik bir g&ouml;r&uuml;n&uuml;m kazandıran &ccedil;ukurumsu g&ouml;r&uuml;nt&uuml;ye doğuştan sahip olamayan hastaların istediği b&ouml;lgede gamze g&ouml;r&uuml;n&uuml;m&uuml; oluşturmayı ama&ccedil;layan bir operasyondur. Hastanın isteği doğrultusunda bir&ccedil;ok farklı g&ouml;lgeye uygulanabilir ancak yaygın kullanım alanı yanak ve bel &uuml;st&uuml;d&uuml;r. Operasyon lokal anestezi altında uygulanır. Hasta uygulamadan hemen sonra taburcu edilir ve g&uuml;ndelik hayatına d&ouml;nebilir.&nbsp;</p>\r\n', '', 'Dimple Aesthetics', '<p>Dimples are concave areas on any part of the body. It is usually seen on the face, but can also be seen on the shoulders and waist. The dimple, which provides an attractive appearance, is actually formed by the irregular development of muscle and connective tissue. However, it has become a very popular aesthetic application today. With the practical and comfortable dimple aesthetic, a dimple appearance can be achieved in the desired area in a very short time.</p>\r\n\r\n<p>Dimple aesthetics is an operation that aims to create a dimple appearance in the desired area of patients who do not have a congenital dimple appearance that gives the face an aesthetic appearance. It can be applied to many different shades according to the patient&#39;s request, but the common usage area is on the cheeks and waist. The operation is performed under local anesthesia. The patient is discharged immediately after the application and can return to his daily life.</p>\r\n', '', '', '', '', 'جماليات الغمازة', '<p dir=\"rtl\">الغمازة هي مناطق مدمل تقع على أي جزء من الجسم. عادة ما يرى على الوجه ولكن يمكن رؤيته أيضا على الكتفين فوق الخصر. يتم تشكيل الغمازة ، الذي يوفر مظهرا جذابا ، في الواقع من خلال التطور غير المتكافئ لعضلة والنسيج الضام. ومع ذلك ، فقد أصبح ممارسة جمالية شعبية جدا اليوم. جماليات الغمازة ، وهي عملية ومريحة، يمكن أن توفر مظهر الغمازات في المنطقة المرغوبة في وقت قصير جدا.&nbsp;</p>\r\n\r\n<p dir=\"rtl\">جماليات الغمازة هي عملية تهدف إلى خلق مظهر الغمازة في المنطقة المرغوبة من قبل المرضى الذين لا يستطيعون الحصول على صورة غمازة تعطي مظهرا جماليا للوجه منذ الولادة. يمكن تطبيقه على العديد من المناطق المختلفة وفقا لطلب المريض ، ولكن منطقة استخدامه الشائعة هي الخد والخصر. يتم تنفيذ العملية تحت التخدير الموضعي. يخرج المريض مباشرة بعد التطبيق ويمكنه العودة إلى حياته اليومية.</p>\r\n', '', '', '', '', 'Grübchen-Ästhetik', '<p>Gr&uuml;bchen sind konkave Bereiche an jedem Teil des K&ouml;rpers. Es ist normalerweise im Gesicht zu sehen, kann aber auch an den Schultern und der oberen Taille gesehen werden. Das optisch ansprechende Gr&uuml;bchen entsteht eigentlich durch die unregelm&auml;&szlig;ige Ausbildung von Muskel- und Bindegewebe. Es ist jedoch heute eine sehr beliebte &auml;sthetische Anwendung geworden. Mit der praktischen und komfortablen Gr&uuml;bchen&auml;sthetik l&auml;sst sich in k&uuml;rzester Zeit eine Gr&uuml;bchenoptik im gew&uuml;nschten Bereich erzielen.</p>\r\n\r\n<p>Gr&uuml;bchen&auml;sthetik ist eine Operation, die darauf abzielt, bei Patienten, die kein angeborenes Gr&uuml;bchenbild haben, im gew&uuml;nschten Bereich ein Gr&uuml;bchenbild zu erzeugen, das dem Gesicht ein &auml;sthetisches Aussehen verleiht. Es kann auf Wunsch des Patienten an vielen verschiedenen Stellen angewendet werden, aber der &uuml;bliche Anwendungsbereich ist die Wangen- und Taillenregion. Die Operation wird unter &ouml;rtlicher Bet&auml;ubung durchgef&uuml;hrt. Der Patient wird unmittelbar nach der Anwendung entlassen und kann in seinen Alltag zur&uuml;ckkehren.</p>\r\n', '', NULL, NULL, NULL, '6a625bc03a5602d4fb3120220530eyalcin3abd472693bc5abcad75', '7', '2022-05-30 19:54:18', NULL, NULL, NULL, '1'),
('58', '42', '2022-05-30', NULL, 'Mikro İğneleme', '<p>Mikro iğneleme derinin sıkılaşması ve gergin bir yapıya kavuşması, ince &ccedil;izgilerin yok olması, deri sarkması ve &ccedil;atlak gibi sorunların giderilmesi, akne, g&uuml;neş lekesi ve g&ouml;z altı morluklarının giderilmesi i&ccedil;in uygulanan bir y&ouml;ntemdir. &nbsp;Bunların yanında sel&uuml;lit oluşumunu &ouml;nleme, kolajen gelişimi i&ccedil;in de tercih edilmektedir.&nbsp;</p>\r\n\r\n<p>İşlem &ouml;ncesinde uygulama yapılacak olan alan anestezik etkisi bulunan kremler ile uyuşturulmaktadır. B&ouml;ylece işlem sırasında acı hissi olmamaktadır. Olduk&ccedil;a y&uuml;ksek etkiye sahip olan mikro iğneleme uygulaması pratik ve konforlu bir işlemdir ve 18 yaşın &uuml;zerindeki hemen herkese uygulanabilir. &nbsp;İğneleme yapılacak ciltte enfeksiyon bulguları mevcut ise yapılmamaktadır. Yine aktif akne d&ouml;neminde de uygulanması sakıncalıdır. Genellikle 1 ay arayla 4 ila 6 seans uygulanmaktadır. &nbsp;Hastalar uygulamadan hemen sonra g&uuml;ndelik yaşamına d&ouml;nebilir.</p>\r\n', '', 'Micro Needling', '<p>Micro needling is a method used for tightening the skin and making it taut, eliminating fine lines, removing skin sagging and cracks, and removing acne, sunspots and dark circles under the eyes. In addition to these, it is preferred for preventing cellulite formation and collagen development.</p>\r\n\r\n<p>Before the procedure, the area to be treated is anesthetized with creams with anesthetic effect. Thus, there is no feeling of pain during the procedure. Micro needling, which has a very high effect, is a practical and comfortable procedure and can be applied to almost everyone over the age of 18. Needling is not performed if there are signs of infection on the skin to be needled. Again, it is inconvenient to apply it during the active acne period. Generally, 4 to 6 sessions are applied 1 month apart. Patients can return to their daily life immediately after the application.</p>\r\n', '', '', '', '', 'علاج تحفيز الكولاجين', '<p dir=\"rtl\">علاج تحفيز الكولاجين هي طريقة تستخدم لشد الجلد والحصول على بنية مشدودة ، والقضاء على الخطوط الدقيقة ، والقضاء على مشاكل مثل ترهل الجلد والشقوق ، والقضاء على حب الشباب ، وبقع الشمس وكدمات تحت العين. بالإضافة إلى ذلك ، فهو تطور الكولاجين و مفضل للوقاية من تكون السيلوليت.&nbsp;</p>\r\n\r\n<p dir=\"rtl\">يتم تخدير المنطقة التي سيتم تطبيقها قبل الإجراء مع الكريمات التي لها تأثير مخدر. وبالتالي ، لا توجد أحاسيس مؤلمة أثناء العملية. إن تطبيق علاج تحفيز الكولاجين ، الذي له تأثير كبير إلى حد ما ، هو إجراء عملي ومريح ويمكن تطبيقه على كل شخص تقريبا فوق سن ١٨ عاما. إذا كانت هناك علامات العدوى على الجلد التي سيتم إبرة ، فإنه لا يتم. مرة أخرى ، من غير المناسب تطبيقه أيضا خلال فترة حب الشباب النشط. عادة ، يتم تنفيذ ٤ إلى ٦ جلسات مع فاصل من&nbsp; شهرا. يمكن للمرضى العودة إلى حياتهم اليومية مباشرة بعد التطبيق.</p>\r\n', '', '', '', '', 'Mikro-Nadeln', '<p>Mikro-Nadeln ist eine Methode, die verwendet wird, um die Haut zu straffen, feine Linien zu beseitigen, Probleme wie Hauterschlaffung und Risse zu beseitigen und Akne, Sonnenflecken und Augenringe zu entfernen. Dar&uuml;ber hinaus wird es auch zur Vorbeugung von Cellulitebildung und Kollagenentwicklung bevorzugt.</p>\r\n\r\n<p>Vor dem Eingriff wird der zu behandelnde Bereich mit Cremes mit an&auml;sthetischer Wirkung bet&auml;ubt. Somit entsteht w&auml;hrend des Eingriffs kein Schmerzempfinden. Mikro-Nadeln, das eine sehr hohe Wirkung hat, ist ein praktisches und komfortables Verfahren und kann bei fast allen Menschen ab 18 Jahren angewendet werden. Eine Nadelung wird nicht durchgef&uuml;hrt, wenn Anzeichen einer Infektion auf der zu nadelnden Haut vorhanden sind. Auch hier ist es unbequem, es w&auml;hrend der aktiven Akneperiode anzuwenden. Im Allgemeinen werden 4 bis 6 Sitzungen im Abstand von 1 Monat angewendet. Die Patienten k&ouml;nnen unmittelbar nach der Anwendung in ihren Alltag zur&uuml;ckkehren.</p>\r\n', '', NULL, NULL, NULL, '5b1fddc510dfcc1be80720220530eyalcinec7954142616788b4f56', '7', '2022-05-30 19:55:18', NULL, NULL, NULL, '-1'),
('59', '42', '2022-05-30', NULL, 'Cilt Soyma (Kimyasal Peeling) İşlemleri', '<p>Kimyasal Peeling; mat, cansız ve sağlıksız g&ouml;r&uuml;nen cildin soyulması ve yerine canlı, ferah, taze olan yeni cildin ortaya &ccedil;ıkmasını sağlayan bir işlemdir. Cildin &uuml;st tabakasının b&uuml;t&uuml;n&uuml;yle soyulması sonrasında kendiliğinden iyileşmesi sağlanarak yeni, canlı, ferah ve lekesiz olan cildin ortaya &ccedil;ıkarılmasıdır. Hastanın ve uygulanacak b&ouml;lgenin &ouml;zelliklerine g&ouml;re y&uuml;zeysel, orta derinlikte ve derin kimyasal peeling olarak &uuml;&ccedil; farklı şekilde uygulanabilmektedir.&nbsp;</p>\r\n\r\n<p>S&uuml;t&uuml;n i&ccedil;erdiği laktik asit ile meyvelerin i&ccedil;eriğinde bulunan glikolik asidin kullanılmasıyla cildin en &uuml;st&uuml;nde bulunan tabakanın &ccedil;ok hafif olarak soyulması ile yapılan ve cildin ardından kendini yenilemesi işlemidir. Kimyasal peeling uygulaması cildi nemlendirir, sivilce ve akne oluşumunu engeller, g&uuml;neş lekelerini ve &ccedil;illeri ortadan kaldırır ve cildin doğal renginin ortaya &ccedil;ıkmasını sağlar. Olduk&ccedil;a konforlu olan bu işlem hassas cilde sahip olan kişiler i&ccedil;in olduk&ccedil;a iyi olan bir uygulamadır ve hemen herkese uygulanabilmektedir.</p>\r\n', '', 'Skin Peeling (Chemical Peeling) Procedures', '<p>Chemical Peeling; It is a procedure that peels off the dull, lifeless and unhealthy looking skin and replaces it with lively, fresh and fresh skin. It is the revealing of the new, lively, fresh and spotless skin by providing self-healing after the top layer of the skin is completely peeled off. It can be applied in three different ways as superficial, medium depth and deep chemical peeling, depending on the characteristics of the patient and the area to be applied.</p>\r\n\r\n<p>It is the process of renewing itself after the skin, which is done by peeling the layer on the top of the skin very lightly by using the lactic acid contained in the milk and the glycolic acid contained in the fruits. Chemical peeling application moisturizes the skin, prevents the formation of acne and acne, eliminates sunspots and freckles, and allows the natural color of the skin to emerge. This very comfortable procedure is a very good application for people with sensitive skin and can be applied to almost everyone.</p>\r\n', '', '', '', '', ' إجراءات تقشير الجلد (التقشير الكيميائي)', '<p dir=\"rtl\">تقشير كيميائي إنها عملية تقشر البشرة الباهتة وغير الحيوية وغير الصحية وتستبدلها ببشرة منتعشة وحيوية. بعد التقشير الكامل للطبقة العليا من الجلد ، يتم تحقيق الشفاء الذاتي ، وكشف عن بشرة جديدة وحيوية وجديدة ونظيفة. يمكن تطبيقه بثلاث طرق مختلفة مثل التقشير الكيميائي السطحي والمتوسط والعميق وفقا لخصائص المريض والمنطقة المراد تطبيقها.&nbsp;</p>\r\n\r\n<p dir=\"rtl\">إنها عملية تقشير خفيف جدا للطبقة الموجودة في الجزء العلوي من الجلد باستخدام حمض اللاكتيك الموجود في الحليب وحمض الجليكوليك الموجود في الفاكهة ، يليه التجديد الذاتي للجلد. تطبيق التقشير الكيميائي يرطب البشرة ، ويمنع تكوين حب الشباب وحب الشباب ، ويزيل بقع الشمس والنمش ، ويضمن ظهور اللون الطبيعي للبشرة. هذا الإجراء ، وهو مريح للغاية، هو تطبيق جيد جدا للأشخاص ذوي البشرة الحساسة ويمكن تطبيقه على الجميع تقريبا.</p>\r\n', '', '', '', '', 'Hautpeeling (Chemisches Peeling) Verfahren', '<p>Chemischer Peeling; Es ist ein Verfahren, das die stumpfe, leblose und ungesund aussehende Haut absch&auml;lt und durch lebendige, frische und frische Haut ersetzt. Es ist die Enth&uuml;llung der neuen, lebendigen, frischen und makellosen Haut durch Selbstheilung, nachdem die oberste Hautschicht vollst&auml;ndig abgesch&auml;lt ist. Es kann auf drei verschiedene Arten angewendet werden, als oberfl&auml;chliches, mitteltiefer und tiefer chemischer Peeling, je nach den Eigenschaften des Patienten und des Anwendungsbereichs.</p>\r\n\r\n<p>Es ist der Prozess der Selbsterneuerung nach der Haut, der durch sehr leichtes Absch&auml;len der Schicht auf der Hautoberfl&auml;che unter Verwendung der in der Milch enthaltenen Milchs&auml;ure und der in den Fr&uuml;chten enthaltenen Glykols&auml;ure erfolgt. Die Anwendung des chemischen Peelings spendet der Haut Feuchtigkeit, beugt der Entstehung von Akne vor, beseitigt Sonnenflecken und Sommersprossen und l&auml;sst die nat&uuml;rliche Hautfarbe erscheinen. Dieses sehr angenehme Verfahren ist eine sehr gute Anwendung f&uuml;r Menschen mit empfindlicher Haut und kann bei fast jedem angewendet werden.</p>\r\n', '', NULL, NULL, NULL, '2c52e50e54e29c9f1d4420220530eyalcin41fd762fabc91bbed3cd', '7', '2022-05-30 19:56:18', NULL, NULL, NULL, '-1'),
('60', '42', '2022-05-30', NULL, 'Skar Revizyonu (Yara izi estetiği)', '<p>Yara izi estetiği yani skar revizyonu &ccedil;eşitli nedenlere bağlı olarak oluşan yara izlerinin g&ouml;r&uuml;n&uuml;m&uuml;n&uuml; hafifletmek amacıyla uygulanan bir operasyondur. Yara izlerinin g&ouml;r&uuml;n&uuml;m&uuml;n&uuml; hafifletmek ya da şayet m&uuml;mk&uuml;nse tamamen ortadan kaldırmak i&ccedil;in plastik cerrahi y&ouml;ntemler uygulanabildiği gibi cerrahi dışı y&ouml;ntemlerin de tercih edilebileceğini s&ouml;yleyebiliriz.</p>\r\n\r\n<p>V&uuml;cudun herhangi bir b&ouml;lgesinde meydana gelen yaralanmanın tipi, yaranın nerede olduğu, onarım i&ccedil;in kullanılan y&ouml;ntemler, cilt yapısı, cildin esnekliği gibi &ouml;zelliklere bağlı olarak yara iziniz de farklı derinlikte ve g&ouml;r&uuml;n&uuml;mde olabilir. Ancak her t&uuml;rl&uuml; yara izi i&ccedil;in skar revizyonu işleminin yapılabildiğini de belirtmeliyiz.</p>\r\n\r\n<p>Skar tedavisi, v&uuml;cutta farklı sebeplerden dolayı meydana gelen yara izleri ve kesiklerin iyileşmesi i&ccedil;in &nbsp;uygulanmaktadır. Ameliyattan dolayı oluşan kesik izleri, yaralanma gibi durumlarda oluşan izlerde yara kendiliğinden kapansa bile izler uzun s&uuml;re sebat edebilir. Yara izleri, kişinin genetik yapısına, yaranın bulunduğu b&ouml;lgeye, yaşa, ırka, cilt tipine ve sağlık durumuna g&ouml;re farklılık g&ouml;sterir. Aynı şiddetteki yara, herkeste aynı etkiyi yaratmayabilir.</p>\r\n\r\n<p>Yara izleri i&ccedil;in uygulanan estetik girişimlerin sonucu kalıcıdır. Yaranın iyileşmesinin &uuml;zerinden 6 ay ila 1 yıl ge&ccedil;tikten sonra yara izinin giderilmesi ya da g&ouml;r&uuml;n&uuml;m&uuml;n&uuml;n hafiflemesi i&ccedil;in estetik m&uuml;dahalenin yapılmasını sağlayabilirsiniz. Operasyon lokal anestezi altında uygulanır. Hasta uygulamadan hemen sonra taburcu edilir ve g&uuml;ndelik hayatına d&ouml;nebilir.&nbsp;</p>\r\n', '', 'Scar Revision (Scar Aesthetics)', '<p>Scar aesthetics, that is, scar revision, is an operation applied to alleviate the appearance of scars caused by various reasons. We can say that plastic surgery methods can be applied to alleviate the appearance of scars or, if possible, to completely remove them, as well as non-surgical methods.</p>\r\n\r\n<p>Depending on the type of injury in any part of the body, the location of the wound, the methods used for repair, skin structure, and skin elasticity, your scar may have different depths and appearances. However, we should also state that scar revision can be performed for any type of scar.</p>\r\n\r\n<p>Scar treatment is applied for the healing of scars and cuts that occur in the body for different reasons. Even if the wound is closed by itself, the scars may persist for a long time in the scars caused by the surgery, such as cut marks and injuries. Scars differ according to the genetic structure of the person, the region of the wound, age, race, skin type and health status. A wound of the same severity may not have the same effect on everyone.</p>\r\n\r\n<p>The result of aesthetic interventions applied for scars is permanent. After 6 months to 1 year after the healing of the wound, you can have an aesthetic intervention for the removal of the scar or the lightening of its appearance. The operation is performed under local anesthesia. The patient is discharged immediately after the application and can return to his daily life.</p>\r\n', '', '', '', '', 'تصحيح الندبات (مراجعة الندبة)', '<p dir=\"rtl\">جماليات الندبة ، أي مراجعة الندبة ، هي عملية يتم إجراؤها للتخفيف من ظهور الندوب الناتجة عن أسباب مختلفة. يمكننا القول أنه يمكن تطبيق طرق الجراحة التجميلية للتخفيف من ظهور الندبات أو ، إن أمكن ، القضاء عليها تماما ، وكذلك يمكن تفضيل الطرق غير الجراحية.&nbsp;</p>\r\n\r\n<p dir=\"rtl\">اعتمادا على الخصائص مثل نوع الإصابة التي تحدث في أي منطقة من الجسم ، حيث يكون الجرح ، والطرق المستخدمة للإصلاح ، وبنية الجلد ، ومرونة الجلد ، يمكن أن تكون ندبتك أيضا ذات عمق ومظهر مختلفين. ومع ذلك ، تجدر الإشارة أيضا إلى أنه يمكن إجراء مراجعة الندبات لجميع أنواع الندبات.</p>\r\n\r\n<p dir=\"rtl\">يتم إجراء علاج الندبات لشفاء الندبات والجروح التي تحدث على الجسم لأسباب مختلفة. الندوب الناجمة عن الجراحة ، والندوب التي تشكلت في حالات مثل الإصابة ، حتى لو كان الجرح يغلق من تلقاء نفسه ، يمكن أن تستمر الندوب لفترة طويلة. تختلف الندوب حسب التركيب الجيني للشخص ، والمنطقة التي يقع فيها الجرح ، والعمر ، والعرق ، ونوع الجلد ، والحالة الصحية. قد لا يكون للجرح من نفس الشدة نفس التأثير على الجميع.</p>\r\n\r\n<p dir=\"rtl\">نتيجة التدخلات الجمالية المطبقة على الندوب دائمة. بعد ٦ أشهر إلى ١ سنة بعد التئام الجرح ، يمكنك الحصول على تدخل جمالي لإزالة الندبة أو التخفيف من مظهرها. يتم تنفيذ العملية تحت التخدير الموضعي. يتم تفريغ المريض مباشرة بعد التطبيق ويمكنه العودة إلى حياته اليومية.</p>\r\n', '', '', '', '', 'Narbenrevision (Narbenästhetik)', '<p>Die Narben&auml;sthetik (Narbenrevision) ist eine Operation, die angewendet wird, um das Erscheinungsbild von Narben aufzuhellen, die aus verschiedenen Gr&uuml;nden verursacht wurden. Plastische Chirurgie Methoden k&ouml;nnen angewendet werden, um das Erscheinungsbild von Narben aufzuhellen oder, wenn m&ouml;glich, vollst&auml;ndig zu beseitigen, sowie auch nicht-chirurgische Methoden k&ouml;nnen bevorzugt werden.</p>\r\n\r\n<p>Abh&auml;ngig von der Art der Verletzung an einem K&ouml;rperteil, dem Ort der Wunde, den Reparaturmethoden, der Hautstruktur und der Hautelastizit&auml;t kann Ihre Narbe unterschiedliche Tiefen und Aussehen haben. Wir sollten jedoch auch festhalten, dass eine Narbenkorrektur bei jeder Art von Narbe durchgef&uuml;hrt werden kann.</p>\r\n\r\n<p>Die Narbenbehandlung wird aus verschiedenen Gr&uuml;nden zur Heilung von Narben und Schnittwunden am K&ouml;rper angewendet. Auch wenn sich die Wunde von selbst verschlie&szlig;t, k&ouml;nnen die Narben noch lange in den Operationsnarben wie Schnittwunden und Verletzungen verbleiben. Narben unterscheiden sich je nach genetischer Struktur der Person, Wundregion, Alter, Rasse, Hauttyp und Gesundheitszustand. Eine Wunde der gleichen Schwere hat m&ouml;glicherweise nicht bei allen die gleiche Wirkung.</p>\r\n\r\n<p>Das Ergebnis &auml;sthetischer Narbeneingriffe ist dauerhaft. Nach 6 Monaten bis 1 Jahr nach der Wundheilung k&ouml;nnen Sie einen &auml;sthetischen Eingriff zur Entfernung der Narbe oder zur Aufhellung ihres Aussehens durchf&uuml;hren lassen. Die Operation wird unter &ouml;rtlicher Bet&auml;ubung durchgef&uuml;hrt. Der Patient wird unmittelbar nach der Anwendung entlassen und kann in seinen Alltag zur&uuml;ckkehren.</p>\r\n', '', NULL, NULL, NULL, '029fb7193cff2aa8d07420220530eyalcin5aa2a0dd9c81d7b7f437', '7', '2022-05-30 19:57:06', NULL, NULL, NULL, '-1'),
